def utc_now():
    """Returns current Eastern Time (EST/EDT) as a timezone-aware datetime."""
    return datetime.now(_EST_TZ)


def make_status_emoji(status: str) -> str:
    return {
        "Pending": "🟡 Pending",
        "More Info Requested": "🟠 More Info Requested",
        "Timed Out": "⏰ Timed Out",
        "Approved": "🟢 Approved",
        "Denied": "🔴 Denied",
        "Closed": "⚫ Closed",
    }.get(status, status)


def count_message_attachments(messages) -> int:
    total = 0
    for msg in messages:
        total += len(msg.attachments)
    return total


def is_staff_reviewer(member: discord.Member) -> bool:
    allowed = _LEADERSHIP_ROLE_IDS
    return any(role.id in allowed for role in member.roles)


