_HRSVP_FILE = os.path.join("diff_data", "diff_host_rsvp.json")
_HRSVP_DAYS = ["Meet 1", "Meet 2", "Meet 3"]


def _hrsvp_repair_entries(data: dict) -> dict:
    """Convert any string-dict entries back to proper dicts (fixes legacy corruption)."""
    import re as _re
    changed = False
    for day in _HRSVP_DAYS:
        slot = data.get(day, {})
        for key in ("yes", "maybe", "no"):
            fixed = []
            for entry in slot.get(key, []):
                if isinstance(entry, str) and entry.startswith("{"):
                    # Extract fields with regex — handles apostrophes in values
                    uid_m   = _re.search(r"'uid'\s*:\s*'([^']+)'", entry)
                    day_m   = _re.search(r"'day'\s*:\s*'([^']+)'", entry)
                    time_m  = _re.search(r"'time'\s*:\s*'([^']+)'", entry)
                    theme_m = _re.search(r"'theme'\s*:\s*'(.*?)'(?:\s*[,}])", entry)
                    if uid_m:
                        entry = {
                            "uid":   uid_m.group(1),
                            "day":   day_m.group(1)   if day_m   else "TBD",
                            "time":  time_m.group(1)  if time_m  else "TBD",
                            "theme": theme_m.group(1) if theme_m else "TBD",
                        }
                        changed = True
                fixed.append(entry)
            slot[key] = fixed
        data[day] = slot
    if changed:
        _hrsvp_save(data)
    return data


def _hrsvp_load() -> dict:
    if os.path.exists(_HRSVP_FILE):
        try:
            with open(_HRSVP_FILE, "r") as f:
                raw = json.load(f)
            return _hrsvp_repair_entries(raw)
        except Exception:
            pass
    return {day: {"yes": [], "no": [], "maybe": []} for day in _HRSVP_DAYS}


def _hrsvp_save(data: dict) -> None:
    _atomic_json_save(_HRSVP_FILE, data)


def _hrsvp_reset() -> dict:
    data = {day: {"yes": [], "no": [], "maybe": []} for day in _HRSVP_DAYS}
    _hrsvp_save(data)
    return data


def _hrsvp_uid(entry) -> str:
    """Return UID string from either a plain string or a dict entry."""
    return entry if isinstance(entry, str) else entry.get("uid", "")


# ── Host Reliability Tracking ────────────────────────────────────────────────
_HREL_FILE = os.path.join("diff_data", "diff_host_reliability.json")


def _hrel_load() -> dict:
    if os.path.exists(_HREL_FILE):
        try:
            with open(_HREL_FILE) as f:
                return json.load(f)
        except Exception:
            pass
    return {}


def _hrel_save(data: dict) -> None:
    _atomic_json_save(_HREL_FILE, data)


def _hrel_entry(data: dict, uid: str) -> dict:
    return data.setdefault(uid, {
        "rsvp_count": 0, "confirmed_count": 0,
        "last_rsvp": None, "last_confirmed": None,
    })


def _hrel_track_rsvp(uid: str) -> None:
    data = _hrel_load()
    e = _hrel_entry(data, uid)
    e["rsvp_count"] += 1
    e["last_rsvp"] = utc_now().isoformat()
    _hrel_save(data)


def _hrel_track_confirmed(uid: str) -> None:
    data = _hrel_load()
    e = _hrel_entry(data, uid)
    e["confirmed_count"] += 1
    e["last_confirmed"] = utc_now().isoformat()
    _hrel_save(data)


# ── HRSVP weekly auto-reset state ────────────────────────────────────────────
_HRSVP_RESET_FILE = os.path.join("diff_data", "diff_hrsvp_reset.json")


def _hrsvp_reset_ts_load() -> str | None:
    if os.path.exists(_HRSVP_RESET_FILE):
        try:
            with open(_HRSVP_RESET_FILE) as f:
                return json.load(f).get("last_reset")
        except Exception:
            pass
    return None


def _hrsvp_reset_ts_save(date_str: str) -> None:
    _atomic_json_save(_HRSVP_RESET_FILE, {"last_reset": date_str})


def _hrsvp_build_embed() -> discord.Embed:
    data = _hrsvp_load()
    _DIV = "─" * 30

    # ── Response summary counts ───────────────────────────────
    all_responded_uids: set = set()
    for day in _HRSVP_DAYS:
        d = data.get(day, {})
        for bucket in ("yes", "no", "maybe"):
            for e in d.get(bucket, []):
                all_responded_uids.add(_hrsvp_uid(e))
    total_responders = len(all_responded_uids)
    slots_with_host  = sum(1 for day in _HRSVP_DAYS if data.get(day, {}).get("yes", []))
    slots_needed     = len(_HRSVP_DAYS)
    slot_bar         = "🟩" * slots_with_host + "⬜" * (slots_needed - slots_with_host)

    embed = discord.Embed(
        title="📋 DIFF Host Availability — Meet Schedule",
        description=(
            f"**Hosts, mark your availability for each meet slot below.**\n\n"
            f"📊 {slot_bar}  **{slots_with_host}/{slots_needed} slots have a confirmed host**\n"
            f"👥 **{total_responders} host{'s' if total_responders != 1 else ''}** have responded so far\n\n"
            "• ✅ **Available** — opens a form for your day, time & class\n"
            "• ❓ **Maybe** — opens a form to note your preferred day\n"
            "• ❌ **Unavailable** — marks you as unable to host\n"
            "• 👤 **My Status** — shows what you've submitted so far\n\n"
            f"{_DIV}"
        ),
        color=0x5865F2,
        timestamp=utc_now(),
    )
    if DIFF_LOGO_URL:
        embed.set_thumbnail(url=DIFF_LOGO_URL)

    for day in _HRSVP_DAYS:
        d             = data.get(day, {"yes": [], "no": [], "maybe": []})
        yes_entries   = d.get("yes", [])
        no_entries    = d.get("no", [])
        maybe_entries = d.get("maybe", [])

        # Slot status badge
        if yes_entries:
            slot_status = f"🟢 **{len(yes_entries)} host{'s' if len(yes_entries) != 1 else ''} available**"
        elif maybe_entries:
            slot_status = f"🟡 **{len(maybe_entries)} maybe** — still needs a host"
        else:
            slot_status = "🔴 **Open — no hosts yet**"

        lines = [slot_status]

        if yes_entries:
            for e in yes_entries:
                uid = _hrsvp_uid(e)
                if isinstance(e, dict):
                    dv = e.get('day', 'TBD')
                    tv = e.get('time', 'TBD')
                    ts = _parse_meet_ts(dv, tv) if not tv.startswith("<t:") else None
                    if ts:
                        when_display = f"<t:{ts}:F>  (<t:{ts}:R>)"
                    elif tv.startswith("<t:"):
                        when_display = tv
                    else:
                        when_display = f"📅 {dv}  🕒 {tv}"
                    lines.append(
                        f"✅ <@{uid}>\n"
                        f"　{when_display}  🎮 {e.get('theme', 'TBD')}"
                    )
                else:
                    lines.append(f"✅ <@{uid}>")
        else:
            lines.append("✅ *No confirmed hosts yet*")

        if maybe_entries:
            for e in maybe_entries:
                uid = _hrsvp_uid(e)
                day_pref = e.get("day", "") if isinstance(e, dict) else ""
                lines.append(f"❓ <@{uid}>" + (f" — prefers {day_pref}" if day_pref else ""))

        if no_entries:
            no_tags = "  ".join(f"<@{_hrsvp_uid(u)}>" for u in no_entries)
            lines.append(f"❌ Unavailable: {no_tags}")

        embed.add_field(name=day, value="\n".join(lines) or "*No responses yet*", inline=False)

    embed.set_footer(text="Different Meets • Host Availability  •  Times shown in your local timezone")
    return embed


class _HrsvpResetConfirmModal(discord.ui.Modal, title="Confirm Reset"):
    confirm = discord.ui.TextInput(
        label='Type RESET to confirm clearing all responses',
        placeholder="RESET",
        required=True,
        max_length=10,
    )

    async def on_submit(self, interaction: discord.Interaction) -> None:
        if str(self.confirm).strip().upper() != "RESET":
            return await interaction.response.send_message(
                "❌ Reset cancelled — you didn't type RESET.", ephemeral=True
            )
        await interaction.response.defer(ephemeral=True)
        try:
            _hrsvp_reset()
            await _hrsvp_update_panel(interaction.client)
            await interaction.followup.send(
                "🗑️ All host availability responses have been cleared for the new week.", ephemeral=True
            )
        except Exception as _e:
            print(f"[HRSVP] Reset on_submit error: {_e}")
            try:
                await interaction.followup.send("❌ Reset failed. Try again.", ephemeral=True)
            except Exception:
                pass


class _HrsvpResetBtn(discord.ui.Button):
    def __init__(self):
        super().__init__(
            label="Reset Responses",
            emoji="🗑️",
            style=discord.ButtonStyle.danger,
            custom_id="hrsvp_reset_all",
            row=4,
        )

    async def callback(self, interaction: discord.Interaction) -> None:
        is_staff = any(
            r.id in _LEADERSHIP_ROLE_IDS
            for r in getattr(interaction.user, "roles", [])
        )
        if not getattr(getattr(interaction.user, "guild_permissions", None), "administrator", False) and not is_staff:
            return await interaction.response.send_message(
                "Only leadership can reset availability responses.", ephemeral=True
            )
        await interaction.response.send_modal(_HrsvpResetConfirmModal())


class _HrsvpMyStatusBtn(discord.ui.Button):
    def __init__(self):
        super().__init__(
            label="My Status",
            emoji="👤",
            style=discord.ButtonStyle.secondary,
            custom_id="hrsvp_my_status",
            row=3,
        )

    async def callback(self, interaction: discord.Interaction) -> None:
        uid  = str(interaction.user.id)
        data = _hrsvp_load()
        lines = []
        for day in _HRSVP_DAYS:
            slot = data.get(day, {})
            found = False
            for e in slot.get("yes", []):
                if _hrsvp_uid(e) == uid:
                    if isinstance(e, dict):
                        dv = e.get('day', 'TBD')
                        tv = e.get('time', 'TBD')
                        ts = _parse_meet_ts(dv, tv) if dv and tv != 'TBD' else None
                        when_str = f"<t:{ts}:F>" if ts else f"{dv} · {tv}"
                        lines.append(
                            f"✅ **{day}** — {when_str} · 🎮 {e.get('theme','TBD')}"
                        )
                    else:
                        lines.append(f"✅ **{day}** — Available")
                    found = True
            for e in slot.get("maybe", []):
                if _hrsvp_uid(e) == uid:
                    day_pref = e.get("day","") if isinstance(e, dict) else ""
                    lines.append(f"❓ **{day}** — Maybe" + (f" (prefers {day_pref})" if day_pref else ""))
                    found = True
            for e in slot.get("no", []):
                if _hrsvp_uid(e) == uid:
                    lines.append(f"❌ **{day}** — Unavailable")
                    found = True
            if not found:
                lines.append(f"⬜ **{day}** — No response yet")

        await interaction.response.send_message(
            "**Your current availability:**\n" + "\n".join(lines),
            ephemeral=True,
        )


