class _ASchedOverrideModal(discord.ui.Modal, title="🛠️ Override Schedule Slot"):
    slot_input = discord.ui.TextInput(
        label="Which slot? (Meet 1 / Meet 2 / Meet 3)",
        placeholder="e.g. Meet 1",
        required=True,
        max_length=10,
    )
    host_input = discord.ui.TextInput(
        label="Host user ID or @mention",
        placeholder="e.g. 123456789012345678",
        required=True,
        max_length=32,
    )
    day_time_input = discord.ui.TextInput(
        label="Day & Time",
        placeholder="e.g. Sunday 8:00 PM EST",
        required=True,
        max_length=60,
    )
    class_input = discord.ui.TextInput(
        label="Class / Theme (blank = Open Class)",
        placeholder="e.g. JDM  |  Muscle  |  Euro  |  Open Class",
        required=False,
        max_length=100,
    )

    async def on_submit(self, interaction: discord.Interaction) -> None:
        import re as _re
        import traceback as _tb
        try:
            slot_raw  = self.slot_input.value.strip()
            host_raw  = self.host_input.value.strip()
            dt_raw    = self.day_time_input.value.strip()
            class_val = (self.class_input.value or "").strip() or "Open Class"

            slot_name = next((d for d in _HRSVP_DAYS if slot_raw.lower() in d.lower()), None)
            if not slot_name:
                return await interaction.response.send_message(
                    f"❌ Unknown slot '{slot_raw}'. Use: Meet 1, Meet 2, or Meet 3.", ephemeral=True
                )
            m = _re.search(r"(\d{15,20})", host_raw)
            if not m:
                return await interaction.response.send_message(
                    "❌ Couldn't parse a user ID. Paste their ID or @mention.", ephemeral=True
                )
            host_id = int(m.group(1))
            guild   = interaction.guild
            member  = guild.get_member(host_id) if guild else None

            # Defer before any async network calls
            await interaction.response.defer(ephemeral=True)

            if not member:
                try:
                    member = await guild.fetch_member(host_id)
                except Exception:
                    return await interaction.followup.send(
                        f"❌ Member {host_id} not found in this server.", ephemeral=True
                    )

            parts    = dt_raw.split(None, 1)
            day_val  = parts[0].capitalize() if parts else dt_raw
            time_raw = parts[1] if len(parts) > 1 else dt_raw
            time_val = time_raw.strip()

            schedule = _asched_load()
            slot     = schedule["days"].setdefault(slot_name, {})
            slot.update({"host_id": host_id, "host_status": "yes",
                         "day": day_val, "time": time_val, "class": class_val})
            slot["locked"] = True   # lock so Rebuild Schedule doesn't overwrite
            schedule["updated_at"] = utc_now().isoformat()
            _asched_save(schedule)

            # ── Inject synthetic HRSVP entry so the availability panel reflects the override ──
            try:
                hrsvp = _hrsvp_load()
                uid_str = str(host_id)
                synthetic = {"uid": uid_str, "day": day_val, "time": time_val, "theme": class_val}
                for day_key in _HRSVP_DAYS:
                    bucket = hrsvp.setdefault(day_key, {"yes": [], "no": [], "maybe": []})
                    # Remove this host from all slots first (clean slate)
                    for b in ("yes", "no", "maybe"):
                        bucket[b] = [e for e in bucket.get(b, [])
                                     if _hrsvp_uid(e) != uid_str]
                # Add as confirmed yes for the overridden slot
                hrsvp.setdefault(slot_name, {"yes": [], "no": [], "maybe": []})["yes"].append(synthetic)
                _hrsvp_save(hrsvp)
            except Exception as _he:
                print(f"[OverrideSlot] HRSVP inject failed: {_he}")

            try:
                await _asched_update_panel(interaction.client)
            except Exception as _pe:
                print(f"[OverrideSlot] Schedule panel update failed: {_pe}")

            try:
                await _hrsvp_update_panel(interaction.client)
            except Exception as _pe:
                print(f"[OverrideSlot] HRSVP panel update failed: {_pe}")

            all_filled = all(schedule["days"].get(d, {}).get("host_id") for d in _HRSVP_DAYS)
            if all_filled:
                try:
                    await _asched_post_finalized(interaction.client)
                except Exception as _fe:
                    print(f"[OverrideSlot] Post finalized failed: {_fe}")

            try:
                _hrel_track_confirmed(str(host_id))
            except Exception:
                pass

            try:
                ov_embed = discord.Embed(
                    title=f"📅 You've Been Manually Assigned — {slot_name}",
                    description="Leadership has assigned you to host this meet slot.",
                    color=discord.Color.blurple(),
                    timestamp=utc_now(),
                )
                ov_embed.add_field(name="🗓 Day",   value=day_val,   inline=True)
                ov_embed.add_field(name="🕒 Time",  value=time_val,  inline=True)
                ov_embed.add_field(name="🎮 Class", value=class_val, inline=True)
                ov_embed.set_footer(text="DIFF Meets • Host Schedule — questions? Contact leadership.")
                await member.send(embed=ov_embed)
            except (discord.Forbidden, Exception):
                pass

            fin_note = "\n📢 All slots confirmed — schedule posted to #upcoming-meet." if all_filled else ""
            await interaction.followup.send(
                f"✅ **{slot_name}** overridden → {member.mention}\n"
                f"📅 {day_val}  🕒 {time_val}  🎮 {class_val}{fin_note}",
                ephemeral=True,
            )
        except Exception as _err:
            print(f"[OverrideSlot] on_submit error: {_err}")
            _tb.print_exc()
            try:
                if not interaction.response.is_done():
                    await interaction.response.send_message(
                        f"❌ Override failed: {_err}", ephemeral=True
                    )
                else:
                    await interaction.followup.send(
                        f"❌ Override failed: {_err}", ephemeral=True
                    )
            except Exception:
                pass

    async def on_error(self, interaction: discord.Interaction, error: Exception) -> None:
        import traceback as _tb
        print(f"[OverrideSlot Modal] on_error: {error}")
        _tb.print_exc()
        try:
            if not interaction.response.is_done():
                await interaction.response.send_message(
                    f"❌ Override failed: {error}", ephemeral=True
                )
            else:
                await interaction.followup.send(
                    f"❌ Override failed: {error}", ephemeral=True
                )
        except Exception:
            pass


class _ASchedOverrideBtn(discord.ui.Button):
    def __init__(self):
        super().__init__(
            label="Override Slot",
            emoji="🛠️",
            style=discord.ButtonStyle.secondary,
            custom_id="diff_asched_override",
            row=1,
        )

    async def callback(self, interaction: discord.Interaction) -> None:
        try:
            user   = interaction.user
            roles  = getattr(user, "roles", [])
            perms  = getattr(user, "guild_permissions", None)
            is_admin = getattr(perms, "administrator", False)
            is_owner = (
                interaction.guild is not None
                and interaction.guild.owner_id == getattr(user, "id", None)
            )
            is_staff = is_admin or is_owner or any(
                r.id in _LEADERSHIP_HOST_ROLE_IDS
                for r in roles
            )
            if not is_staff:
                return await interaction.response.send_message(
                    "Only leadership can override schedule slots.", ephemeral=True
                )
            await interaction.response.send_modal(_ASchedOverrideModal())
        except Exception as _e:
            print(f"[OverrideBtn] callback error: {_e}")
            import traceback as _tb; _tb.print_exc()
            try:
                if not interaction.response.is_done():
                    await interaction.response.send_message(f"❌ Override failed to open: {_e}", ephemeral=True)
                else:
                    await interaction.followup.send(f"❌ Override failed to open: {_e}", ephemeral=True)
            except Exception:
                pass


class _ASchedPingNonRespondersBtn(discord.ui.Button):
    def __init__(self):
        super().__init__(
            label="Ping Non-Responders",
            emoji="📩",
            style=discord.ButtonStyle.secondary,
            custom_id="diff_asched_ping_nonresponders",
            row=2,
        )

    async def callback(self, interaction: discord.Interaction) -> None:
        is_staff = any(
            r.id in _LEADERSHIP_ROLE_IDS
            for r in getattr(interaction.user, "roles", [])
        )
        if not is_staff:
            return await interaction.response.send_message(
                "Only leadership can ping non-responders.", ephemeral=True
            )
        guild = interaction.guild
        if not guild:
            return await interaction.response.send_message("Server not found.", ephemeral=True)

        data   = _hrsvp_load()
        responded_uids: set = set()
        for day in _HRSVP_DAYS:
            slot = data.get(day, {})
            for status in ("yes", "no", "maybe"):
                for e in slot.get(status, []):
                    responded_uids.add(_hrsvp_uid(e))

        host_role = guild.get_role(HOST_ROLE_ID)
        if not host_role:
            return await interaction.response.send_message("Host role not found.", ephemeral=True)

        non_responders = [m for m in host_role.members if str(m.id) not in responded_uids and not m.bot]
        if not non_responders:
            return await interaction.response.send_message(
                "✅ All hosts have submitted their availability this week!", ephemeral=True
            )

        # Defer immediately — DM loop can take several seconds
        await interaction.response.defer(ephemeral=True)

        dm_embed = discord.Embed(
            title="📋 Host Availability Reminder",
            description=(
                "Hey! You haven't submitted your availability for this week's meet schedule yet.\n\n"
                f"Please head to <#{HOST_RSVP_CHANNEL_ID}> and mark your availability "
                "for **Meet 1, Meet 2, and Meet 3**.\n\n"
                "• ✅ **Available** — mark which slots you can host\n"
                "• ❌ **Unavailable** — let leadership know you can't this week\n"
                "• ❓ **Maybe** — note your preference and we'll follow up\n\n"
                "Tap **My Status** on the panel to see what you've already submitted."
            ),
            color=discord.Color.orange(),
            timestamp=utc_now(),
        )
        dm_embed.set_footer(text="DIFF Meets • Host Availability Reminder")

        sent, failed = 0, 0
        for member in non_responders:
            try:
                await member.send(embed=dm_embed)
                sent += 1
            except Exception:
                failed += 1

        await interaction.followup.send(
            f"📩 Reminded **{sent}** host{'s' if sent != 1 else ''} via DM."
            + (f" ({failed} had DMs closed)" if failed else ""),
            ephemeral=True,
        )


class AutoScheduleView(discord.ui.View):
    def __init__(self, bot_ref=None):
        super().__init__(timeout=None)
        self._bot_ref = bot_ref
        self.add_item(_ASchedReminderBtn())
        self.add_item(_ASchedOverrideBtn())
        self.add_item(_ASchedPingNonRespondersBtn())
        self.add_item(_ASchedSubmitBtn())

    @discord.ui.button(label="Refresh", emoji="🔄", style=discord.ButtonStyle.secondary, custom_id=_ASCHED_REFRESH_ID)
    async def refresh_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        await _asched_update_panel(interaction.client)
        await interaction.response.send_message("Schedule panel refreshed.", ephemeral=True)

    @discord.ui.button(label="Rebuild Schedule", emoji="🧠", style=discord.ButtonStyle.primary, custom_id=_ASCHED_REBUILD_ID)
    async def rebuild_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        is_staff = any(
            r.id in _LEADERSHIP_HOST_ROLE_IDS
            for r in getattr(interaction.user, "roles", [])
        )
        if not is_staff:
            await interaction.response.send_message("Only staff can rebuild the schedule.", ephemeral=True)
            return
        schedule = _asched_build()
        await _asched_update_panel(interaction.client)
        # Only auto-post to upcoming-meet when every slot has a confirmed host
        all_filled = all(schedule["days"].get(d, {}).get("host_id") for d in _HRSVP_DAYS)
        if all_filled:
            await _asched_post_finalized(interaction.client)
        if interaction.guild:
            rc_meets = []
            for idx, day in enumerate(_HRSVP_DAYS, 1):
                entry = schedule["days"].get(day, {})
                rc_meets.append({
                    "meet_number": idx,
                    "class_name": entry.get("class", "TBD"),
                    "start_time": entry.get("time", "TBD"),
                    "host_id": entry.get("host_id"),
                    "date_text": entry.get("day", "TBD"),
                    "is_finalized": False,
                })
            await _rc_sync_from_schedule(interaction.guild, rc_meets)

            # DM each assigned host their meet details
            for day in _HRSVP_DAYS:
                entry = schedule["days"].get(day, {})
                host_id = entry.get("host_id")
                if not host_id:
                    continue
                host_member = interaction.guild.get_member(int(host_id))
                if not host_member:
                    continue
                try:
                    dm_embed = discord.Embed(
                        title=f"📅 You've Been Assigned — {day}",
                        description="You have been assigned as the host for the upcoming meet schedule.",
                        color=discord.Color.blurple(),
                        timestamp=utc_now(),
                    )
                    dm_embed.add_field(name="🗓 Day", value=entry.get("day", "TBD"), inline=True)
                    dm_embed.add_field(name="🕒 Time", value=entry.get("time", "TBD"), inline=True)
                    dm_embed.add_field(name="🎮 Class", value=entry.get("class", "TBD"), inline=True)
                    dm_embed.set_footer(text="DIFF Meets • Host Schedule — questions? Contact leadership.")
                    await host_member.send(embed=dm_embed)
                except discord.Forbidden:
                    pass
                except Exception as _dme:
                    print(f"[AutoSched] DM to host {host_id} failed: {_dme}")
                _hrel_track_confirmed(str(host_id))

        _slots_filled = sum(1 for d in _HRSVP_DAYS if schedule["days"].get(d, {}).get("host_id"))
        _rebuild_msg = "✅ Schedule rebuilt and hosts have been DM'd their assignments."
        if all_filled:
            _rebuild_msg += f"\n📢 All 3 slots confirmed — schedule auto-posted to <#{UPCOMING_MEET_CHANNEL_ID}>."
        else:
            _rebuild_msg += f"\n⚠️ {_slots_filled}/{len(_HRSVP_DAYS)} slots filled — schedule will auto-post to <#{UPCOMING_MEET_CHANNEL_ID}> once all slots are confirmed."
        await interaction.response.send_message(_rebuild_msg, ephemeral=True)


def _asched_is_sched_msg(msg: discord.Message, bot_id: int) -> bool:
    if msg.author.id != bot_id:
        return False
    for row in msg.components:
        for child in row.children:
            cid = getattr(child, "custom_id", "") or ""
            if cid in {_ASCHED_REFRESH_ID, _ASCHED_REBUILD_ID}:
                return True
    return False


async def _asched_update_panel(bot_client) -> None:
    channel = bot_client.get_channel(HOST_RSVP_CHANNEL_ID)
    if not isinstance(channel, discord.TextChannel):
        try:
            channel = await bot_client.fetch_channel(HOST_RSVP_CHANNEL_ID)
        except Exception:
            return
    if not isinstance(channel, discord.TextChannel):
        return
    try:
        embed = _asched_build_embed()
    except Exception as _be:
        print(f"[AutoSched] Build embed error: {_be}")
        return
    view = AutoScheduleView(bot_client)
    async for msg in channel.history(limit=25):
        if _asched_is_sched_msg(msg, bot_client.user.id):
            try:
                await msg.edit(embed=embed, view=view)
            except Exception:
                pass
            return
    try:
        await channel.send(embed=embed, view=view)
    except Exception as e:
        print(f"[AutoSched] Panel send failed: {e}")


# -------------------------------------------------------
# Weekly host DM reminder — every Sunday at 12 PM ET
# -------------------------------------------------------
_HOST_TEAM_CHANNEL_ID = 1486228191243669646


def _hrsvp_responded_uids() -> set:
    """Return set of user IDs who have responded to any meet slot this week."""
    data = _hrsvp_load()
    uids: set = set()
    for day in _HRSVP_DAYS:
        slot = data.get(day, {})
        for bucket in ("yes", "no", "maybe"):
            for entry in slot.get(bucket, []):
                uids.add(_hrsvp_uid(entry))
    return uids


async def _do_host_weekly_reminder(force: bool = False) -> bool:
    """Send the weekly host availability reminder.

    Returns True if the reminder was actually sent, False if skipped.
    force=True bypasses the Sunday-noon guard (for manual/staff triggers).
    """
    try:
        from zoneinfo import ZoneInfo
        now_et = datetime.now(ZoneInfo("America/New_York"))
    except Exception:
        return False

    if not force:
        if now_et.weekday() != 6 or now_et.hour < 12:
            return False

    # Deduplicate — one blast per calendar day max (unless forced)
    today_str = now_et.strftime("%Y-%m-%d")
    sched = _asched_load()
    if not force and sched.get("_reminder_last_sent") == today_str:
        return False
    sched["_reminder_last_sent"] = today_str
    _asched_save(sched)

    guild = next((g for g in bot.guilds if g.id == GUILD_ID), None)
    if not guild:
        return False
    host_role = guild.get_role(HOST_ROLE_ID)
    if not host_role:
        return False

    panel_url = f"https://discord.com/channels/{GUILD_ID}/{HOST_RSVP_CHANNEL_ID}"

    # Hosts who haven't responded yet
    responded = _hrsvp_responded_uids()
    pending = [m for m in host_role.members if str(m.id) not in {str(u) for u in responded}]

    # ── Channel post ──────────────────────────────────────────
    host_ch = guild.get_channel(_HOST_TEAM_CHANNEL_ID)
    if isinstance(host_ch, discord.TextChannel):
        ch_embed = discord.Embed(
            title="📅 New Week — Mark Your Availability!",
            description=(
                "A new DIFF Meet week has started **(Sunday–Saturday)**.\n\n"
                f"📌 **[Open the Host Availability Panel]({panel_url})**\n\n"
                "Use the buttons to mark:\n"
                "✅ **Available** — include your time, day, and class\n"
                "❌ **Unavailable** — can't host this week\n"
                "❓ **Maybe** — unsure, check back later\n\n"
                "*Leadership will rebuild the schedule once responses are in.*"
            ),
            color=discord.Color.blurple(),
            timestamp=utc_now(),
        )
        ch_embed.set_thumbnail(url=DIFF_LOGO_URL)
        ch_embed.set_footer(text="DIFF Meets • Weekly Host Reminder — Sunday 12 PM ET")
        if pending:
            pending_mentions = " ".join(m.mention for m in pending)
            ch_embed.add_field(
                name="⏳ Still needs to respond",
                value=pending_mentions,
                inline=False,
            )
        try:
            await host_ch.send(embed=ch_embed)
        except Exception as _ce:
            print(f"[HostReminder] Channel post failed: {_ce}")

    # ── DM only hosts who haven't responded ──────────────────
    dm_embed = discord.Embed(
        title="📅 New Week — Mark Your Availability!",
        description=(
            "Hey! A new DIFF Meet week has started **(Sunday–Saturday)**.\n\n"
            "You haven't marked your availability yet — please do so when you can.\n\n"
            f"📌 **[Open the Host Availability Panel]({panel_url})**\n\n"
            "✅ **Available** — include your time, day, and class\n"
            "❌ **Unavailable** — can't host this week\n"
            "❓ **Maybe** — unsure, check back later\n\n"
            "*Leadership will rebuild the schedule once responses are in.*"
        ),
        color=discord.Color.blurple(),
        timestamp=utc_now(),
    )
    dm_embed.set_thumbnail(url=DIFF_LOGO_URL)
    dm_embed.set_footer(text="DIFF Meets • Weekly Host Reminder — Sunday 12 PM ET")

    sent = failed = 0
    for member in pending:
        try:
            await member.send(embed=dm_embed)
            sent += 1
        except discord.Forbidden:
            failed += 1
        except Exception as _e:
            print(f"[HostReminder] DM to {member.id} failed: {_e}")
            failed += 1
    print(f"[HostReminder] Weekly reminder — {sent} DMs delivered, {failed} failed, {len(host_role.members) - len(pending)} already responded.")
    if failed > 0:
        try:
            logs_ch = guild.get_channel(STAFF_LOGS_CHANNEL_ID)
            if isinstance(logs_ch, discord.TextChannel):
                await logs_ch.send(embed=discord.Embed(
                    title="⚠️ Host Reminder — DM Failures",
                    description=(
                        f"**{failed}** host(s) could not receive the weekly availability reminder DM "
                        f"(DMs likely closed).\n\n"
                        f"✅ Delivered: {sent} · ❌ Failed: {failed}"
                    ),
                    color=discord.Color.orange(),
                    timestamp=datetime.now(_EST_TZ),
                ).set_footer(text="DIFF Meets • Host Reminder System"))
        except Exception:
            pass

    # ── Color team reminder ───────────────────────────────────
    color_role = guild.get_role(COLOR_TEAM_ROLE_ID)
    color_ch   = guild.get_channel(COLOR_TEAM_POST_CHANNEL_ID)
    color_panel_url = f"https://discord.com/channels/{GUILD_ID}/{COLOR_SUBMISSION_CHANNEL_ID}"

    color_embed = discord.Embed(
        title="🎨 New Week — Submit Your Crew Color!",
        description=(
            "Hey! A new week has started. If you have a color to submit for crew review, now's the time.\n\n"
            f"📌 **[Open the Color Submission Panel]({color_panel_url})**\n\n"
            "**What to include:**\n"
            "• Color name\n"
            "• HEX code (e.g. `#FF9742`)\n"
            "• Image link of your preview car\n\n"
            "Voting goes live **Tuesday ~12 PM ET** and the winner is announced **Monday ~12 PM ET**.\n\n"
            "*Keep it clean, realistic, and meet-ready.*"
        ),
        color=discord.Color.og_blurple(),
        timestamp=utc_now(),
    )
    color_embed.set_thumbnail(url=DIFF_LOGO_URL)
    color_embed.set_footer(text="DIFF Meets • Color Team — Weekly Submission Reminder")

    # Channel post
    if isinstance(color_ch, discord.TextChannel):
        ping = color_role.mention if color_role else ""
        try:
            await color_ch.send(content=ping or None, embed=color_embed)
        except Exception as _cce:
            print(f"[ColorReminder] Channel post failed: {_cce}")

    # DM color team members
    if color_role:
        cs = cd = 0
        for member in color_role.members:
            try:
                await member.send(embed=color_embed)
                cs += 1
            except discord.Forbidden:
                cd += 1
            except Exception as _dme:
                print(f"[ColorReminder] DM to {member.id} failed: {_dme}")
                cd += 1
        print(f"[ColorReminder] Weekly reminder — {cs} delivered, {cd} failed.")
    return True


async def __host_weekly_reminder_loop_logic():
    """Every 30 min: check if it's Sunday ≥12 PM ET and send the reminder if not yet sent today."""
    await _do_host_weekly_reminder(force=False)

@tasks.loop(minutes=30)
async def _host_weekly_reminder_loop():
    _loop_success('_host_weekly_reminder_loop')
    try:
        await run_with_timeout('_host_weekly_reminder_loop', __host_weekly_reminder_loop_logic(), timeout=120)
    except Exception as _lte:
        await _handle_loop_error('_host_weekly_reminder_loop', _lte, _host_weekly_reminder_loop)
@_host_weekly_reminder_loop.error
async def __host_weekly_reminder_loop_on_error(error: Exception) -> None:
    await _handle_loop_error('_host_weekly_reminder_loop', error, _host_weekly_reminder_loop)
@_host_weekly_reminder_loop.before_loop
async def _before_host_weekly_reminder():
    await bot.wait_until_ready()


@bot.command(name="sendhostavailabilityreminder", aliases=["hostreminder"])
async def _cmd_send_host_reminder(ctx: commands.Context):
    """Manually trigger the Sunday host availability reminder (staff only)."""
    is_staff = (
        isinstance(ctx.author, discord.Member)
        and (
            ctx.author.guild_permissions.administrator
            or any(r.id in _LEADERSHIP_ROLE_IDS for r in ctx.author.roles)
        )
    )
    if not is_staff:
        await ctx.send("Staff only.", delete_after=6)
        return
    try:
        await ctx.message.delete()
    except Exception:
        pass
    msg = await ctx.send("📤 Sending host availability reminder…")
    sent = await _do_host_weekly_reminder(force=True)
    if sent:
        await msg.edit(content="✅ Host availability reminder sent to the channel and all pending hosts.")
    else:
        await msg.edit(content="⚠️ Reminder couldn't be sent (no guild or host role found).")


