async def post_or_refresh_hierarchy_panel(guild: discord.Guild):
    channel = guild.get_channel(HIERARCHY_CHANNEL_ID)
    if channel is None:
        return False, "Hierarchy channel not found."

    embeds = build_hierarchy_embeds(guild)
    support_view = build_hierarchy_support_view()
    hierarchy_message_ids = data.get("hierarchy_message_ids", [])

    saved_messages = []
    if hierarchy_message_ids:
        for message_id in hierarchy_message_ids:
            try:
                msg = await channel.fetch_message(message_id)
                saved_messages.append(msg)
            except discord.NotFound:
                saved_messages = []
                break

    if saved_messages and len(saved_messages) == len(embeds):
        for i, (msg, embed) in enumerate(zip(saved_messages, embeds)):
            is_last = i == len(embeds) - 1
            await msg.edit(
                content="## DIFF Hierarchy Panel" if i == 0 else None,
                embed=embed,
                view=support_view if is_last else discord.ui.View(),
            )
        await cleanup_extra_hierarchy_messages(channel, [msg.id for msg in saved_messages])
        return True, channel.mention

    # recover old single-id storage if present
    legacy_message_id = data.get("hierarchy_message_id")
    if not saved_messages and legacy_message_id:
        try:
            legacy_message = await channel.fetch_message(legacy_message_id)
            saved_messages = [legacy_message]
        except discord.NotFound:
            saved_messages = []

    if saved_messages:
        for msg in saved_messages:
            try:
                await msg.delete()
            except Exception:
                pass

    new_ids = []
    for index, embed in enumerate(embeds):
        content = "## DIFF Hierarchy Panel" if index == 0 else None
        is_last = index == len(embeds) - 1
        msg = await channel.send(content=content, embed=embed, view=support_view if is_last else None)
        new_ids.append(msg.id)

    data["hierarchy_message_ids"] = new_ids
    data["hierarchy_message_id"] = new_ids[0] if new_ids else None
    save_data(data)
    await cleanup_extra_hierarchy_messages(channel, new_ids)
    return True, channel.mention


async def _auto_refresh_hierarchy_panel(guild: discord.Guild):
    await asyncio.sleep(15)
    hierarchy_message_ids = data.get("hierarchy_message_ids", [])
    if not hierarchy_message_ids:
        return
    channel = guild.get_channel(HIERARCHY_CHANNEL_ID)
    if channel is None:
        return
    embeds = build_hierarchy_embeds(guild)
    support_view = build_hierarchy_support_view()
    saved_messages = []
    for message_id in hierarchy_message_ids:
        try:
            msg = await channel.fetch_message(message_id)
            saved_messages.append(msg)
        except discord.NotFound:
            return
    if len(saved_messages) != len(embeds):
        return
    for i, (msg, embed) in enumerate(zip(saved_messages, embeds)):
        is_last = i == len(embeds) - 1
        try:
            await msg.edit(
                content="## DIFF Hierarchy Panel" if i == 0 else None,
                embed=embed,
                view=support_view if is_last else discord.ui.View(),
            )
        except Exception:
            pass


def build_status_embed(guild: discord.Guild) -> discord.Embed:
    gta_hosts:    list[str] = []
    online_hosts: list[str] = []
    offline_hosts: list[str] = []

    hp_data    = _hp_load()
    host_stats = hp_data.get("host_stats", {})

    def _last_session_str(uid: int) -> str:
        """Return a Discord relative timestamp for the host's last HP session, or empty string."""
        s = host_stats.get(str(uid), {})
        last = s.get("last_session_at")
        if last:
            try:
                ts = int(datetime.fromisoformat(str(last).replace("Z", "+00:00")).timestamp())
                return f"<t:{ts}:R>"
            except Exception:
                pass
        return ""

    def _tier(meets: int) -> str:
        """Tier badge based on career meets hosted (uses real activity data)."""
        if meets >= 15:
            return "💎 Elite"
        if meets >= 5:
            return "🔥 Senior"
        if meets >= 1:
            return "⭐ Junior"
        return "🆕 New"

    for host in data["hosts"]:
        member  = guild.get_member(host["discord_id"])
        profile = host.get("profile_url", "")
        link    = f" [↗]({profile})" if profile else ""
        uid     = host["discord_id"]

        # Pull real meet count from the activity file
        meets     = get_user_stats(uid).get("meets_hosted", 0)
        tier      = _tier(meets)
        meets_str = f"{meets} meet{'s' if meets != 1 else ''}"
        last_str  = _last_session_str(uid)

        if member:
            is_online = member.status != discord.Status.offline
            activity  = get_activity(member)
            name      = member.display_name
        else:
            is_online = False
            activity  = "Offline"
            name      = host["name"]

        activity_lower = activity.lower()

        if is_online:
            if "grand theft auto" in activity_lower or "gta" in activity_lower:
                line = f"🎮 **{name}** • {tier} • {meets_str}{link}"
                gta_hosts.append(line)
            else:
                act_label = (activity[:22] + "…") if len(activity) > 24 else (activity or "Online")
                line = f"🟡 **{name}** — `{act_label}` • {tier} • {meets_str}{link}"
                online_hosts.append(line)
        else:
            # Offline: show tier + meets + last session (if any)
            if last_str:
                line = f"🔴 **{name}** • {tier} • {meets_str} • last {last_str}{link}"
            elif meets == 0:
                line = f"🔴 **{name}** • {tier} • no meets yet{link}"
            else:
                line = f"🔴 **{name}** • {tier} • {meets_str}{link}"
            offline_hosts.append(line)

    # Progress bar
    total        = max(len(gta_hosts) + len(online_hosts) + len(offline_hosts), 1)
    online_count = len(gta_hosts) + len(online_hosts)
    filled       = round(online_count / total * 10)
    bar          = "🟩" * filled + "🟥" * (10 - filled)
    summary_line = f"{bar}  **{online_count}/{total}** online"

    # Dynamic color
    if gta_hosts:
        color = 0x43B581   # green
    elif online_hosts:
        color = 0xFAA61A   # yellow
    else:
        color = 0xED4245   # red

    embed = discord.Embed(
        title="🏁 DIFF Host Activity Board",
        description=(
            "Real-time status of your DIFF host team.\n"
            "━━━━━━━━━━━━━━━━━━━━━━\n"
            f"{summary_line}"
        ),
        color=color,
    )
    embed.set_thumbnail(url=DIFF_LOGO_URL)

    if gta_hosts:
        embed.add_field(
            name=f"🎮 In GTA Right Now  ({len(gta_hosts)})",
            value="\n".join(gta_hosts),
            inline=False,
        )
    if online_hosts:
        embed.add_field(
            name=f"🟡 Online Elsewhere  ({len(online_hosts)})",
            value="\n".join(online_hosts),
            inline=False,
        )
    if offline_hosts:
        embed.add_field(
            name=f"🔴 Offline  ({len(offline_hosts)})",
            value="\n".join(offline_hosts),
            inline=False,
        )

    embed.set_footer(text="DIFF Meets • EST. 2020")
    embed.timestamp = datetime.now(timezone.utc)
    return embed


