class _HostWarnAppealBtn(discord.ui.Button):
    def __init__(self, session_id: str, issue: str):
        super().__init__(label="📩 Appeal This Warning", style=discord.ButtonStyle.primary)
        self._session_id = session_id
        self._issue = issue

    async def callback(self, interaction: discord.Interaction) -> None:
        self.disabled = True
        self.label = "✓ Appeal Submitted"
        try:
            await interaction.response.edit_message(view=self.view)
        except Exception:
            await interaction.response.defer()
        staff_ch = bot.get_channel(STAFF_LOGS_CHANNEL_ID)
        if isinstance(staff_ch, discord.TextChannel):
            appeal_embed = discord.Embed(
                title="📩 Host Warning Appeal",
                description=f"{interaction.user.mention} is appealing a host performance warning.",
                color=discord.Color.gold(),
            )
            appeal_embed.add_field(name="Warning", value=self._issue, inline=False)
            appeal_embed.add_field(name="Session ID", value=f"`{self._session_id}`", inline=False)
            appeal_embed.set_footer(text="Review and clear the warning if you agree with the appeal.")
            guild = bot.get_guild(GUILD_ID)
            leader_role = guild.get_role(LEADER_ROLE_ID) if guild else None
            ping = leader_role.mention if leader_role else None
            await staff_ch.send(content=ping, embed=appeal_embed)


class _HostWarnAppealView(discord.ui.View):
    def __init__(self, session_id: str, issue: str):
        super().__init__(timeout=86400)  # 24h to appeal
        self.add_item(_HostWarnAppealBtn(session_id, issue))


def _hp_recap_embed(session: dict, score: int, warnings: list[str]) -> discord.Embed:
    """Public recap embed posted to the recap channel after a session ends."""
    color = discord.Color.green() if not warnings else discord.Color.orange()
    embed = discord.Embed(
        title=f"🏁 Meet Recap — {session['meet_name']}",
        color=color,
        timestamp=utc_now(),
    )
    embed.add_field(name="🎮 Host", value=f"<@{session['host_id']}>", inline=True)
    embed.add_field(name="👥 Total Attendance", value=str(session.get("total_attendance", 0)), inline=True)
    embed.add_field(name="🏅 DIFF Attendance", value=str(session.get("diff_attendance", 0)), inline=True)
    embed.add_field(name="📊 Score", value=f"**{score}**", inline=True)
    embed.add_field(name="⚠ Warnings", value=str(len(warnings)) if warnings else "None", inline=True)
    embed.add_field(
        name="✅ Compliance",
        value=(
            f"Blacklist Checked: {'✅' if session.get('blacklist_checked') else '❌'}\n"
            f"Checklist Complete: {'✅' if session.get('checklist_completed') else '❌'}\n"
            f"Lobby Proof Posted: {'✅' if session.get('lobby_proof_posted') else '❌'}\n"
            f"Today's Meet Posted: {'✅' if session.get('todays_meet_posted') else '❌'}"
        ),
        inline=False,
    )
    embed.set_footer(text="DIFF Host Performance System")
    return embed


class HostSessionView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=None)

    async def _get_session(self, interaction: discord.Interaction):
        if not isinstance(interaction.channel, discord.Thread):
            await interaction.response.send_message("Use this inside a session thread.", ephemeral=True)
            return None
        data = _hp_load()
        for s in data["active_sessions"].values():
            if s["thread_id"] == interaction.channel.id and not s.get("ended"):
                return s, data
        await interaction.response.send_message("No active session found in this thread.", ephemeral=True)
        return None

    async def _refresh_embed(self, thread: discord.Thread, session: dict) -> None:
        try:
            async for msg in thread.history(limit=15, oldest_first=True):
                if msg.author.id == bot.user.id and msg.embeds:
                    await msg.edit(embed=_hp_session_embed(session), view=self)
                    return
        except Exception:
            pass

    @discord.ui.button(label="Blacklist Checked", emoji="🚫", style=discord.ButtonStyle.danger,
                       custom_id="diff_host_session:blacklist_checked", row=0)
    async def blacklist_checked(self, interaction: discord.Interaction, button: discord.ui.Button):
        result = await self._get_session(interaction)
        if not result:
            return
        session, data = result
        session["blacklist_checked"] = True
        _hp_save(data)
        await self._refresh_embed(interaction.channel, session)
        await interaction.response.send_message("Blacklist check confirmed. ✅", ephemeral=True)

    @discord.ui.button(label="Checklist Complete", emoji="📝", style=discord.ButtonStyle.success,
                       custom_id="diff_host_session:checklist_complete", row=0)
    async def checklist_complete(self, interaction: discord.Interaction, button: discord.ui.Button):
        result = await self._get_session(interaction)
        if not result:
            return
        session, data = result
        session["checklist_completed"] = True
        _hp_save(data)
        await self._refresh_embed(interaction.channel, session)
        await interaction.response.send_message("Checklist completion confirmed. ✅", ephemeral=True)

    @discord.ui.button(label="Lobby Opened", emoji="🚪", style=discord.ButtonStyle.primary,
                       custom_id="diff_host_session:lobby_opened", row=0)
    async def lobby_opened(self, interaction: discord.Interaction, button: discord.ui.Button):
        result = await self._get_session(interaction)
        if not result:
            return
        session, data = result
        session["lobby_opened"] = True
        _hp_save(data)
        await self._refresh_embed(interaction.channel, session)
        await interaction.response.send_message("Lobby opening confirmed. ✅", ephemeral=True)

    @discord.ui.button(label="Proof Posted", emoji="📸", style=discord.ButtonStyle.secondary,
                       custom_id="diff_host_session:proof_posted", row=1)
    async def proof_posted(self, interaction: discord.Interaction, button: discord.ui.Button):
        result = await self._get_session(interaction)
        if not result:
            return
        session, data = result
        session["lobby_proof_posted"] = True
        _hp_save(data)
        await self._refresh_embed(interaction.channel, session)
        await interaction.response.send_message("Lobby proof confirmed. ✅", ephemeral=True)

    @discord.ui.button(label="Today's Meet Posted", emoji="📢", style=discord.ButtonStyle.primary,
                       custom_id="diff_host_session:todays_meet_posted", row=1)
    async def todays_meet_posted(self, interaction: discord.Interaction, button: discord.ui.Button):
        result = await self._get_session(interaction)
        if not result:
            return
        session, data = result
        session["todays_meet_posted"] = True
        _hp_save(data)
        await self._refresh_embed(interaction.channel, session)
        await interaction.response.send_message("Today's Meet confirmation saved. ✅", ephemeral=True)

    @discord.ui.button(label="Submit Attendance", emoji="📊", style=discord.ButtonStyle.success,
                       custom_id="diff_host_session:submit_attendance", row=1)
    async def submit_attendance(self, interaction: discord.Interaction, button: discord.ui.Button):
        result = await self._get_session(interaction)
        if not result:
            return
        session, _ = result
        await interaction.response.send_modal(_HPAttendanceModal(session["session_id"]))

    @discord.ui.button(label="Lock VC", emoji="🔒", style=discord.ButtonStyle.secondary,
                       custom_id="diff_host_session:lock_vc", row=2)
    async def lock_vc(self, interaction: discord.Interaction, button: discord.ui.Button):
        result = await self._get_session(interaction)
        if not result:
            return
        session, data = result
        is_host = interaction.user.id == session["host_id"]
        is_staff = isinstance(interaction.user, discord.Member) and interaction.user.guild_permissions.manage_guild
        if not is_host and not is_staff:
            return await interaction.response.send_message("Only the session host or staff can do this.", ephemeral=True)
        vc_id = session.get("voice_channel_id")
        if not vc_id:
            return await interaction.response.send_message("No voice channel is linked to this session.", ephemeral=True)
        vc = interaction.guild.get_channel(vc_id) if interaction.guild else None
        if not isinstance(vc, discord.VoiceChannel):
            return await interaction.response.send_message("Session voice channel not found.", ephemeral=True)
        everyone = interaction.guild.default_role
        is_locked = session.get("vc_locked", False)
        if is_locked:
            await vc.set_permissions(everyone, connect=None)
            session["vc_locked"] = False
            _hp_save(data)
            await interaction.response.send_message("✅ Voice channel unlocked — members can join again.", ephemeral=True)
        else:
            await vc.set_permissions(everyone, connect=False)
            session["vc_locked"] = True
            _hp_save(data)
            await interaction.response.send_message("🔒 Voice channel locked — no new members can join.", ephemeral=True)

    @discord.ui.button(label="End Meet Session", emoji="🏁", style=discord.ButtonStyle.danger,
                       custom_id="diff_host_session:end_session", row=2)
    async def end_session(self, interaction: discord.Interaction, button: discord.ui.Button):
        result = await self._get_session(interaction)
        if not result:
            return
        session, data = result

        is_host = interaction.user.id == session["host_id"]
        is_staff = isinstance(interaction.user, discord.Member) and interaction.user.guild_permissions.manage_guild
        if not is_host and not is_staff:
            return await interaction.response.send_message("Only the session host or staff can end this session.", ephemeral=True)

        session["ended"] = True
        session["ended_at"] = _hp_utcnow()
        score, warnings = _hp_score(session)
        session["score"] = score
        session["warning_count"] = len(warnings)

        stats = data["host_stats"].setdefault(str(session["host_id"]), {
            "host_name": session["host_name"],
            "meets_hosted": 0, "total_attendance_sum": 0, "diff_attendance_sum": 0,
            "blacklist_checks": 0, "checklists_completed": 0, "lobby_proofs": 0,
            "todays_meet_posts": 0, "warning_count": 0, "score_total": 0, "last_session_at": None,
        })
        stats["host_name"] = session["host_name"]
        stats["meets_hosted"] += 1
        stats["total_attendance_sum"] += session["total_attendance"]
        stats["diff_attendance_sum"] += session["diff_attendance"]
        stats["blacklist_checks"] += 1 if session["blacklist_checked"] else 0
        stats["checklists_completed"] += 1 if session["checklist_completed"] else 0
        stats["lobby_proofs"] += 1 if session["lobby_proof_posted"] else 0
        stats["todays_meet_posts"] += 1 if session["todays_meet_posted"] else 0
        stats["warning_count"] += len(warnings)
        stats["score_total"] += score
        stats["last_session_at"] = session["ended_at"]
        _hp_save(data)

        await self._refresh_embed(interaction.channel, session)

        staff_ch = bot.get_channel(STAFF_LOGS_CHANNEL_ID)
        if isinstance(staff_ch, discord.TextChannel):
            log_embed = discord.Embed(
                title="📊 Host Performance Update",
                description=f"Host performance logged for <@{session['host_id']}>.",
                color=discord.Color.blue(),
            )
            log_embed.add_field(name="Session Summary", value=(
                f"Meet: **{session['meet_name']}**\n"
                f"Total Attendance: **{session['total_attendance']}**\n"
                f"DIFF Attendance: **{session['diff_attendance']}**\n"
                f"Score: **{score}**\n"
                f"Warnings: **{len(warnings)}**"
            ), inline=False)
            log_embed.add_field(name="Compliance", value=(
                f"Blacklist Checked: {'✅' if session['blacklist_checked'] else '❌'}\n"
                f"Checklist Completed: {'✅' if session['checklist_completed'] else '❌'}\n"
                f"Lobby Proof Posted: {'✅' if session['lobby_proof_posted'] else '❌'}\n"
                f"Today's Meet Posted: {'✅' if session['todays_meet_posted'] else '❌'}"
            ), inline=False)
            log_embed.set_footer(text="Auto-generated by DIFF Host Performance System")
            await staff_ch.send(embed=log_embed)
            for issue in warnings:
                warn_embed = discord.Embed(
                    title="⚠️ Host Warning Logged",
                    description=f"A host warning has been logged for <@{session['host_id']}>.",
                    color=discord.Color.red(),
                )
                warn_embed.add_field(name="Warning Details", value=(
                    f"Meet: **{session['meet_name']}**\n"
                    f"Issue: **{issue}**\n"
                    f"Session ID: `{session['session_id']}`"
                ), inline=False)
                warn_embed.set_footer(text="Logged automatically for staff review")
                await staff_ch.send(embed=warn_embed)

        # ── Public recap post ────────────────────────────────────────────
        recap_ch = bot.get_channel(RECAP_CHANNEL_ID)
        if isinstance(recap_ch, discord.TextChannel):
            try:
                await recap_ch.send(embed=_hp_recap_embed(session, score, warnings))
            except Exception as _re:
                print(f"[HostSession] Recap post failed: {_re}")

        # ── DM the host with session summary + appeal buttons ────────────
        host_member = interaction.guild.get_member(session["host_id"]) if interaction.guild else None
        if host_member:
            try:
                dm_embed = discord.Embed(
                    title=f"📋 Your Session Summary — {session['meet_name']}",
                    color=discord.Color.green() if not warnings else discord.Color.orange(),
                    timestamp=utc_now(),
                )
                dm_embed.add_field(name="📊 Score", value=str(score), inline=True)
                dm_embed.add_field(name="👥 Total Attendance", value=str(session.get("total_attendance", 0)), inline=True)
                dm_embed.add_field(name="🏅 DIFF Attendance", value=str(session.get("diff_attendance", 0)), inline=True)
                dm_embed.add_field(
                    name="✅ Compliance",
                    value=(
                        f"Blacklist Checked: {'✅' if session.get('blacklist_checked') else '❌'}\n"
                        f"Checklist Complete: {'✅' if session.get('checklist_completed') else '❌'}\n"
                        f"Lobby Proof Posted: {'✅' if session.get('lobby_proof_posted') else '❌'}\n"
                        f"Today's Meet Posted: {'✅' if session.get('todays_meet_posted') else '❌'}"
                    ),
                    inline=False,
                )
                if warnings:
                    dm_embed.add_field(
                        name="⚠ Warnings",
                        value="\n".join(f"• {w}" for w in warnings),
                        inline=False,
                    )
                    dm_embed.set_footer(text="You may appeal any warning below within 24 hours.")
                else:
                    dm_embed.set_footer(text="Great session — no warnings issued!")
                await host_member.send(embed=dm_embed)
                for issue in warnings:
                    await host_member.send(
                        content=f"⚠ Warning: **{issue}**",
                        view=_HostWarnAppealView(session["session_id"], issue),
                    )
            except discord.Forbidden:
                pass
            except Exception as _de:
                print(f"[HostSession] DM to host failed: {_de}")

        await interaction.response.send_message(
            f"Meet session ended. Score: **{score}** | Warnings: **{len(warnings)}**\n"
            f"This channel will be deleted in **10 seconds**.",
            ephemeral=True,
        )
        try:
            await interaction.channel.send(
                f"✅ Session closed for <@{session['host_id']}>.\n"
                f"**Final Score: {score}** | Warnings: **{len(warnings)}**\n\n"
                f"*This channel will be deleted in 10 seconds.*"
            )
        except Exception:
            pass

        async def _delete_thread():
            await asyncio.sleep(10)
            # Delete the session voice channel
            vc_id = session.get("voice_channel_id")
            if vc_id:
                try:
                    vc = bot.get_channel(vc_id)
                    if isinstance(vc, discord.VoiceChannel):
                        await vc.delete(reason=f"Host session ended — {session.get('meet_name', '')}")
                except Exception as _vc_del_err:
                    print(f"[HostSession] Could not delete session VC: {_vc_del_err}")
            # Delete the session thread
            try:
                if isinstance(interaction.channel, discord.Thread):
                    await interaction.channel.delete()
            except Exception as e:
                print(f"[HostSession] Could not delete thread: {e}")

        asyncio.create_task(_delete_thread())


