    if not stats:
        return await ctx.send("No host stats recorded yet.", delete_after=10)

    # Sort by meets_hosted desc, then score_total desc
    ranked = sorted(
        stats.items(),
        key=lambda kv: (kv[1].get("meets_hosted", 0), kv[1].get("score_total", 0)),
        reverse=True,
    )

    medals = ["🥇", "🥈", "🥉"]
