def _get_theme_guide(theme: str) -> tuple[str, str] | None:
    """Return (display_name, accepted_cars_text) if the theme matches a guide entry, else None."""
    if not theme:
        return None
    lower = theme.lower()
    for keyword, entry in _THEME_GUIDE.items():
        if keyword in lower:
            return entry
    return None


def _om_build_embed(theme: str, host: discord.Member, timestamp: int, notes: str = "") -> discord.Embed:
    embed = discord.Embed(
        title="🏁 DIFF Official Meet",
        color=0xC9A227,
        timestamp=datetime.now(timezone.utc),
    )
    embed.add_field(name="📅 Date", value=f"<t:{timestamp}:F>", inline=True)
    embed.add_field(name="⏰ Begins", value=f"<t:{timestamp}:R>", inline=True)
    embed.add_field(name="\u200b", value="\u200b", inline=True)
    embed.add_field(name="🎙️ Host", value=host.mention, inline=True)
    embed.add_field(name="🎨 Theme", value=theme, inline=True)
    embed.add_field(name="\u200b", value="\u200b", inline=True)
    embed.add_field(
        name="📋 Entry Info",
        value=(
            "Send your vehicle photos to the host before joining, unless told otherwise.\n"
            f"All vehicles must match the meet theme and follow the standards in <#{MEET_INFO_CHANNEL_ID}> and <#{MEET_RULES_CHANNEL_ID}>."
        ),
        inline=False,
    )
    embed.add_field(
        name="📌 Meet Notes",
        value=(
            "• Follow all host instructions at all times\n"
            "• Use #chat for meet communication and updates\n"
            "• Bring clean, realistic, theme-fitting vehicles only"
        ),
        inline=False,
    )
    guide = _get_theme_guide(theme)
    if guide:
        _display_name, _accepted = guide
        embed.add_field(
            name=f"✅ Accepted Cars — {_display_name}",
            value=_accepted,
            inline=False,
        )
    else:
        embed.add_field(
            name="🚗 Style Direction",
            value="Choose vehicles that match tonight's theme and represent DIFF properly.",
            inline=False,
        )
    if notes:
        embed.add_field(name="📝 Staff Notes", value=notes, inline=False)
    embed.set_thumbnail(url=DIFF_LOGO_URL)
    embed.set_footer(text="DIFF Meets • Official Session")
    return embed


@bot.command(name="officialmeet")
async def _cmd_officialmeet(ctx: commands.Context, theme: str, date: str, time_str: str, host: discord.Member):
    if not ctx.author.guild_permissions.manage_guild and not any(
        r.id in _JOIN_STAFF_ROLE_IDS for r in getattr(ctx.author, "roles", [])
    ):
        return
    try:
        await ctx.message.delete()
    except Exception:
        pass
    channel = bot.get_channel(_OFFICIAL_MEET_CHANNEL_ID)
    if not isinstance(channel, discord.TextChannel):
        await ctx.send("Meet announcement channel not found.", delete_after=10)
        return
    try:
        local_dt = datetime.strptime(f"{date} {time_str}", "%Y-%m-%d %H:%M").replace(
            tzinfo=ZoneInfo(_OFFICIAL_MEET_TZ)
        )
    except ValueError:
        await ctx.send("Invalid date/time. Use: `!officialmeet \"Theme\" YYYY-MM-DD HH:MM @Host`", delete_after=15)
        return
    meet_ts = int(local_dt.timestamp())
    if meet_ts <= int(datetime.now(timezone.utc).timestamp()):
        await ctx.send("That meet time is already in the past.", delete_after=10)
        return
    try:
        sent = await channel.send(
            content=f"<@&{PS5_ROLE_ID}> <@&{NOTIFY_ROLE_ID}>",
            embed=_om_build_embed(theme=theme, host=host, timestamp=meet_ts),
            view=_OfficialMeetRSVPView(),
            allowed_mentions=discord.AllowedMentions(roles=True, users=True),
        )
    except discord.Forbidden:
        await ctx.send("Missing permissions to post in the meet channel.", delete_after=10)
        return
    record = _OmRecord(
        message_id=sent.id,
        channel_id=channel.id,
        host_id=host.id,
        theme=theme,
        timestamp=meet_ts,
    )
    _om_upsert_record(record)
    _om_schedule_reminders(record)
    await ctx.send(f"Official meet posted in {channel.mention} for <t:{meet_ts}:F>.", delete_after=15)


