_OM_PANEL_FILE = os.path.join(DATA_FOLDER, "diff_om_panel.json")


def _om_panel_load() -> dict:
    try:
        with open(_OM_PANEL_FILE) as f:
            return json.load(f)
    except Exception:
        return {}


def _om_panel_save(data: dict):
    try:
        _atomic_json_save(_OM_PANEL_FILE, data)
    except Exception:
        pass


def _om_parse_datetime(date_str: str, time_str: str) -> int | None:
    """Parse 'YYYY-MM-DD' + '8pm EST' into a Unix timestamp. Returns None on failure."""
    from datetime import timedelta
    tz_abbr = "EST"
    clean_time = time_str.strip()
    m = re.search(r'([A-Za-z]{2,4})$', clean_time)
    if m:
        tz_abbr = m.group(1).upper()
        clean_time = clean_time[:m.start()].strip()
    tz_name = _POPUP_TZ_MAP.get(tz_abbr, "America/New_York")
    try:
        tz = ZoneInfo(tz_name)
        date_part = datetime.strptime(date_str.strip(), "%Y-%m-%d").date()
        tm = re.match(r'(\d{1,2})(?::(\d{2}))?\s*(am|pm)?', clean_time, re.IGNORECASE)
        if not tm:
            return None
        hour = int(tm.group(1))
        minute = int(tm.group(2)) if tm.group(2) else 0
        meridiem = tm.group(3).lower() if tm.group(3) else None
        if meridiem == "pm" and hour != 12:
            hour += 12
        elif meridiem == "am" and hour == 12:
            hour = 0
        local_dt = datetime(date_part.year, date_part.month, date_part.day, hour, minute, tzinfo=tz)
        return int(local_dt.timestamp())
    except Exception:
        return None


def _om_next_meet() -> "_OmRecord | None":
    """Return the soonest upcoming non-ended meet, or None."""
    data = _om_load_records()
    now_ts = int(datetime.now(timezone.utc).timestamp())
    upcoming: list[_OmRecord] = []
    for raw in data.values():
        try:
            rec = _OmRecord(**{k: v for k, v in raw.items() if k in _OmRecord.__dataclass_fields__})
            if not rec.ended and rec.timestamp > now_ts:
                upcoming.append(rec)
        except Exception:
            pass
    return min(upcoming, key=lambda r: r.timestamp) if upcoming else None


def _om_restore_rsvp_counts():
    """Restore in-memory RSVP dicts from saved records (called on bot startup)."""
    data = _om_load_records()
    for raw in data.values():
        try:
            rec = _OmRecord(**{k: v for k, v in raw.items() if k in _OmRecord.__dataclass_fields__})
            if rec.ended:
                continue
            _om_rsvps[rec.message_id] = {
                "yes":   set(rec.rsvp_yes_ids),
                "maybe": set(rec.rsvp_maybe_ids),
                "no":    set(rec.rsvp_no_ids),
            }
        except Exception:
            pass


def _om_panel_build_embed() -> discord.Embed:
    embed = discord.Embed(
        title="🏁 DIFF Official Meet Hub",
        description=(
            f"Use the **Schedule Official Meet** button below to post an official meet "
            f"announcement to <#{_OFFICIAL_MEET_CHANNEL_ID}>."
        ),
        color=discord.Color.dark_gold(),
    )
    embed.set_thumbnail(url=DIFF_LOGO_URL)

    # Show next scheduled meet if one exists
    next_meet = _om_next_meet()
    if next_meet:
        status = "🟢 Live" if next_meet.started else "📅 Upcoming"
        embed.add_field(
            name=f"{status} — Next Official Meet",
            value=(
                f"**{next_meet.theme}**\n"
                f"<t:{next_meet.timestamp}:F>  •  <t:{next_meet.timestamp}:R>\n"
                f"🎙️ Host: <@{next_meet.host_id}>"
            ),
            inline=False,
        )
    else:
        embed.add_field(
            name="📅 Next Official Meet",
            value="No meet currently scheduled.",
            inline=False,
        )

    embed.add_field(
        name="📋 What Gets Posted",
        value=(
            "• Full meet announcement with role pings\n"
            "• Auto-converting Discord timestamp\n"
            "• Entry info, custom notes, and style direction\n"
            "• RSVP buttons for members\n"
            "• Start / End / Cancel meet controls for staff\n"
            "• Automatic 1-hour and 15-minute reminders"
        ),
        inline=False,
    )
    embed.add_field(
        name="🔒 Access",
        value="Restricted to **staff and assigned hosts** only.",
        inline=False,
    )
    embed.set_footer(text="DIFF Official Meet System")
    embed.timestamp = datetime.now(timezone.utc)
    return embed


def _om_parse_combined_datetime(text: str) -> int | None:
    """Parse a natural-language 'Date & Time' string into a Unix timestamp.
    Accepts: 'April 5 9:00 PM EST', '04/05 9PM CST', '2026-04-05 21:00 UTC', etc.
    """
    text = text.strip()
    tz_name = "America/New_York"
    m = re.search(r'\b([A-Za-z]{2,5})$', text)
    if m:
        abbr = m.group(1).upper()
        tz_name = _POPUP_TZ_MAP.get(abbr, tz_name)
        text = text[:m.start()].strip()
    try:
        tz = ZoneInfo(tz_name)
    except Exception:
        tz = ZoneInfo("America/New_York")
    text = re.sub(r'(\d)(am|pm)', r'\1 \2', text, flags=re.IGNORECASE)
    text = re.sub(r'\s+', ' ', text).strip()
    if not re.search(r'\b(202\d|203\d)\b', text):
        text = f"{text} {datetime.now(timezone.utc).year}"
    fmts = [
        "%B %d %Y %I:%M %p", "%B %d %Y %I %p",
        "%B %d, %Y %I:%M %p", "%B %d, %Y %I %p",
        "%m/%d/%Y %I:%M %p", "%m/%d/%Y %I %p",
        "%m/%d %I:%M %p %Y", "%m/%d %I %p %Y",
        "%Y-%m-%d %H:%M",    "%Y-%m-%d %I:%M %p",
        "%Y-%m-%d %I %p",
    ]
    for fmt in fmts:
        try:
            naive = datetime.strptime(text, fmt)
            return int(naive.replace(tzinfo=tz).timestamp())
        except ValueError:
            continue
    return None


class _HostPickerView(discord.ui.View):
    """Ephemeral view shown before the schedule modal — lets staff pick a host from a member select."""

    def __init__(self):
        super().__init__(timeout=120)

    @discord.ui.select(
        cls=discord.ui.UserSelect,
        placeholder="Search and select the meet host…",
        min_values=1,
        max_values=1,
    )
    async def host_select(self, interaction: discord.Interaction, select: discord.ui.UserSelect):
        selected = select.values[0]
        guild = interaction.guild

        # Ensure we have a Member object (not just a User) so role check is reliable
        member = selected if isinstance(selected, discord.Member) else None
        if member is None and guild:
            try:
                member = await guild.fetch_member(selected.id)
            except Exception:
                pass

        if member is None:
            await interaction.response.send_message(
                "Couldn't resolve that user as a server member. Try again.", ephemeral=True
            )
            return

        # Validate Host role
        has_role = any(r.id == HOST_ROLE_ID for r in member.roles)
        if not has_role:
            await interaction.response.send_message(
                f"⚠️ {member.mention} doesn't have the **Host** role. Select someone with the Host role.",
                ephemeral=True,
            )
            return

        # Open the scheduling modal with the chosen host pre-loaded
        await interaction.response.send_modal(_OfficialMeetScheduleModal(host_id=member.id))


class _OfficialMeetScheduleModal(discord.ui.Modal, title="🏁 Schedule Official Meet"):
    theme_field = discord.ui.TextInput(
        label="Meet Theme",
        placeholder="e.g. Tire Lettering / JDM Night / Stanced Only",
        required=True,
        max_length=100,
    )
    datetime_field = discord.ui.TextInput(
        label="Date & Time",
        placeholder="e.g. April 5 9:00 PM EST  or  04/05 9PM CST",
        required=True,
        max_length=80,
    )
    notes_field = discord.ui.TextInput(
        label="Meet Notes (optional)",
        placeholder="e.g. LOWERED CARS ONLY • Send photos to host before joining",
        style=discord.TextStyle.paragraph,
        required=False,
        max_length=500,
    )

    def __init__(self, host_id: int):
        super().__init__()
        self._selected_host_id = host_id

    async def on_submit(self, interaction: discord.Interaction):
        guild = interaction.guild
        if not guild:
            await interaction.response.send_message("Server only.", ephemeral=True)
            return

        host_id = self._selected_host_id
        host_member = guild.get_member(host_id)
        if not host_member:
            try:
                host_member = await guild.fetch_member(host_id)
            except Exception:
                await interaction.response.send_message(
                    "That user wasn't found in the server.", ephemeral=True
                )
                return

        meet_ts = _om_parse_combined_datetime(self.datetime_field.value)
        if meet_ts is None:
            await interaction.response.send_message(
                "❌ Couldn't read that date/time. Try:\n"
                "• `April 5 9:00 PM EST`\n"
                "• `04/05 9PM CST`\n"
                "• `2026-04-05 21:00 UTC`",
                ephemeral=True,
            )
            return
        if meet_ts <= int(datetime.now(timezone.utc).timestamp()):
            await interaction.response.send_message("That date/time is already in the past.", ephemeral=True)
            return

        channel = bot.get_channel(_OFFICIAL_MEET_CHANNEL_ID)
        if not isinstance(channel, discord.TextChannel):
            await interaction.response.send_message("Meet channel not found.", ephemeral=True)
            return

        notes = self.notes_field.value.strip() if self.notes_field.value else ""
        await interaction.response.defer(ephemeral=True)
        try:
            sent = await channel.send(
                content=f"<@&{PS5_ROLE_ID}> <@&{NOTIFY_ROLE_ID}>",
                embed=_om_build_embed(
                    theme=self.theme_field.value.strip(),
                    host=host_member,
                    timestamp=meet_ts,
                    notes=notes,
                ),
                view=_OfficialMeetRSVPView(),
                allowed_mentions=discord.AllowedMentions(roles=True, users=True),
            )
        except discord.Forbidden:
            await interaction.followup.send("Missing permissions to post in the meet channel.", ephemeral=True)
            return
        except Exception as _e:
            await interaction.followup.send(f"❌ Failed to post meet: {_e}", ephemeral=True)
            return

        record = _OmRecord(
            message_id=sent.id,
            channel_id=channel.id,
            host_id=host_member.id,
            theme=self.theme_field.value.strip(),
            timestamp=meet_ts,
        )
        _om_upsert_record(record)
        _om_schedule_reminders(record)
        await interaction.followup.send(
            f"Official meet posted for <t:{meet_ts}:F>.", ephemeral=True
        )
        try:
            await _om_panel_post_or_refresh(guild, force_repost=True)
        except Exception:
            pass


class _OfficialMeetPanelView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=None)

    @discord.ui.button(label="📋 Schedule Official Meet", style=discord.ButtonStyle.primary, custom_id="diff_om_panel:schedule")
    async def schedule_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        member = interaction.user
        if not isinstance(member, discord.Member):
            await interaction.response.send_message("Server only.", ephemeral=True)
            return
        is_staff = member.guild_permissions.manage_guild or any(r.id in _JOIN_STAFF_ROLE_IDS for r in member.roles)
        if not is_staff:
            await interaction.response.send_message("Only staff can schedule official meets.", ephemeral=True)
            return
        embed = discord.Embed(
            title="🎙️ Select Meet Host",
            description=(
                "Use the dropdown below to select the host for this meet.\n"
                "Only members with the **Host** role can be chosen."
            ),
            color=discord.Color.dark_gold(),
        )
        embed.set_footer(text="DIFF Official Meet System • Step 1 of 2")
        await interaction.response.send_message(embed=embed, view=_HostPickerView(), ephemeral=True)


async def _om_panel_post_or_refresh(guild: discord.Guild, force_repost: bool = False):
    """Post or refresh the Official Meet panel.

    force_repost=False (startup): edit existing in place, or create if missing.
    force_repost=True  (after new meet posted): delete old panel, send fresh one at
                        the bottom of the channel so it's always visible.
    """
    channel = guild.get_channel(_OFFICIAL_MEET_CHANNEL_ID)
    if not isinstance(channel, discord.TextChannel):
        try:
            channel = await guild.fetch_channel(_OFFICIAL_MEET_CHANNEL_ID)
        except Exception:
            return
    if not isinstance(channel, discord.TextChannel):
        return

    data = _om_panel_load()
    msg_id = data.get(str(guild.id))

    if force_repost:
        if msg_id:
            try:
                old = await channel.fetch_message(int(msg_id))
                await old.delete()
            except Exception:
                pass
        msg = await channel.send(
            embed=_om_panel_build_embed(),
            view=_OfficialMeetPanelView(),
        )
        data[str(guild.id)] = msg.id
        _om_panel_save(data)
        return

    if msg_id:
        try:
            msg = await channel.fetch_message(int(msg_id))
            await msg.edit(embed=_om_panel_build_embed(), view=_OfficialMeetPanelView())
            return
        except discord.NotFound:
            pass
        except Exception:
            return

    # Saved ID missing or deleted — scan history for existing panel before posting new
    try:
        async for hist_msg in channel.history(limit=150):
            if hist_msg.author.id == guild.me.id and hist_msg.embeds:
                footer = hist_msg.embeds[0].footer.text if hist_msg.embeds[0].footer else ""
                if footer == "DIFF Official Meet System":
                    data[str(guild.id)] = hist_msg.id
                    _om_panel_save(data)
                    await hist_msg.edit(embed=_om_panel_build_embed(), view=_OfficialMeetPanelView())
                    return
    except Exception:
        pass

    msg = await channel.send(embed=_om_panel_build_embed(), view=_OfficialMeetPanelView())
    data[str(guild.id)] = msg.id
    _om_panel_save(data)


@bot.command(name="postofficialmeetpanel")
async def _cmd_postofficialmeetpanel(ctx: commands.Context):
    is_auth = (
        ctx.author.guild_permissions.administrator
        or (ctx.guild and ctx.guild.owner_id == ctx.author.id)
        or any(r.id in _JOIN_STAFF_ROLE_IDS for r in getattr(ctx.author, "roles", []))
    )
    if not is_auth:
        await ctx.send("Staff only.", delete_after=6)
        return
    try:
        await ctx.message.delete()
    except Exception:
        pass
    await _om_panel_post_or_refresh(ctx.guild)


