# POP-UP MEET SYSTEM
# =========================

_POPUP_PANEL_CHANNEL_ID = 1484768466023223418
_POPUP_DB_FILE = os.path.join(DATA_FOLDER, "diff_popup_meets.db")


class _PopupDB:
    def __init__(self):
        self.conn = sqlite3.connect(_POPUP_DB_FILE)
        self.conn.row_factory = sqlite3.Row
        self._setup()

    def _setup(self):
        cur = self.conn.cursor()
        cur.execute("""
            CREATE TABLE IF NOT EXISTS popup_meets (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                guild_id INTEGER NOT NULL,
                host_user_id INTEGER NOT NULL,
                theme TEXT,
                location TEXT NOT NULL,
                time_text TEXT NOT NULL,
                extra_notes TEXT,
                ping_playstation INTEGER NOT NULL DEFAULT 0,
                ping_carmeet INTEGER NOT NULL DEFAULT 0,
                created_at TEXT NOT NULL
            )
        """)
        cur.execute("""
            CREATE TABLE IF NOT EXISTS panel_state (
                guild_id INTEGER NOT NULL,
                panel_name TEXT NOT NULL,
                channel_id INTEGER NOT NULL,
                message_id INTEGER NOT NULL,
                PRIMARY KEY (guild_id, panel_name)
            )
        """)
        cur.execute("""
            CREATE TABLE IF NOT EXISTS popup_rsvps (
                guild_id INTEGER NOT NULL,
                meet_id INTEGER NOT NULL,
                user_id INTEGER NOT NULL,
                status TEXT NOT NULL DEFAULT 'pullup',
                updated_at TEXT NOT NULL,
                PRIMARY KEY (guild_id, meet_id, user_id)
            )
        """)
        # Non-destructive column migrations for existing installs
        for col, defn in (
            ("message_id",         "INTEGER"),
            ("is_ended",           "INTEGER NOT NULL DEFAULT 0"),
            ("host_display_name",  "TEXT"),
            ("host_avatar_url",    "TEXT"),
        ):
            try:
                cur.execute(f"ALTER TABLE popup_meets ADD COLUMN {col} {defn}")
            except Exception:
                pass
        self.conn.commit()

    def add_meet(self, guild_id, host_id, theme, location, time_text, extra_notes,
                 ping_ps, ping_cm, host_display_name: str = "", host_avatar_url: str = "") -> int:
        cur = self.conn.cursor()
        cur.execute("""
            INSERT INTO popup_meets (guild_id, host_user_id, theme, location, time_text, extra_notes,
                ping_playstation, ping_carmeet, created_at, host_display_name, host_avatar_url)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """, (guild_id, host_id, theme, location, time_text, extra_notes,
              1 if ping_ps else 0, 1 if ping_cm else 0,
              datetime.now(timezone.utc).isoformat(), host_display_name, host_avatar_url))
        self.conn.commit()
        return int(cur.lastrowid)

    def set_message_id(self, meet_id: int, message_id: int) -> None:
        self.conn.execute("UPDATE popup_meets SET message_id=? WHERE id=?", (message_id, meet_id))
        self.conn.commit()

    def end_meet(self, meet_id: int) -> None:
        self.conn.execute("UPDATE popup_meets SET is_ended=1 WHERE id=?", (meet_id,))
        self.conn.commit()

    def get_meet(self, meet_id: int):
        return self.conn.execute("SELECT * FROM popup_meets WHERE id=?", (meet_id,)).fetchone()

    def get_active_meets(self, guild_id: int):
        """Returns active (non-ended) meets that have a message_id stored."""
        return self.conn.execute(
            "SELECT * FROM popup_meets WHERE guild_id=? AND is_ended=0 AND message_id IS NOT NULL",
            (guild_id,)
        ).fetchall()

    # ── RSVP helpers ──────────────────────────────────────────────────────────

    def set_rsvp(self, guild_id: int, meet_id: int, user_id: int, status: str) -> str | None:
        """Upsert RSVP; returns previous status or None."""
        cur = self.conn.cursor()
        prev = cur.execute(
            "SELECT status FROM popup_rsvps WHERE guild_id=? AND meet_id=? AND user_id=?",
            (guild_id, meet_id, user_id),
        ).fetchone()
        previous = prev[0] if prev else None
        cur.execute("""
            INSERT INTO popup_rsvps (guild_id, meet_id, user_id, status, updated_at)
            VALUES (?, ?, ?, ?, ?)
            ON CONFLICT(guild_id, meet_id, user_id)
            DO UPDATE SET status=excluded.status, updated_at=excluded.updated_at
        """, (guild_id, meet_id, user_id, status, datetime.now(timezone.utc).isoformat()))
        self.conn.commit()
        return previous

    def remove_rsvp(self, guild_id: int, meet_id: int, user_id: int) -> None:
        self.conn.execute(
            "DELETE FROM popup_rsvps WHERE guild_id=? AND meet_id=? AND user_id=?",
            (guild_id, meet_id, user_id),
        )
        self.conn.commit()

    def get_user_rsvp(self, guild_id: int, meet_id: int, user_id: int) -> str | None:
        row = self.conn.execute(
            "SELECT status FROM popup_rsvps WHERE guild_id=? AND meet_id=? AND user_id=?",
            (guild_id, meet_id, user_id),
        ).fetchone()
        return row[0] if row else None

    def get_rsvp_counts(self, guild_id: int, meet_id: int) -> dict:
        counts = {"pullup": 0, "cantmake": 0}
        for row in self.conn.execute(
            "SELECT status, COUNT(*) FROM popup_rsvps WHERE guild_id=? AND meet_id=? GROUP BY status",
            (guild_id, meet_id),
        ):
            counts[row[0]] = row[1]
        return counts

    def save_panel(self, guild_id, channel_id, message_id):
        cur = self.conn.cursor()
        cur.execute("""
            INSERT INTO panel_state (guild_id, panel_name, channel_id, message_id)
            VALUES (?, 'popup', ?, ?)
            ON CONFLICT(guild_id, panel_name)
            DO UPDATE SET channel_id=excluded.channel_id, message_id=excluded.message_id
        """, (guild_id, channel_id, message_id))
        self.conn.commit()

    def get_panel(self, guild_id):
        cur = self.conn.cursor()
        cur.execute("SELECT channel_id, message_id FROM panel_state WHERE guild_id=? AND panel_name='popup'", (guild_id,))
        return cur.fetchone()


_popup_db = _PopupDB()

_POPUP_TZ_MAP = {
    "EST": "America/New_York", "EDT": "America/New_York", "ET": "America/New_York",
    "CST": "America/Chicago", "CDT": "America/Chicago", "CT": "America/Chicago",
    "MST": "America/Denver", "MDT": "America/Denver", "MT": "America/Denver",
    "PST": "America/Los_Angeles", "PDT": "America/Los_Angeles", "PT": "America/Los_Angeles",
    "UTC": "UTC", "GMT": "UTC",
}


def _popup_parse_time(raw: str) -> str:
    """Convert '8pm EST' / '8:30pm CST' / '20:00 ET' to a Discord timestamp string.
    Falls back to the original string if parsing fails."""
    import re
    from datetime import timedelta
    m = re.search(
        r'(\d{1,2})(?::(\d{2}))?\s*(am|pm)?\s*([A-Za-z]{2,4})?',
        raw.strip(), re.IGNORECASE
    )
    if not m:
        return raw
    hour = int(m.group(1))
    minute = int(m.group(2)) if m.group(2) else 0
    meridiem = m.group(3).lower() if m.group(3) else None
    tz_abbr = m.group(4).upper() if m.group(4) else "EST"
    tz_name = _POPUP_TZ_MAP.get(tz_abbr, "America/New_York")
    if meridiem == "pm" and hour != 12:
        hour += 12
    elif meridiem == "am" and hour == 12:
        hour = 0
    if hour > 23 or minute > 59:
        return raw
    try:
        tz = ZoneInfo(tz_name)
        now = datetime.now(tz)
        local_dt = now.replace(hour=hour, minute=minute, second=0, microsecond=0)
        if local_dt <= now:
            local_dt += timedelta(days=1)
        ts = int(local_dt.timestamp())
        return f"<t:{ts}:F> — <t:{ts}:R>"
    except Exception:
        return raw


_POPUP_STAFF_ROLES = _LEADERSHIP_ROLE_IDS


def _popup_build_meet_embed(
    theme: str,
    location: str,
    time_text: str,
    notes: str,
    meet_id: int,
    host_id: int,
    host_display_name: str,
    host_avatar_url: str | None,
    pullup_count: int = 0,
    cantmake_count: int = 0,
    is_ended: bool = False,
) -> discord.Embed:
    if is_ended:
        title = "🛑 DIFF Pop-Up Meet — Ended"
        color = discord.Color.from_rgb(231, 76, 60)
        attendance_line = f"**{pullup_count}** member{'s' if pullup_count != 1 else ''} pulled up"
        if cantmake_count:
            attendance_line += f"  •  {cantmake_count} couldn't make it"
        description = f"This meet has ended. Hosted by <@{host_id}>.\n{attendance_line}"
    else:
        title = "⚡ DIFF Pop-Up Meet — Live Now"
        color = discord.Color.from_rgb(255, 140, 0)
        description = f"A spontaneous meet is live — <@{host_id}> is hosting. Pull up!"

    embed = discord.Embed(
        title=title,
        color=color,
        description=description,
        timestamp=datetime.now(timezone.utc),
    )
    if host_avatar_url:
        embed.set_thumbnail(url=host_avatar_url)

    # Row 1: Theme + Location (2 columns, no spacer needed)
    embed.add_field(name="🎨 Theme",    value=theme or "Open Class", inline=True)
    embed.add_field(name="📍 Location", value=location,              inline=True)
    # Row 2: Time + Host + Pulling Up (3 columns)
    embed.add_field(name="🕒 Time",  value=time_text,         inline=True)
    embed.add_field(name="👤 Host",  value=f"<@{host_id}>",   inline=True)
    embed.add_field(
        name="🚗 Pulling Up",
        value=f"**{pullup_count}** confirmed" + (f"  •  {cantmake_count} can't make it" if cantmake_count else ""),
        inline=True,
    )
    if notes:
        embed.add_field(name="📝 Notes", value=notes, inline=False)

    if not is_ended:
        guide = _get_theme_guide(theme or "")
        if guide:
            _display_name, _accepted = guide
            embed.add_field(
                name=f"✅ Accepted Cars — {_display_name}",
                value=_accepted,
                inline=False,
            )

    footer = f"DIFF Pop-Up Meet #{meet_id}"
    if is_ended:
        footer += " • Ended"
    else:
        footer += " • Click below to RSVP"
    embed.set_footer(text=footer)
    return embed


# ── Pop-Up Meet RSVP buttons (Pi-compatible Button subclasses) ────────────────

class _PopupPullUpBtn(discord.ui.Button):
    def __init__(self, meet_id: int):
        super().__init__(
            label="🚗 Pulling Up!",
            style=discord.ButtonStyle.success,
            custom_id=f"diff_popup:{meet_id}:pullup",
            row=0,
        )
        self.meet_id = meet_id

    async def callback(self, interaction: discord.Interaction) -> None:
        if not interaction.guild or not isinstance(interaction.user, discord.Member):
            return await interaction.response.send_message("Server only.", ephemeral=True)
        meet = _popup_db.get_meet(self.meet_id)
        if not meet or meet["is_ended"]:
            return await interaction.response.send_message("This meet has already ended.", ephemeral=True)

        existing = _popup_db.get_user_rsvp(interaction.guild.id, self.meet_id, interaction.user.id)
        if existing == "pullup":
            _popup_db.remove_rsvp(interaction.guild.id, self.meet_id, interaction.user.id)
            reply = "Removed your RSVP — you're no longer listed as pulling up."
        else:
            _popup_db.set_rsvp(interaction.guild.id, self.meet_id, interaction.user.id, "pullup")
            reply = "🚗 You're pulling up! See you there."

        counts  = _popup_db.get_rsvp_counts(interaction.guild.id, self.meet_id)
        new_emb = _popup_build_meet_embed(
            meet["theme"] or "", meet["location"], meet["time_text"],
            meet["extra_notes"] or "", self.meet_id, meet["host_user_id"],
            meet["host_display_name"] or "", meet["host_avatar_url"],
            counts["pullup"], counts["cantmake"],
        )
        await interaction.response.edit_message(embed=new_emb)
        await interaction.followup.send(reply, ephemeral=True)


class _PopupCantMakeBtn(discord.ui.Button):
    def __init__(self, meet_id: int):
        super().__init__(
            label="❌ Can't Make It",
            style=discord.ButtonStyle.secondary,
            custom_id=f"diff_popup:{meet_id}:cantmake",
            row=0,
        )
        self.meet_id = meet_id

    async def callback(self, interaction: discord.Interaction) -> None:
        if not interaction.guild or not isinstance(interaction.user, discord.Member):
            return await interaction.response.send_message("Server only.", ephemeral=True)
        meet = _popup_db.get_meet(self.meet_id)
        if not meet or meet["is_ended"]:
            return await interaction.response.send_message("This meet has already ended.", ephemeral=True)

        existing = _popup_db.get_user_rsvp(interaction.guild.id, self.meet_id, interaction.user.id)
        if existing == "cantmake":
            _popup_db.remove_rsvp(interaction.guild.id, self.meet_id, interaction.user.id)
            reply = "Removed your response."
        else:
            _popup_db.set_rsvp(interaction.guild.id, self.meet_id, interaction.user.id, "cantmake")
            reply = "Got it — marked as can't make it."

        counts  = _popup_db.get_rsvp_counts(interaction.guild.id, self.meet_id)
        new_emb = _popup_build_meet_embed(
            meet["theme"] or "", meet["location"], meet["time_text"],
            meet["extra_notes"] or "", self.meet_id, meet["host_user_id"],
            meet["host_display_name"] or "", meet["host_avatar_url"],
            counts["pullup"], counts["cantmake"],
        )
        await interaction.response.edit_message(embed=new_emb)
        await interaction.followup.send(reply, ephemeral=True)


class _PopupEndMeetBtn(discord.ui.Button):
    def __init__(self, meet_id: int):
        super().__init__(
            label="🏁 End Meet",
            style=discord.ButtonStyle.danger,
            custom_id=f"diff_popup:{meet_id}:end",
            row=1,
        )
        self.meet_id = meet_id

    async def callback(self, interaction: discord.Interaction) -> None:
        if not interaction.guild or not isinstance(interaction.user, discord.Member):
            return await interaction.response.send_message("Server only.", ephemeral=True)
        meet = _popup_db.get_meet(self.meet_id)
        if not meet:
            return await interaction.response.send_message("Meet not found.", ephemeral=True)
        if meet["is_ended"]:
            return await interaction.response.send_message("Already ended.", ephemeral=True)

        is_host  = interaction.user.id == meet["host_user_id"]
        is_staff = interaction.user.guild_permissions.administrator or \
                   any(r.id in _POPUP_STAFF_ROLES for r in interaction.user.roles)
        if not (is_host or is_staff):
            return await interaction.response.send_message(
                "Only the host or staff can end this meet.", ephemeral=True
            )

        _popup_db.end_meet(self.meet_id)
        counts  = _popup_db.get_rsvp_counts(interaction.guild.id, self.meet_id)
        end_emb = _popup_build_meet_embed(
            meet["theme"] or "", meet["location"], meet["time_text"],
            meet["extra_notes"] or "", self.meet_id, meet["host_user_id"],
            meet["host_display_name"] or "", meet["host_avatar_url"],
            counts["pullup"], counts["cantmake"], is_ended=True,
        )
        await interaction.response.edit_message(embed=end_emb, view=None)


class _PopupMeetView(discord.ui.View):
    """Persistent per-meet RSVP view.  meet_id is encoded in each button's custom_id."""
    def __init__(self, meet_id: int):
        super().__init__(timeout=None)
        self.add_item(_PopupPullUpBtn(meet_id))
        self.add_item(_PopupCantMakeBtn(meet_id))
        self.add_item(_PopupEndMeetBtn(meet_id))


class _PopupMeetModal(discord.ui.Modal, title="⚡ Create Pop-Up Meet"):
    theme_field = discord.ui.TextInput(
        label="Meet Theme (optional)",
        placeholder="e.g. JDM Night / Clean Euros / Under 1M  — leave blank for open theme",
        required=False,
        max_length=100,
    )
    location_field = discord.ui.TextInput(
        label="Location",
        placeholder="e.g. LS Car Meet / City / Sandy Shores",
        required=True,
        max_length=100,
    )
    time_field = discord.ui.TextInput(
        label="Time",
        placeholder="e.g. 8pm EST  or  8:30pm CST  or  Now",
        required=True,
        max_length=300,
    )
    notes_field = discord.ui.TextInput(
        label="Meet Notes (optional)",
        style=discord.TextStyle.paragraph,
        placeholder="e.g. Clean builds only / first come first served / lowered cars only",
        required=False,
        max_length=500,
    )
    ping_field = discord.ui.TextInput(
        label="Who to Notify",
        placeholder="both  |  ps5  |  carmeet  |  none",
        required=True,
        max_length=30,
    )

    async def on_submit(self, interaction: discord.Interaction):
        guild = interaction.guild
        user = interaction.user
        if guild is None or not isinstance(user, discord.Member):
            await interaction.response.send_message("This can only be used inside the server.", ephemeral=True)
            return
        host_role = guild.get_role(HOST_ROLE_ID)
        if not user.guild_permissions.administrator and (not host_role or host_role not in user.roles):
            await interaction.response.send_message("Only users with the Host role can create pop-up meets.", ephemeral=True)
            return
        panel_ch = guild.get_channel(_POPUP_PANEL_CHANNEL_ID)
        if not isinstance(panel_ch, discord.TextChannel):
            await interaction.response.send_message("Pop-up meet channel not found.", ephemeral=True)
            return

        raw_ping = self.ping_field.value.strip().lower()
        ping_ps = any(w in raw_ping for w in ("playstation", "ps5", "ps", "both", "all"))
        ping_cm = any(w in raw_ping for w in ("carmeet", "car meet", "car", "both", "all", "notify"))

        theme = self.theme_field.value.strip()
        location = self.location_field.value.strip()
        time_text = _popup_parse_time(self.time_field.value.strip())
        notes = self.notes_field.value.strip()

        avatar_url = str(user.display_avatar.url)
        meet_id = _popup_db.add_meet(
            guild.id, user.id, theme, location, time_text, notes, ping_ps, ping_cm,
            host_display_name=user.display_name,
            host_avatar_url=avatar_url,
        )

        ping_parts = []
        if ping_ps:
            r = guild.get_role(PS5_ROLE_ID)
            ping_parts.append(r.mention if r else "@PlayStation")
        if ping_cm:
            r = guild.get_role(NOTIFY_ROLE_ID)
            ping_parts.append(r.mention if r else "@CarMeet")
        ping_text = " ".join(ping_parts) or None

        meet_view = _PopupMeetView(meet_id)
        bot.add_view(meet_view)   # register immediately so buttons work after restart

        embed = _popup_build_meet_embed(
            theme, location, time_text, notes, meet_id,
            user.id, user.display_name, avatar_url,
            pullup_count=0, cantmake_count=0,
        )

        meet_msg = await panel_ch.send(
            content=ping_text,
            embed=embed,
            view=meet_view,
            allowed_mentions=discord.AllowedMentions(roles=True, users=False),
        )
        _popup_db.set_message_id(meet_id, meet_msg.id)

        log_ch = guild.get_channel(STAFF_LOGS_CHANNEL_ID)
        if isinstance(log_ch, discord.TextChannel):
            log_embed = discord.Embed(
                title="📋 Pop-Up Meet Created",
                color=discord.Color.green(),
                timestamp=datetime.now(timezone.utc),
                description=f"{user.mention} created a new pop-up meet.",
            )
            log_embed.add_field(name="Meet ID",   value=str(meet_id),       inline=True)
            log_embed.add_field(name="Location",  value=location,           inline=True)
            log_embed.add_field(name="Theme",     value=theme or "Open Class", inline=True)
            try:
                await log_ch.send(embed=log_embed)
            except Exception:
                pass

        await interaction.response.send_message(
            f"✅ Pop-up meet #{meet_id} posted! Members can now click **🚗 Pulling Up!** to RSVP.",
            ephemeral=True,
        )


class _PopupCreateBtn(discord.ui.Button):
    def __init__(self):
        super().__init__(
            label="⚡ Create Pop-Up Meet",
            style=discord.ButtonStyle.success,
            custom_id="diff_popup:create",
        )

    async def callback(self, interaction: discord.Interaction) -> None:
        user = interaction.user
        if not isinstance(user, discord.Member):
            return await interaction.response.send_message("Server only.", ephemeral=True)
        host_role = interaction.guild.get_role(HOST_ROLE_ID) if interaction.guild else None
        if not user.guild_permissions.administrator and (not host_role or host_role not in user.roles):
            return await interaction.response.send_message(
                "Only users with the **Host** role can create pop-up meets.", ephemeral=True
            )
        await interaction.response.send_modal(_PopupMeetModal())


class _PopupMeetPanelView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=None)
        self.add_item(_PopupCreateBtn())


def _popup_build_panel_embed() -> discord.Embed:
    embed = discord.Embed(
        title="⚡ DIFF Pop-Up Meets Hub",
        description="Spontaneous meets hosted by approved DIFF hosts throughout the week.",
        color=discord.Color.blue(),
    )
    embed.set_thumbnail(url=DIFF_LOGO_URL)
    embed.add_field(
        name="🚗 What Are Pop-Up Meets?",
        value="Quick, unscheduled meets that go live without advance notice — pull up fast when one drops.",
        inline=False,
    )
    embed.add_field(
        name="📋 How It Works",
        value=(
            "• Host clicks **Create Pop-Up Meet** below\n"
            "• Fills out theme, location, and time\n"
            "• Bot posts the meet card with role pings\n"
            "• Members see it and join fast"
        ),
        inline=False,
    )
    embed.add_field(
        name="⚠️ Rules",
        value=(
            "• Clean, realistic builds only\n"
            "• No crashing or griefing\n"
            "• Follow host instructions\n"
            "• Be ready to join when you RSVP"
        ),
        inline=False,
    )
    embed.add_field(
        name="🔒 Access",
        value="Only users with the **Host** role can create pop-up meets.",
        inline=False,
    )
    embed.set_footer(text="DIFF Pop-Up Meet System")
    embed.timestamp = datetime.now(timezone.utc)
    return embed


async def _popup_post_or_refresh(guild: discord.Guild):
    channel = guild.get_channel(_POPUP_PANEL_CHANNEL_ID)
    if not isinstance(channel, discord.TextChannel):
        return
    row = _popup_db.get_panel(guild.id)
    if row:
        try:
            msg = await channel.fetch_message(row["message_id"])
            await msg.edit(embed=_popup_build_panel_embed(), view=_PopupMeetPanelView())
            return
        except discord.NotFound:
            pass
        except Exception:
            return
    msg = await channel.send(embed=_popup_build_panel_embed(), view=_PopupMeetPanelView())
    _popup_db.save_panel(guild.id, channel.id, msg.id)


@bot.command(name="postpopuppanel")
async def _cmd_postpopuppanel(ctx: commands.Context):
    is_owner = ctx.guild and ctx.guild.owner_id == ctx.author.id
    is_admin = ctx.author.guild_permissions.administrator
    is_staff = any(r.id in _JOIN_STAFF_ROLE_IDS for r in getattr(ctx.author, "roles", []))
    if not (is_owner or is_admin or is_staff):
        await ctx.send("You need a staff role to use this command.", delete_after=8)
        return
    try:
        await ctx.message.delete()
    except Exception:
        pass
    await _popup_post_or_refresh(ctx.guild)


# =========================
# ROTATING BOT STATUS
# =========================
_presence_index = 0

def _status_next_meet_label() -> str | None:
    """Return a short 'Next Meet: Day • Time' string from the schedule, or None."""
    try:
        schedule = _asched_load()
        from zoneinfo import ZoneInfo as _ZI
        now = datetime.now(_ZI("America/New_York"))
        best_ts  = None
        best_lbl = None
        for day_key, slot in schedule.get("days", {}).items():
            if not slot.get("host_id"):
                continue
            day_val  = slot.get("day", "")
            time_val = slot.get("time", "")
            if not day_val or not time_val:
                continue
            ts = _parse_meet_ts(day_val, time_val)
            if ts and ts > now.timestamp():
                if best_ts is None or ts < best_ts:
                    best_ts  = ts
                    best_lbl = f"Next Meet: {day_val} • {time_val}"
        return best_lbl
    except Exception:
        return None

async def __rotating_presence_loop_logic():
    global _presence_index
    guild        = bot.get_guild(GUILD_ID)
    member_count = guild.member_count if guild else 0
    next_meet    = _status_next_meet_label()

    activities = [
        discord.Streaming(
            name="🏁 DIFF Car Meets | PS5 GTA V",
            url="https://www.twitch.tv/directory/game/Grand%20Theft%20Auto%20V",
        ),
        discord.Activity(type=discord.ActivityType.watching,  name=f"over {member_count:,} members"),
        discord.Activity(type=discord.ActivityType.competing, name="DIFF Host Meets"),
        discord.Activity(type=discord.ActivityType.listening, name="the DIFF community"),
        discord.Activity(type=discord.ActivityType.watching,  name="🚗 Host Flow • Crew Management"),
    ]

    # inject next meet as its own slide if data is available
    if next_meet:
        activities.insert(2, discord.Activity(
            type=discord.ActivityType.playing,
            name=f"📅 {next_meet}",
        ))

    activity = activities[_presence_index % len(activities)]
    _presence_index += 1
    try:
        await bot.change_presence(status=discord.Status.online, activity=activity)
    except Exception:
        pass

@tasks.loop(seconds=45)
async def _rotating_presence_loop():
    _loop_success('_rotating_presence_loop')
    try:
        await run_with_timeout('_rotating_presence_loop', __rotating_presence_loop_logic(), timeout=30)
    except Exception as _lte:
        await _handle_loop_error('_rotating_presence_loop', _lte, _rotating_presence_loop)
@_rotating_presence_loop.error
async def __rotating_presence_loop_on_error(error: Exception) -> None:
    await _handle_loop_error('_rotating_presence_loop', error, _rotating_presence_loop)
# =========================
# JOIN TICKET AUTO-BUMP (escalating: 2h → 6h → 24h → 72h auto-close)
# =========================

async def __join_auto_bump_loop_logic():
    """Escalating staff pings after photos submitted with no decision: 2h / 6h / 24h / 72h auto-close."""
    try:
        guild = bot.get_guild(GUILD_ID)
        if not guild:
            return
        category = guild.get_channel(JOIN_TICKET_CATEGORY_ID)
        if not isinstance(category, discord.CategoryChannel):
            return
        extra = _join_extra_load()
        changed = False
        now_utc = datetime.now(timezone.utc)
        ts_role  = guild.get_role(TICKET_SUPPORT_ROLE_ID)
        mgr_role = guild.get_role(MANAGER_ROLE_ID)
        lead     = guild.get_role(LEADER_ROLE_ID)
        co       = guild.get_role(CO_LEADER_ROLE_ID)
        for ch in category.text_channels:
            topic = ch.topic or ""
            if "JOIN_USER:" not in topic:
                continue
            ch_key = str(ch.id)
            entry = extra.get(ch_key, {})
            # Backward-compat: old bump_sent=True means already reached level 3
            if entry.get("bump_sent") and "bump_level" not in entry:
                entry["bump_level"] = 3
            bump_level = entry.get("bump_level", 0)
            if bump_level >= 4:
                extra[ch_key] = entry
                continue
            photos_ts = entry.get("photos_complete_at")
            if not photos_ts:
                extra[ch_key] = entry
                continue
            try:
                complete_at = datetime.fromisoformat(photos_ts)
                if complete_at.tzinfo is None:
                    complete_at = complete_at.replace(tzinfo=timezone.utc)
            except Exception:
                continue
            hours = (now_utc - complete_at).total_seconds() / 3600

            if bump_level < 1 and hours >= 2:
                # Level 1 — 2h: ping Ticket Support in ticket
                ts_mention = ts_role.mention if ts_role else ""
                emb = discord.Embed(
                    title="⏰ Review Needed — 2h",
                    description=(
                        "All required photos have been submitted for **over 2 hours** "
                        "with no decision yet.\n\nPlease review this application."
                    ),
                    color=discord.Color.yellow(),
                    timestamp=now_utc,
                )
                emb.set_footer(text="Different Meets • Join Hub Auto-Bump")
                try:
                    await ch.send(
                        content=ts_mention or None,
                        embed=emb,
                        allowed_mentions=discord.AllowedMentions(roles=True),
                    )
                    entry["bump_level"] = 1
                    changed = True
                except Exception:
                    pass

            elif bump_level < 2 and hours >= 6:
                # Level 2 — 6h: ping Ticket Support + Server Operations
                mentions = " ".join(r.mention for r in [ts_role, mgr_role] if r)
                emb = discord.Embed(
                    title="⏰ Review Needed — 6h",
                    description=(
                        "This application has been waiting for a decision for **over 6 hours**.\n\n"
                        "Ticket Support and Server Operations — please review and action this ticket."
                    ),
                    color=discord.Color.orange(),
                    timestamp=now_utc,
                )
                emb.set_footer(text="Different Meets • Join Hub Auto-Bump")
                try:
                    await ch.send(
                        content=mentions or None,
                        embed=emb,
                        allowed_mentions=discord.AllowedMentions(roles=True),
                    )
                    entry["bump_level"] = 2
                    changed = True
                except Exception:
                    pass

            elif bump_level < 3 and hours >= 24:
                # Level 3 — 24h: ping Founder + Executive + Server Operations
                mentions = " ".join(r.mention for r in [lead, co, mgr_role] if r)
                emb = discord.Embed(
                    title="🚨 Application Still Unresolved — 24h",
                    description=(
                        "This join application has had all required photos for **over 24 hours** "
                        "with no accept or deny decision.\n\n"
                        "This needs to be resolved immediately."
                    ),
                    color=discord.Color.red(),
                    timestamp=now_utc,
                )
                emb.set_footer(text="Different Meets • Join Hub Auto-Bump")
                try:
                    await ch.send(
                        content=mentions or None,
                        embed=emb,
                        allowed_mentions=discord.AllowedMentions(roles=True),
                    )
                    entry["bump_level"] = 3
                    entry["bump_sent"] = True  # backward-compat flag
                    changed = True
                except Exception:
                    pass

            elif bump_level < 4 and hours >= 72:
                # Level 4 — 72h: auto-close ticket, DM applicant
                uid_raw = _join_parse_user_id(topic)
                applicant = guild.get_member(int(uid_raw)) if uid_raw and uid_raw.isdigit() else None
                if applicant:
                    try:
                        await safe_dm(
                            applicant,
                            "**DIFF Join Application Update**\n\n"
                            "Your join application ticket was automatically closed after **72 hours** "
                            "because our review team was unable to action it in time.\n\n"
                            "This is **not a rejection** — you are welcome to reapply when our team "
                            "is available. We apologise for the delay.",
                        )
                    except Exception:
                        pass
                try:
                    await ch.send(embed=discord.Embed(
                        title="🔒 Auto-Closed — 72h No Decision",
                        description=(
                            "This ticket has been automatically closed after **72 hours** "
                            "of staff inactivity. The applicant has been notified and may reapply."
                        ),
                        color=discord.Color.dark_grey(),
                        timestamp=now_utc,
                    ))
                except Exception:
                    pass
                try:
                    new_name = f"closed-{ch.name}"[:90]
                    await ch.edit(name=new_name)
                    await ch.set_permissions(guild.default_role, view_channel=False)
                    if applicant:
                        await ch.set_permissions(applicant, view_channel=False)
                except Exception:
                    pass
                entry["bump_level"] = 4
                entry["bump_sent"] = True
                changed = True

            extra[ch_key] = entry
        if changed:
            _join_extra_save(extra)
    except Exception as _e:
        print(f"[JoinAutoBump] Error: {_e}")

@tasks.loop(minutes=30)
async def _join_auto_bump_loop():
    _loop_success('_join_auto_bump_loop')
    try:
        await run_with_timeout('_join_auto_bump_loop', __join_auto_bump_loop_logic(), timeout=120)
    except Exception as _lte:
        await _handle_loop_error('_join_auto_bump_loop', _lte, _join_auto_bump_loop)
@_join_auto_bump_loop.error
async def __join_auto_bump_loop_on_error(error: Exception) -> None:
    await _handle_loop_error('_join_auto_bump_loop', error, _join_auto_bump_loop)

# =========================
# JOIN TICKET MICRO-BUMP (every 10 min after photos complete, until claimed)
# =========================

_JOIN_MICRO_BUMP_MAX = 12  # max pings before handing off to escalating system (~2h)

async def __join_micro_bump_logic():
    """Ping @Ticket Support every 10 min in-ticket after photos are complete, until someone claims the review."""
    try:
        guild = bot.get_guild(GUILD_ID)
        if not guild:
            return
        category = guild.get_channel(JOIN_TICKET_CATEGORY_ID)
        if not isinstance(category, discord.CategoryChannel):
            return
        ts_role = guild.get_role(TICKET_SUPPORT_ROLE_ID)
        extra = _join_extra_load()
        changed = False
        now_utc = datetime.now(timezone.utc)
        for ch in category.text_channels:
            topic = ch.topic or ""
            if "JOIN_USER:" not in topic:
                continue
            # Stop if already claimed or auto-closed
            if "join_claimed_by=" in topic:
                continue
            ch_key = str(ch.id)
            entry = extra.get(ch_key, {})
            if entry.get("bump_level", 0) >= 4:
                continue
            # Only fire after photos are complete
            if not entry.get("photos_complete_at"):
                continue
            # Stop after max pings — escalating system takes over
            micro_count = entry.get("micro_bump_count", 0)
            if micro_count >= _JOIN_MICRO_BUMP_MAX:
                continue
            # Rate-limit: at least 9 minutes since last micro ping (buffer for loop jitter)
            last_micro = entry.get("micro_last_ping")
            if last_micro:
                try:
                    last_dt = datetime.fromisoformat(last_micro)
                    if last_dt.tzinfo is None:
                        last_dt = last_dt.replace(tzinfo=timezone.utc)
                    if (now_utc - last_dt).total_seconds() < 540:
                        continue
                except Exception:
                    pass
            ts_mention = ts_role.mention if ts_role else ""
            emb = discord.Embed(
                title="🔔 Review Reminder",
                description=(
                    "All required photos have been submitted and this application is "
                    "**waiting for a decision**.\n\nClick **Claim Review** to take this ticket, then Accept or Deny."
                ),
                color=discord.Color.blurple(),
                timestamp=now_utc,
            )
            emb.set_footer(text=f"Different Meets • Reminder {micro_count + 1}/{_JOIN_MICRO_BUMP_MAX}")
            try:
                await ch.send(
                    content=ts_mention or None,
                    embed=emb,
                    allowed_mentions=discord.AllowedMentions(roles=True),
                )
                entry["micro_bump_count"] = micro_count + 1
                entry["micro_last_ping"] = now_utc.isoformat()
                extra[ch_key] = entry
                changed = True
            except Exception:
                pass
        if changed:
            _join_extra_save(extra)
    except Exception as _e:
        print(f"[JoinMicroBump] Error: {_e}")

@tasks.loop(minutes=10)
async def _join_micro_bump_loop():
    _loop_success("_join_micro_bump_loop")
    try:
        await run_with_timeout("_join_micro_bump_loop", __join_micro_bump_logic(), timeout=60)
    except Exception as _lte:
        await _handle_loop_error("_join_micro_bump_loop", _lte, _join_micro_bump_loop)
@_join_micro_bump_loop.error
async def __join_micro_bump_loop_on_error(error: Exception) -> None:
    await _handle_loop_error("_join_micro_bump_loop", error, _join_micro_bump_loop)
