# =========================
# ROLL CALL AUTO-ARCHIVE LOOP
# =========================
_rc_archive_last_ran: str = ""

async def _rc_auto_archive_loop() -> None:
    """Every Monday at 12:05 AM ET: post a final roll call summary for the week to staff logs."""
    await bot.wait_until_ready()
    global _rc_archive_last_ran
    while not bot.is_closed():
        await asyncio.sleep(60)
        try:
            now = datetime.now(_EST_TZ)
            # Monday (weekday 0), 12:05 AM
            if now.weekday() != 0 or now.hour != 0 or now.minute != 5:
                continue
            today_key = now.strftime("%Y-%m-%d")
            if _rc_archive_last_ran == today_key:
                continue
            _rc_archive_last_ran = today_key

            guild = bot.get_guild(GUILD_ID)
            if not guild:
                continue
            logs_ch = guild.get_channel(STAFF_LOGS_CHANNEL_ID)
            if not isinstance(logs_ch, discord.TextChannel):
                continue

            meets = _rc_db.get_meets(guild.id)
            responses = _rc_db.get_all_responses(guild.id)
            crew_role = guild.get_role(CREW_MEMBER_ROLE_ID)
            total_crew = len([m for m in crew_role.members if not m.bot]) if crew_role else 0

            embed = discord.Embed(
                title="📋 Weekly Roll Call Archive",
                description=f"Automatic end-of-week snapshot for **{now.strftime('%B %d, %Y')}**",
                color=discord.Color.blurple(),
                timestamp=now,
            )
            if not meets:
                embed.add_field(name="No meets this week", value="Roll call was not active.", inline=False)
            else:
                for meet_row in meets:
                    mn = meet_row["meet_number"]
                    meet_responses = responses.get(mn, {})
                    yes_ids  = meet_responses.get("yes",   [])
                    no_ids   = meet_responses.get("no",    [])
                    maybe_ids = meet_responses.get("maybe", [])
                    total_resp = len(yes_ids) + len(no_ids) + len(maybe_ids)
                    host_id = meet_row["host_id"]
                    host_mention = f"<@{host_id}>" if host_id else "Unassigned"
                    embed.add_field(
                        name=f"Meet {mn} — {meet_row['class_name'] or 'TBD'} ({meet_row['date_text'] or 'TBD'})",
                        value=(
                            f"Host: {host_mention}\n"
                            f"✅ Yes: **{len(yes_ids)}** · ❌ No: **{len(no_ids)}** · "
                            f"❓ Maybe: **{len(maybe_ids)}**\n"
                            f"Total responses: **{total_resp}** / {total_crew} crew"
                        ),
                        inline=False,
                    )
            embed.set_footer(text="Different Meets • Roll Call Auto-Archive")
            await logs_ch.send(embed=embed)
        except Exception as _e:
            print(f"[RollCall] Auto-archive error: {_e}")


# =========================
# ROLL CALL SATURDAY REMINDER LOOP
# =========================
_rc_saturday_reminder_last_ran: str = ""

async def _rc_saturday_reminder_loop() -> None:
    """Every Saturday at 12:00 PM ET: DM crew members who haven't responded to any meet."""
    await bot.wait_until_ready()
    global _rc_saturday_reminder_last_ran
    while not bot.is_closed():
        await asyncio.sleep(60)
        try:
            now = datetime.now(_EST_TZ)
            # Saturday (weekday 5), noon
            if now.weekday() != 5 or now.hour != 12 or now.minute != 0:
                continue
            today_key = now.strftime("%Y-%m-%d")
            if _rc_saturday_reminder_last_ran == today_key:
                continue
            _rc_saturday_reminder_last_ran = today_key

            guild = bot.get_guild(GUILD_ID)
            if not guild:
                continue
            meets = _rc_db.get_meets(guild.id)
            if not meets:
                continue
            responses = _rc_db.get_all_responses(guild.id)
            crew_role = guild.get_role(CREW_MEMBER_ROLE_ID)
            if not crew_role:
                continue

            # All user IDs who have responded to at least one meet
            responded: set = set()
            for mr in responses.values():
                for uid_list in mr.values():
                    responded.update(uid_list)

            pending = [m for m in crew_role.members if not m.bot and m.id not in responded]
            if not pending:
                continue

            rc_url = f"https://discord.com/channels/{GUILD_ID}/{ROLL_CALL_CHANNEL_ID}"
            dm_embed = discord.Embed(
                title="📋 Don't forget — Roll Call closes soon!",
                description=(
                    "Hey! You haven't responded to this week's **DIFF Meet roll call** yet.\n\n"
                    f"📌 **[Open the Roll Call]({rc_url})**\n\n"
                    "Let the crew know if you're coming — it takes 10 seconds.\n"
                    "The roll call resets every Monday."
                ),
                color=discord.Color.orange(),
                timestamp=now,
            )
            dm_embed.set_footer(text="DIFF Meets • Saturday Roll Call Reminder")

            sent = failed = 0
            for m in pending:
                try:
                    await m.send(embed=dm_embed)
                    sent += 1
                    await asyncio.sleep(1)
                except discord.Forbidden:
                    failed += 1
                except Exception as _de:
                    print(f"[RcReminder] DM to {m.id} failed: {_de}")
                    failed += 1

            print(f"[RcReminder] Saturday reminder — {sent} DMs sent, {failed} failed, {len(responded)} already responded.")
            if failed > 0:
                logs_ch = guild.get_channel(STAFF_LOGS_CHANNEL_ID)
                if isinstance(logs_ch, discord.TextChannel):
                    await logs_ch.send(embed=discord.Embed(
                        title="⚠️ Roll Call Reminder — DM Failures",
                        description=f"**{failed}** crew member(s) couldn't be DM'd for the Saturday roll call reminder.\n\n✅ Sent: {sent} · ❌ Failed: {failed}",
                        color=discord.Color.orange(),
                        timestamp=now,
                    ).set_footer(text="DIFF Meets • Roll Call Reminder System"))
        except Exception as _e:
            print(f"[RcReminder] Loop error: {_e}")


# =========================
# CREW ATTENDANCE PRUNING REPORT LOOP
# =========================
_rc_pruning_report_last_ran: str = ""

async def _rc_pruning_report_loop() -> None:
    """Every Monday at 12:15 AM ET: post a pruning report of crew with zero yes responses this week."""
    await bot.wait_until_ready()
    global _rc_pruning_report_last_ran
    while not bot.is_closed():
        await asyncio.sleep(60)
        try:
            now = datetime.now(_EST_TZ)
            # Monday (weekday 0), 12:15 AM
            if now.weekday() != 0 or now.hour != 0 or now.minute != 15:
                continue
            today_key = now.strftime("%Y-%m-%d")
            if _rc_pruning_report_last_ran == today_key:
                continue
            _rc_pruning_report_last_ran = today_key

            guild = bot.get_guild(GUILD_ID)
            if not guild:
                continue
            logs_ch = guild.get_channel(STAFF_LOGS_CHANNEL_ID)
            if not isinstance(logs_ch, discord.TextChannel):
                continue

            crew_role = guild.get_role(CREW_MEMBER_ROLE_ID)
            if not crew_role:
                continue

            crew_members = [m for m in crew_role.members if not m.bot]
            responses = _rc_db.get_all_responses(guild.id)

            # Build per-member response map for this week
            yes_responders:  set = set()
            any_responders:  set = set()
            no_only: list = []

            for mr in responses.values():
                yes_responders.update(mr.get("yes", []))
                for uid_list in mr.values():
                    any_responders.update(uid_list)

            no_response = [m for m in crew_members if m.id not in any_responders]
            no_only_members = [m for m in crew_members if m.id in any_responders and m.id not in yes_responders]

            embed = discord.Embed(
                title="🔍 Weekly Crew Attendance Pruning Report",
                description=f"Week ending **{now.strftime('%B %d, %Y')}** — {len(crew_members)} total crew",
                color=discord.Color.red(),
                timestamp=now,
            )

            if no_response:
                sample = " ".join(m.mention for m in no_response[:20])
                suffix = f" + {len(no_response) - 20} more" if len(no_response) > 20 else ""
                embed.add_field(
                    name=f"⬜ No Response At All ({len(no_response)})",
                    value=sample + suffix,
                    inline=False,
                )
            else:
                embed.add_field(name="⬜ No Response At All", value="Everyone responded this week ✅", inline=False)

            if no_only_members:
                sample2 = " ".join(m.mention for m in no_only_members[:20])
                suffix2 = f" + {len(no_only_members) - 20} more" if len(no_only_members) > 20 else ""
                embed.add_field(
                    name=f"❌ Responded 'No' to All Meets ({len(no_only_members)})",
                    value=sample2 + suffix2,
                    inline=False,
                )

            embed.add_field(
                name="📊 Summary",
                value=(
                    f"✅ Responded yes to ≥1 meet: **{len(yes_responders)}**\n"
                    f"❌ All no / maybe: **{len(no_only_members)}**\n"
                    f"⬜ No response: **{len(no_response)}**"
                ),
                inline=False,
            )
            embed.set_footer(text="Different Meets • Crew Pruning Report")
            await logs_ch.send(embed=embed)
        except Exception as _e:
            print(f"[PruningReport] Loop error: {_e}")


# =========================
# HRSVP AUTO-RESET LOOP
# =========================
async def _hrsvp_auto_reset_loop() -> None:
    """Every 30 min: wipe RSVP panel on Monday midnight EST, ping @Meet Hosts.
    On startup, immediately catches up any missed Monday reset."""
    await bot.wait_until_ready()
    from zoneinfo import ZoneInfo as _ZI
    from datetime import timedelta as _td

    # ── Startup catch-up: reset if this week's Monday reset was missed ───────
    try:
        now_est = datetime.now(_ZI("America/New_York"))
        days_since_monday = now_est.weekday()            # 0=Mon … 6=Sun
        most_recent_monday = (now_est - _td(days=days_since_monday)).strftime("%Y-%m-%d")
        if _hrsvp_reset_ts_load() != most_recent_monday:
            _hrsvp_reset()
            _hrsvp_reset_ts_save(most_recent_monday)
            await _hrsvp_update_panel(bot)
            ch = bot.get_channel(HOST_RSVP_CHANNEL_ID)
            if isinstance(ch, discord.TextChannel):
                host_role = ch.guild.get_role(HOST_ROLE_ID) if ch.guild else None
                ping      = host_role.mention if host_role else "@Meet Hosts"
                await ch.send(
                    f"{ping} 📋 **New week — availability panel reset!**\n"
                    "Please mark your availability for Meet 1, Meet 2, and Meet 3 above. "
                    "Leadership builds the schedule from your responses."
                )
            print("[HRSVP] Startup catch-up reset applied.")
    except Exception as _e:
        print(f"[HRSVP] Startup catch-up error: {_e}")

    # ── Ongoing loop ─────────────────────────────────────────────────────────
    while not bot.is_closed():
        await asyncio.sleep(1800)
        try:
            now_est   = datetime.now(_ZI("America/New_York"))
            if now_est.weekday() == 0 and now_est.hour == 0:
                today_str = now_est.strftime("%Y-%m-%d")
                if _hrsvp_reset_ts_load() == today_str:
                    continue
                _hrsvp_reset()
                _hrsvp_reset_ts_save(today_str)
                await _hrsvp_update_panel(bot)
                ch = bot.get_channel(HOST_RSVP_CHANNEL_ID)
                if isinstance(ch, discord.TextChannel):
                    host_role = ch.guild.get_role(HOST_ROLE_ID) if ch.guild else None
                    ping      = host_role.mention if host_role else "@Meet Hosts"
                    await ch.send(
                        f"{ping} 📋 **New week — availability panel reset!**\n"
                        "Please mark your availability for Meet 1, Meet 2, and Meet 3 above. "
                        "Leadership builds the schedule from your responses."
                    )
        except Exception as _e:
            print(f"[HRSVP AutoReset] {_e}")


# =========================
# HRSVP ESCALATION LOOP
# =========================
_HRSVP_ESCALATED: set = set()   # tracks which slots have already been alerted this week


async def _hrsvp_escalation_loop() -> None:
    """Every 6 h: if a meet slot is ≤3 days away with no host, alert #host-team."""
    await bot.wait_until_ready()
    while not bot.is_closed():
        await asyncio.sleep(21600)
        try:
            schedule = _asched_load()
            guild    = discord.utils.get(bot.guilds, id=GUILD_ID)
            if not guild:
                continue
            ch = bot.get_channel(_HOST_TEAM_CHANNEL_ID)
            if not isinstance(ch, discord.TextChannel):
                continue
            rsvp = _hrsvp_load()
            for day in _HRSVP_DAYS:
                entry = schedule["days"].get(day, {})
                if entry.get("host_id"):
                    _HRSVP_ESCALATED.discard(day)
                    continue
                ts = _parse_meet_ts(entry.get("day", ""), entry.get("time", ""))
                if not ts:
                    continue
                days_until = (ts - int(utc_now().timestamp())) / 86400
                if days_until <= 3 and day not in _HRSVP_ESCALATED:
                    _HRSVP_ESCALATED.add(day)
                    slot_data  = rsvp.get(day, {})
                    maybe_ents = slot_data.get("maybe", [])
                    maybe_tags = (
                        "  ".join(f"<@{_hrsvp_uid(e)}>" for e in maybe_ents[:4])
                        if maybe_ents else "*none*"
                    )
                    leader_role = guild.get_role(LEADER_ROLE_ID)
                    ping        = leader_role.mention if leader_role else "@Leadership"
                    await ch.send(
                        f"⚠️ {ping} **{day} has no confirmed host** and is "
                        f"**{int(days_until)} day(s)** away!\n"
                        f"❓ Maybe hosts: {maybe_tags}\n"
                        f"Override a slot in <#{HOST_RSVP_CHANNEL_ID}> using the "
                        f"**Override Slot** button."
                    )
        except Exception as _e:
            print(f"[HRSVP Escalation] {_e}")


# =========================
# APPLICATION TIMEOUT LOOP
# =========================
async def application_timeout_loop():
    await bot.wait_until_ready()
    while not bot.is_closed():
        try:
            app_data = load_apps()
            for app_id, record in app_data.get("applications", {}).items():
                if record.get("status") not in {"Pending", "More Info Requested"}:
                    continue
                submitted_at = record.get("submitted_at")
                if not submitted_at:
                    continue
                try:
                    submitted_dt = datetime.fromisoformat(submitted_at)
                except Exception:
                    continue
                if utc_now() - submitted_dt < timedelta(hours=GARAGE_TIMEOUT_HOURS):
                    continue
                guild = bot.get_guild(GUILD_ID)
                if not guild:
                    continue
                ticket_channel = guild.get_channel(record.get("ticket_channel_id")) if record.get("ticket_channel_id") else None
                photo_count = 0
                if isinstance(ticket_channel, discord.TextChannel):
                    messages = [m async for m in ticket_channel.history(limit=200)]
                    photo_count = count_message_attachments(messages)
                if photo_count >= MIN_GARAGE_PHOTOS:
                    continue
                update_app(
                    app_id,
                    status="Timed Out",
                    reviewed_at=utc_now().isoformat(),
                    decision_reason=f"Timed out before uploading the required {MIN_GARAGE_PHOTOS} garage photos.",
                    ticket_closed=True,
                    closed_at=utc_now().isoformat(),
                )
                applicant = guild.get_member(record["user_id"])
                if applicant:
                    await safe_dm(
                        applicant,
                        f"Your DIFF application **#{app_id}** timed out because the required **{MIN_GARAGE_PHOTOS}** garage photos "
                        f"were not uploaded within **{GARAGE_TIMEOUT_HOURS} hours**.",
                    )
                tracker_channel = guild.get_channel(APPLICATION_TRACKER_CHANNEL_ID)
                if isinstance(tracker_channel, discord.TextChannel) and record.get("tracker_message_id"):
                    try:
                        tracker_msg = await tracker_channel.fetch_message(record["tracker_message_id"])
                        tracker_embed = build_tracker_embed(
                            app_id,
                            applicant or guild.me,
                            record,
                            "Timed Out",
                            "System Auto Timeout",
                        )
                        await tracker_msg.edit(embed=tracker_embed)
                    except Exception:
                        pass
                if isinstance(ticket_channel, discord.TextChannel):
                    try:
                        await ticket_channel.send(embed=discord.Embed(
                            title="Application Timed Out",
                            description=(
                                f"This application timed out because at least **{MIN_GARAGE_PHOTOS}** garage photos "
                                f"were not uploaded within **{GARAGE_TIMEOUT_HOURS} hours**."
                            ),
                            color=discord.Color.dark_orange(),
                            timestamp=utc_now(),
                        ))
                    except Exception:
                        pass
                    try:
                        _tcn = ticket_channel.name
                        await ticket_channel.edit(name=_tcn if _tcn.startswith("closed-") else f"closed-{_tcn[:80]}")
                    except Exception:
                        pass
                    try:
                        await ticket_channel.set_permissions(guild.default_role, view_channel=False)
                    except Exception:
                        pass
                    if applicant:
                        try:
                            await ticket_channel.set_permissions(applicant, overwrite=None)
                        except Exception:
                            pass
        except Exception:
            pass
        await asyncio.sleep(600)


# =========================
_panel_refresh_task = None
_hierarchy_refresh_task = None


async def _auto_refresh_status_panel(guild: discord.Guild):
    await asyncio.sleep(15)
    channel_id = data.get("status_channel_id")
    if not channel_id:
        return
    channel = guild.get_channel(channel_id)
    if channel is None:
        return
    embed = build_status_embed(guild)
    msg_id = data.get("panel_message_id")
    target_message = None
    if msg_id:
        try:
            target_message = await channel.fetch_message(msg_id)
        except discord.NotFound:
            target_message = None
    if target_message is None:
        target_message = await find_existing_status_panel_message(channel)
    if target_message is not None:
        try:
            await target_message.edit(embed=embed)
        except Exception:
            pass


@bot.event
async def on_presence_update(before: discord.Member, after: discord.Member):
    global _panel_refresh_task, _hierarchy_refresh_task
    if after.guild.id != GUILD_ID:
        return
    if before.status == after.status and before.activity == after.activity:
        return
    if _panel_refresh_task is not None and not _panel_refresh_task.done():
        _panel_refresh_task.cancel()
    _panel_refresh_task = asyncio.ensure_future(_auto_refresh_status_panel(after.guild))
    if _hierarchy_refresh_task is not None and not _hierarchy_refresh_task.done():
        _hierarchy_refresh_task.cancel()
    _hierarchy_refresh_task = asyncio.ensure_future(_auto_refresh_hierarchy_panel(after.guild))


