class SupportCloseButton(discord.ui.View):
    def __init__(self) -> None:
        super().__init__(timeout=None)

    @discord.ui.button(label="Claim Ticket", emoji="🙋", style=discord.ButtonStyle.secondary, custom_id="diff_support_claim_ticket")
    async def claim_ticket(self, interaction: discord.Interaction, button: discord.ui.Button) -> None:
        if not isinstance(interaction.user, discord.Member):
            return
        is_staff = any(r.id in _LEADERSHIP_HOST_ROLE_IDS for r in interaction.user.roles)
        if not is_staff:
            return await interaction.response.send_message("Only staff can claim tickets.", ephemeral=True)
        channel = interaction.channel
        if not isinstance(channel, discord.TextChannel):
            return
        topic = channel.topic or ""
        if "ticket_claimed_by=" in topic:
            existing_claimer_id = _supp_parse_topic(topic, "ticket_claimed_by")
            return await interaction.response.send_message(
                f"This ticket has already been claimed by <@{existing_claimer_id}>.", ephemeral=True
            )
        try:
            await channel.edit(topic=topic + f" | ticket_claimed_by={interaction.user.id}")
        except Exception:
            pass
        _tperf_record_claim(interaction.user.id, channel.name)
        await interaction.response.send_message(
            f"🙋 {interaction.user.mention} has claimed this ticket and will be assisting shortly."
        )

    @discord.ui.button(label="Close Ticket", emoji="🔒", style=discord.ButtonStyle.danger, custom_id="diff_support_close_ticket")
    async def close_ticket(self, interaction: discord.Interaction, button: discord.ui.Button) -> None:
        if not interaction.guild or not isinstance(interaction.channel, discord.TextChannel):
            return await interaction.response.send_message("This can only be used in a ticket channel.", ephemeral=True)
        if not isinstance(interaction.user, discord.Member):
            return await interaction.response.send_message("Member check failed.", ephemeral=True)
        channel = interaction.channel
        member = interaction.user
        owner_id = _supp_parse_topic(channel.topic, "ticket_owner")
        is_owner = owner_id == str(member.id)
        is_staff = any(r.id in _LEADERSHIP_HOST_ROLE_IDS for r in member.roles)
        if not (is_owner or is_staff or member.guild_permissions.manage_channels):
            return await interaction.response.send_message("You do not have permission to close this ticket.", ephemeral=True)

        await interaction.response.send_message("🔒 Closing ticket and saving transcript...", ephemeral=True)
        await channel.send(
            embed=discord.Embed(
                description=f"🔒 This ticket is being closed by {member.mention}. The channel will be deleted shortly.",
                color=discord.Color.red(),
            )
        )

        ticket_key = _supp_parse_topic(channel.topic, "ticket_type") or "support"
        ticket = _TICKET_TYPES.get(ticket_key, _TICKET_TYPES["support"])
        claimer_id = _supp_parse_topic(channel.topic, "ticket_claimed_by")
        if claimer_id and claimer_id.isdigit():
            _tperf_record_close(int(claimer_id), channel.name)

        transcript_file = await _supp_export_transcript(channel)
        logs_channel = interaction.guild.get_channel(STAFF_LOGS_CHANNEL_ID)
        if isinstance(logs_channel, discord.TextChannel):
            from datetime import timezone as _tz
            now = datetime.now(_EST_TZ)

            color = _TICKET_COLORS.get(ticket.key, discord.Color.red())
            close_embed = discord.Embed(
                title=f"🔒 Ticket Closed — {ticket.label}",
                color=color,
                timestamp=now,
            )
            close_embed.add_field(name="📋 Type", value=ticket.label, inline=True)
            close_embed.add_field(name="🔒 Closed By", value=member.mention, inline=True)
            close_embed.add_field(name="⏰ Closed At", value=f"<t:{int(now.timestamp())}:F>", inline=True)
            if owner_id:
                close_embed.add_field(name="👤 Ticket Owner", value=f"<@{owner_id}>", inline=True)
            if claimer_id:
                close_embed.add_field(name="🙋 Claimed By", value=f"<@{claimer_id}>", inline=True)
            close_embed.add_field(name="📁 Channel", value=f"`{channel.name}`", inline=True)
            _supp_brand_embed(close_embed)
            try:
                await logs_channel.send(embed=close_embed)
            except discord.HTTPException:
                pass
        _transcript_url: str | None = None
        if transcript_file and interaction.guild:
            _transcript_url = await _post_transcript_to_channel(
                interaction.guild, transcript_file,
                channel.name, "Support Ticket",
            )

        if owner_id:
            try:
                owner = interaction.guild.get_member(int(owner_id))
                if owner:
                    dm_embed = discord.Embed(
                        title="🔒 Your Ticket Has Been Closed",
                        description=(
                            f"Your **{ticket.label}** ticket in **{interaction.guild.name}** has been closed.\n\n"
                            "Your full ticket transcript is available via the button below — you can open it in your browser to view the full conversation.\n\n"
                            "If you still need help, feel free to open a new ticket from the support panel."
                        ),
                        color=_TICKET_COLORS.get(ticket.key, discord.Color.red()),
                        timestamp=datetime.now(timezone.utc),
                    )
                    dm_embed.set_footer(text="Different Meets • Support System")
                    close_view = _TicketRatingView(channel_name=channel.name, ticket_type=ticket.label, transcript_url=_transcript_url)
                    try:
                        await owner.send(embed=dm_embed, view=close_view)
                    except Exception:
                        pass
            except Exception:
                pass

        await asyncio.sleep(2)
        try:
            await channel.delete(reason=f"Ticket closed by {member} ({member.id})")
        except discord.HTTPException:
            pass


class SupportApplicationReviewView(discord.ui.View):
    def __init__(self) -> None:
        super().__init__(timeout=None)

    async def _check(self, interaction: discord.Interaction) -> bool:
        if not interaction.guild or not isinstance(interaction.user, discord.Member):
            return False
        return any(r.id in _LEADERSHIP_ROLE_IDS for r in interaction.user.roles) \
               or interaction.user.guild_permissions.manage_guild

    @discord.ui.button(label="Accept", emoji="✅", style=discord.ButtonStyle.success, custom_id="diff_app_accept")
    async def accept_application(self, interaction: discord.Interaction, button: discord.ui.Button) -> None:
        if not await self._check(interaction):
            return await interaction.response.send_message("Only DIFF leadership can approve applications.", ephemeral=True)
        if not interaction.guild or not isinstance(interaction.channel, discord.TextChannel) or not isinstance(interaction.user, discord.Member):
            return await interaction.response.send_message("Server only.", ephemeral=True)
        applicant_id_raw = _supp_parse_topic(interaction.channel.topic, "ticket_owner")
        if not applicant_id_raw or not applicant_id_raw.isdigit():
            return await interaction.response.send_message("Could not detect the applicant from this ticket.", ephemeral=True)
        applicant = interaction.guild.get_member(int(applicant_id_raw))
        if applicant is None:
            return await interaction.response.send_message("The applicant is no longer in the server.", ephemeral=True)
        await interaction.response.send_message("Application approved.", ephemeral=True)
        role = interaction.guild.get_role(_SUPP_APPROVED_STAFF_ROLE_ID) if _SUPP_APPROVED_STAFF_ROLE_ID else None
        if role:
            try:
                await applicant.add_roles(role, reason=f"Application approved by {interaction.user}")
            except discord.HTTPException:
                pass
        embed = _supp_build_decision_embed(applicant, interaction.user, approved=True)
        await interaction.channel.send(embed=embed)
        logs_channel = interaction.guild.get_channel(STAFF_LOGS_CHANNEL_ID)
        if isinstance(logs_channel, discord.TextChannel):
            await logs_channel.send(embed=embed)
        for child in self.children:
            child.disabled = True
        try:
            await interaction.message.edit(view=self)
        except discord.HTTPException:
            pass

    @discord.ui.button(label="Deny", emoji="❌", style=discord.ButtonStyle.danger, custom_id="diff_app_deny")
    async def deny_application(self, interaction: discord.Interaction, button: discord.ui.Button) -> None:
        if not await self._check(interaction):
            return await interaction.response.send_message("Only DIFF leadership can deny applications.", ephemeral=True)
        if not interaction.guild or not isinstance(interaction.channel, discord.TextChannel) or not isinstance(interaction.user, discord.Member):
            return await interaction.response.send_message("Server only.", ephemeral=True)
        applicant_id_raw = _supp_parse_topic(interaction.channel.topic, "ticket_owner")
        if not applicant_id_raw or not applicant_id_raw.isdigit():
            return await interaction.response.send_message("Could not detect the applicant from this ticket.", ephemeral=True)
        applicant = interaction.guild.get_member(int(applicant_id_raw))
        if applicant is None:
            return await interaction.response.send_message("The applicant is no longer in the server.", ephemeral=True)
        embed = _supp_build_decision_embed(applicant, interaction.user, approved=False)
        await interaction.response.send_message("Application denied.", ephemeral=True)
        await interaction.channel.send(embed=embed)
        logs_channel = interaction.guild.get_channel(STAFF_LOGS_CHANNEL_ID)
        if isinstance(logs_channel, discord.TextChannel):
            await logs_channel.send(embed=embed)
        for child in self.children:
            child.disabled = True
        try:
            await interaction.message.edit(view=self)
        except discord.HTTPException:
            pass


async def _supp_auto_close_ticket(
    channel: discord.TextChannel,
    owner_id: int,
    ticket_label: str,
    reviewer: discord.Member,
    *,
    delay: int = 15,
) -> None:
    """Generate transcript, log it, DM owner, then delete the ticket channel after `delay` seconds."""
    from datetime import timezone as _tz
    guild = channel.guild

    # Generate transcript
    transcript = await _supp_export_transcript(channel)

    # Log to staff-logs
    logs_ch = guild.get_channel(STAFF_LOGS_CHANNEL_ID)
    if isinstance(logs_ch, discord.TextChannel):
        close_embed = discord.Embed(
            title=f"🔒 Appeal Ticket Closed — {ticket_label}",
            color=discord.Color.dark_grey(),
            timestamp=datetime.now(_EST_TZ),
        )
        close_embed.add_field(name="📁 Channel", value=f"`{channel.name}`", inline=True)
        close_embed.add_field(name="🔒 Closed By", value=reviewer.mention, inline=True)
        close_embed.add_field(name="👤 Member", value=f"<@{owner_id}> (`{owner_id}`)", inline=True)
        close_embed.set_footer(text="Different Meets • Appeal System")
        try:
            await logs_ch.send(embed=close_embed)
        except Exception:
            pass
        if transcript and guild:
            await _post_transcript_to_channel(
                guild, transcript,
                channel.name, "Appeal Ticket",
            )

    # Inform the ticket channel before deletion
    try:
        await channel.send(
            embed=discord.Embed(
                description=f"✅ This appeal has been resolved. The channel will close in {delay} seconds.",
                color=discord.Color.dark_grey(),
            )
        )
    except Exception:
        pass

    await asyncio.sleep(delay)
    try:
        await channel.delete(reason=f"Appeal resolved by {reviewer}")
    except discord.HTTPException:
        pass


async def _supp_create_ticket_channel(
    interaction: discord.Interaction,
    ticket: "_TicketType",
) -> "discord.TextChannel | None":
    """Create the private ticket channel and return it, or None on failure (already sends error)."""
    guild = interaction.guild
    assert guild and isinstance(interaction.user, discord.Member)

    panel_channel = guild.get_channel(SUPPORT_PANEL_CHANNEL_ID)
    category = guild.get_channel(SUPPORT_TICKET_CATEGORY_ID) if SUPPORT_TICKET_CATEGORY_ID else None
    if not isinstance(category, discord.CategoryChannel) and isinstance(panel_channel, discord.TextChannel):
        category = panel_channel.category
    if not isinstance(category, discord.CategoryChannel):
        await interaction.followup.send(
            "Ticket category is not configured. Please ask staff to fix this.", ephemeral=True
        )
        return None

    staff_role_ids = {LEADER_ROLE_ID, CO_LEADER_ROLE_ID, MANAGER_ROLE_ID, HOST_ROLE_ID, TICKET_SUPPORT_ROLE_ID}
    overwrites: dict = {
        guild.default_role: discord.PermissionOverwrite(view_channel=False),
        interaction.user: discord.PermissionOverwrite(
            view_channel=True, send_messages=True,
            read_message_history=True, attach_files=True, embed_links=True,
        ),
    }
    me = guild.me
    if me:
        overwrites[me] = discord.PermissionOverwrite(
            view_channel=True, send_messages=True,
            read_message_history=True, manage_channels=True, manage_messages=True,
            attach_files=True, embed_links=True,
        )
    for role_id in staff_role_ids:
        role = guild.get_role(role_id)
        if role:
            overwrites[role] = discord.PermissionOverwrite(
                view_channel=True, send_messages=True,
                read_message_history=True, manage_messages=True,
                attach_files=True, embed_links=True,
            )

    channel_name = f"{ticket.channel_prefix}-{_supp_clean_name(interaction.user.name)}"
    topic = f"ticket_owner={interaction.user.id} | ticket_type={ticket.key}"
    channel = await guild.create_text_channel(
        name=channel_name,
        category=category,
        overwrites=overwrites,
        topic=topic,
        reason=f"{ticket.title} opened by {interaction.user} ({interaction.user.id})",
    )
    return channel


# ── Appeal ticket review view (inside appeal ticket channels) ──────────────────

class _AppealDenyModal(discord.ui.Modal, title="Deny Appeal — Provide Reason"):
    reason = discord.ui.TextInput(
        label="Denial Reason",
        style=discord.TextStyle.paragraph,
        placeholder="Explain clearly why this appeal is being denied...",
        min_length=10,
        max_length=800,
    )

    def __init__(self, owner_id: int, appeal_type: str) -> None:
        super().__init__()
        self.owner_id = owner_id
        self.appeal_type = appeal_type

    async def on_submit(self, interaction: discord.Interaction) -> None:
        if not interaction.guild or not isinstance(interaction.channel, discord.TextChannel):
            return await interaction.response.send_message("Channel error.", ephemeral=True)
        from datetime import timezone as _tz
        now = datetime.now(_EST_TZ)
        color = _TICKET_COLORS.get(self.appeal_type, discord.Color.red())
        label = _TICKET_TYPES.get(self.appeal_type, _TICKET_TYPES["warning"]).label

        result_embed = discord.Embed(
            title="❌ Appeal Denied",
            description=(
                f"Your **{label}** has been reviewed and **denied** by {interaction.user.mention}.\n\n"
                f"**Staff Reason:**\n{self.reason.value}\n\n"
                "If you believe this was incorrect, contact a DIFF leader directly."
            ),
            color=color,
            timestamp=now,
        )
        result_embed.set_footer(text="Different Meets • Appeal System")
        await interaction.channel.send(embed=result_embed)

        # DM the ticket owner
        member = interaction.guild.get_member(self.owner_id)
        if member:
            try:
                dm_embed = discord.Embed(
                    title=f"❌ Your {label} Has Been Denied",
                    description=(
                        f"Your appeal was reviewed by DIFF staff and has been **denied**.\n\n"
                        f"**Reason:** {self.reason.value}\n\n"
                        "If you have additional information or believe this is a mistake, "
                        "please contact a DIFF leader directly."
                    ),
                    color=color,
                    timestamp=now,
                )
                dm_embed.set_footer(text="Different Meets • Appeal System")
                await member.send(embed=dm_embed)
            except Exception:
                pass

        # Disable buttons
        try:
            msg = await interaction.channel.fetch_message(interaction.message.id)
            await msg.edit(view=_AppealActionView(disabled=True))
        except Exception:
            pass

        await interaction.response.send_message("Appeal denied and user notified. Ticket will auto-close.", ephemeral=True)

        logs_ch = interaction.guild.get_channel(STAFF_LOGS_CHANNEL_ID)
        if isinstance(logs_ch, discord.TextChannel):
            log_e = discord.Embed(
                title=f"⚖️ Appeal Denied — {label}",
                color=color, timestamp=now,
            )
            log_e.add_field(name="Member", value=f"<@{self.owner_id}> (`{self.owner_id}`)", inline=True)
            log_e.add_field(name="Staff", value=interaction.user.mention, inline=True)
            log_e.add_field(name="Reason", value=self.reason.value, inline=False)
            log_e.set_footer(text="Different Meets • Appeal System")
            try:
                await logs_ch.send(embed=log_e)
            except Exception:
                pass

        # Record 30-day resubmission cooldown for this appeal type
        _appeal_denial_set(self.owner_id, self.appeal_type)

        # Auto-close the ticket channel
        if isinstance(interaction.channel, discord.TextChannel) and isinstance(interaction.user, discord.Member):
            asyncio.create_task(
                _supp_auto_close_ticket(interaction.channel, self.owner_id, label, interaction.user, delay=15)
            )


class _AppealActionView(discord.ui.View):
    def __init__(self, *, disabled: bool = False) -> None:
        super().__init__(timeout=None)
        for child in self.children:
            child.disabled = disabled  # type: ignore[union-attr]

    def _is_staff(self, member: discord.Member) -> bool:
        return any(r.id in _LEADERSHIP_HOST_ROLE_IDS for r in member.roles)

    @discord.ui.button(label="Accept Appeal", emoji="✅", style=discord.ButtonStyle.success, custom_id="diff_appeal_action_accept")
    async def accept(self, interaction: discord.Interaction, button: discord.ui.Button) -> None:
        if not interaction.guild or not isinstance(interaction.user, discord.Member):
            return await interaction.response.send_message("Server only.", ephemeral=True)
        if not self._is_staff(interaction.user):
            return await interaction.response.send_message("Only DIFF staff can accept appeals.", ephemeral=True)
        if not isinstance(interaction.channel, discord.TextChannel):
            return await interaction.response.send_message("Use inside the ticket channel.", ephemeral=True)

        topic = interaction.channel.topic or ""
        owner_id_raw = _supp_parse_topic(topic, "ticket_owner")
        appeal_type = _supp_parse_topic(topic, "ticket_type") or "warning"
        if not owner_id_raw or not owner_id_raw.isdigit():
            return await interaction.response.send_message("Could not detect ticket owner.", ephemeral=True)

        owner_id = int(owner_id_raw)
        member = interaction.guild.get_member(owner_id)
        label = _TICKET_TYPES.get(appeal_type, _TICKET_TYPES["warning"]).label
        color = _TICKET_COLORS.get(appeal_type, discord.Color.green())
        from datetime import timezone as _tz
        now = datetime.now(_EST_TZ)

        # Auto-reversal
        reversal_note = ""
        if member:
            try:
                if appeal_type == "timeout":
                    await member.timeout(None, reason=f"Appeal accepted by {interaction.user}")
                    reversal_note = "\n✅ Timeout cleared automatically."
                elif appeal_type == "ban":
                    await interaction.guild.unban(discord.Object(id=owner_id), reason=f"Appeal accepted by {interaction.user}")
                    reversal_note = "\n✅ Ban lifted automatically."
                elif appeal_type == "warning":
                    cog = interaction.client.cogs.get("DiffWarningSystem") or interaction.client.cogs.get("WarningSystem")
                    if cog and hasattr(cog, "_remove_latest_warning"):
                        await cog._remove_latest_warning(owner_id, interaction.guild.id)
                        reversal_note = "\n✅ Latest warning removed."
                    else:
                        reversal_note = "\n⚠️ Warning removal requires manual action."
                elif appeal_type == "kick":
                    reversal_note = "\n⚠️ Kicks must be manually reversed — please send the member a new invite."
                elif appeal_type in {"build", "exclusion"}:
                    reversal_note = "\n✅ Restriction lifted — please follow up with the member."
            except discord.Forbidden:
                reversal_note = "\n⚠️ Auto-reversal failed — insufficient permissions."
            except Exception:
                reversal_note = "\n⚠️ Auto-reversal could not complete — handle manually."

        result_embed = discord.Embed(
            title="✅ Appeal Accepted",
            description=(
                f"The **{label}** has been reviewed and **accepted** by {interaction.user.mention}.{reversal_note}"
            ),
            color=discord.Color.green(),
            timestamp=now,
        )
        result_embed.set_footer(text="Different Meets • Appeal System")
        await interaction.channel.send(embed=result_embed)

        # DM member
        if member:
            try:
                dm_embed = discord.Embed(
                    title=f"✅ Your {label} Has Been Accepted",
                    description=(
                        f"Great news! Your appeal was reviewed by DIFF staff and has been **accepted**.{reversal_note}\n\n"
                        "Welcome back to DIFF. Please follow all rules and community standards going forward."
                    ),
                    color=discord.Color.green(),
                    timestamp=now,
                )
                dm_embed.set_footer(text="Different Meets • Appeal System")
                await member.send(embed=dm_embed)
            except Exception:
                pass

        # Disable buttons on the review message
        for child in self.children:
            child.disabled = True  # type: ignore[union-attr]
        try:
            await interaction.message.edit(view=self)
        except Exception:
            pass

        await interaction.response.send_message("Appeal accepted and user notified. Ticket will auto-close.", ephemeral=True)

        logs_ch = interaction.guild.get_channel(STAFF_LOGS_CHANNEL_ID)
        if isinstance(logs_ch, discord.TextChannel):
            log_e = discord.Embed(
                title=f"⚖️ Appeal Accepted — {label}",
                color=discord.Color.green(), timestamp=now,
            )
            log_e.add_field(name="Member", value=f"<@{owner_id}> (`{owner_id}`)", inline=True)
            log_e.add_field(name="Staff", value=interaction.user.mention, inline=True)
            log_e.add_field(name="Reversal", value=reversal_note.strip() or "N/A", inline=False)
            log_e.set_footer(text="Different Meets • Appeal System")
            try:
                await logs_ch.send(embed=log_e)
            except Exception:
                pass

        # Alert mod-hub if reversal failed (needs manual attention)
        if "manually" in reversal_note or "failed" in reversal_note or "insufficient" in reversal_note:
            mod_hub = interaction.guild.get_channel(MOD_HUB_CHANNEL_ID)
            if isinstance(mod_hub, discord.TextChannel):
                try:
                    await mod_hub.send(
                        f"⚠️ **Manual Action Required** — {label} accepted for <@{owner_id}> "
                        f"but auto-reversal could not complete.\n"
                        f"**Reason:** {reversal_note.strip()}\n"
                        f"Reviewed by: {interaction.user.mention}"
                    )
                except Exception:
                    pass

        # Auto-close the ticket channel
        if isinstance(interaction.channel, discord.TextChannel):
            asyncio.create_task(
                _supp_auto_close_ticket(interaction.channel, owner_id, label, interaction.user, delay=15)
            )

    @discord.ui.button(label="Deny Appeal", emoji="❌", style=discord.ButtonStyle.danger, custom_id="diff_appeal_action_deny")
    async def deny(self, interaction: discord.Interaction, button: discord.ui.Button) -> None:
        if not interaction.guild or not isinstance(interaction.user, discord.Member):
            return await interaction.response.send_message("Server only.", ephemeral=True)
        if not self._is_staff(interaction.user):
            return await interaction.response.send_message("Only DIFF staff can deny appeals.", ephemeral=True)
        if not isinstance(interaction.channel, discord.TextChannel):
            return await interaction.response.send_message("Use inside the ticket channel.", ephemeral=True)

        topic = interaction.channel.topic or ""
        owner_id_raw = _supp_parse_topic(topic, "ticket_owner")
        appeal_type = _supp_parse_topic(topic, "ticket_type") or "warning"
        if not owner_id_raw or not owner_id_raw.isdigit():
            return await interaction.response.send_message("Could not detect ticket owner.", ephemeral=True)

        await interaction.response.send_modal(
            _AppealDenyModal(owner_id=int(owner_id_raw), appeal_type=appeal_type)
        )

    @discord.ui.button(label="Need More Info", emoji="💬", style=discord.ButtonStyle.secondary, custom_id="diff_appeal_action_info")
    async def need_info(self, interaction: discord.Interaction, button: discord.ui.Button) -> None:
        if not interaction.guild or not isinstance(interaction.user, discord.Member):
            return await interaction.response.send_message("Server only.", ephemeral=True)
        if not self._is_staff(interaction.user):
            return await interaction.response.send_message("Only DIFF staff can request more info.", ephemeral=True)
        if not isinstance(interaction.channel, discord.TextChannel):
            return await interaction.response.send_message("Use inside the ticket channel.", ephemeral=True)

        topic = interaction.channel.topic or ""
        owner_id_raw = _supp_parse_topic(topic, "ticket_owner")
        await interaction.response.send_message(
            f"<@{owner_id_raw}> — staff need more information before they can make a decision. "
            "Please provide additional details, screenshots, or context as requested.",
        )


def _supp_build_appeal_review_embed(ticket: "_TicketType", user: discord.Member) -> discord.Embed:
    from datetime import timezone as _tz
    now = datetime.now(_EST_TZ)
    color = _TICKET_COLORS.get(ticket.key, discord.Color.orange())
    embed = discord.Embed(
        title=f"⚖️ {ticket.title} — Staff Review",
        description=(
            f"**{user.mention}** has submitted a **{ticket.label}**.\n\n"
            "Read through what they've written above, then use the buttons below to make a decision."
        ),
        color=color,
        timestamp=now,
    )
    embed.add_field(name="👤 Member", value=f"{user.mention} (`{user.id}`)", inline=True)
    embed.add_field(name="📋 Appeal Type", value=ticket.label, inline=True)
    embed.add_field(name="⏰ Submitted", value=f"<t:{int(now.timestamp())}:R>", inline=True)
    embed.add_field(
        name="⚠️ Auto-Reversal",
        value=(
            "✅ Warning → removed automatically\n"
            "✅ Timeout → cleared automatically\n"
            "✅ Ban → lifted automatically\n"
            "⚠️ Kick → requires manual reinvite"
        ),
        inline=False,
    )
    embed.set_footer(text="Different Meets • Appeal System")
    if DIFF_LOGO_URL:
        embed.set_thumbnail(url=DIFF_LOGO_URL)
    return embed


# ── Main support dropdown (Report / General Support / Staff Application) ───────

class SupportDropdown(discord.ui.Select):
    _SUPPORT_KEYS = {"report", "support", "apply", "ts_apply", "mod_apply"}

    def __init__(self) -> None:
        options = [
            discord.SelectOption(
                label=t.label,
                value=t.key,
                description=t.description[:100],
                emoji=t.emoji,
            )
            for k, t in _TICKET_TYPES.items()
            if k in self._SUPPORT_KEYS
        ]
        super().__init__(
            placeholder="📋  Support options — select category...",
            min_values=1,
            max_values=1,
            options=options,
            custom_id="diff_support_dropdown_select",
            row=0,
        )

    async def callback(self, interaction: discord.Interaction) -> None:
        if not interaction.guild or not isinstance(interaction.user, discord.Member):
            return await interaction.response.send_message("This can only be used inside the server.", ephemeral=True)

        ticket_key = self.values[0]
        if ticket_key not in self._SUPPORT_KEYS or ticket_key not in _TICKET_TYPES:
            return await interaction.response.send_message("Invalid selection.", ephemeral=True)

        # Modal-based applications — collect answers upfront before creating ticket
        if ticket_key == "ts_apply":
            return await interaction.response.send_modal(_TicketSupportAppModal())
        if ticket_key == "mod_apply":
            return await interaction.response.send_modal(_ModAppModal())

        ticket = _TICKET_TYPES[ticket_key]

        try:
            await interaction.response.defer(ephemeral=True)
        except discord.NotFound:
            return

        existing = await _supp_find_any_open_ticket(interaction.guild, interaction.user, support_only=True)
        if existing:
            ex_type_key = _supp_parse_topic(existing.topic, "ticket_type") or "ticket"
            ex_ticket = _TICKET_TYPES.get(ex_type_key)
            ex_label = ex_ticket.label if ex_ticket else "ticket"
            return await interaction.followup.send(
                f"You already have an open {ex_label}: {existing.mention}\n"
                "Please close it before opening another support ticket.",
                ephemeral=True,
            )

        channel = await _supp_create_ticket_channel(interaction, ticket)
        if not channel:
            return

        ping = " ".join(filter(None, [interaction.user.mention, _supp_role_mention(ticket.ping_role_id)]))
        await channel.send(
            content=ping or None,
            embed=_supp_build_ticket_embed(ticket, interaction.user),
            view=SupportCloseButton(),
        )

        if ticket.key == "apply":
            await channel.send(embed=_supp_build_questions_embed(interaction.user))
            await channel.send(embed=_supp_build_review_embed(interaction.user), view=SupportApplicationReviewView())

        logs_channel = interaction.guild.get_channel(STAFF_LOGS_CHANNEL_ID)
        if isinstance(logs_channel, discord.TextChannel):
            try:
                await logs_channel.send(embed=_supp_build_log_embed("Opened", interaction.user, ticket, channel))
            except discord.HTTPException:
                pass

        await interaction.followup.send(
            f"Your {ticket.label} ticket has been created: {channel.mention}", ephemeral=True
        )

        # DM the user to confirm their ticket was opened
        try:
            open_embed = discord.Embed(
                title="🎫 Ticket Opened",
                description=(
                    f"You have opened a **{ticket.label}** ticket in **{interaction.guild.name}**.\n\n"
                    f"**Channel:** {channel.name}\n"
                    "A staff member will be with you shortly. Please provide as much detail as possible."
                ),
                color=_TICKET_COLORS.get(ticket.key, discord.Color.blurple()),
                timestamp=datetime.now(timezone.utc),
            )
            open_embed.set_footer(text="Different Meets • Support System")
            ticket_url = f"https://discord.com/channels/{interaction.guild.id}/{channel.id}"
            open_view = discord.ui.View()
            open_view.add_item(discord.ui.Button(
                label="Go to Ticket",
                emoji="🎫",
                style=discord.ButtonStyle.link,
                url=ticket_url,
            ))
            await interaction.user.send(embed=open_embed, view=open_view)
        except Exception:
            pass


# ── Appeal dropdown (all 6 types + status check) ──────────────────────────────

class AppealDropdown(discord.ui.Select):
    _APPEAL_KEYS = ("warning", "timeout", "ban", "kick", "build", "exclusion")

    def __init__(self) -> None:
        options = [
            discord.SelectOption(
                label=_TICKET_TYPES[k].label,
                value=k,
                description=_TICKET_TYPES[k].description[:100],
                emoji=_TICKET_TYPES[k].emoji,
            )
            for k in self._APPEAL_KEYS
            if k in _TICKET_TYPES
        ] + [
            discord.SelectOption(
                label="🔍 Check Appeal Status",
                value="status",
                description="See if you have an open appeal ticket.",
                emoji="🔍",
            )
        ]
        super().__init__(
            placeholder="⚖️  Appeal options — select appeal type...",
            min_values=1,
            max_values=1,
            options=options,
            custom_id="diff_appeal_dropdown_v2",
            row=1,
        )

    async def callback(self, interaction: discord.Interaction) -> None:
        if not interaction.guild or not isinstance(interaction.user, discord.Member):
            return await interaction.response.send_message("This can only be used inside the server.", ephemeral=True)

        selected = self.values[0]

        # ── Status check ──────────────────────────────────────────────────────
        if selected == "status":
            try:
                await interaction.response.defer(ephemeral=True)
            except discord.NotFound:
                return
            appeal_ticket = None
            for ch in interaction.guild.text_channels:
                if ch.topic and f"ticket_owner={interaction.user.id}" in ch.topic:
                    t_type = _supp_parse_topic(ch.topic, "ticket_type")
                    if t_type in _APPEAL_TYPE_KEYS:
                        appeal_ticket = ch
                        break

            if appeal_ticket:
                type_key = _supp_parse_topic(appeal_ticket.topic, "ticket_type") or "appeal"
                ticket_obj = _TICKET_TYPES.get(type_key)
                type_label = ticket_obj.label if ticket_obj else "Appeal"
                return await interaction.followup.send(
                    f"**📂 Open Appeal Found**\n"
                    f"You have an open **{type_label}** ticket: {appeal_ticket.mention}\n"
                    "Staff will review and respond there. Please be patient.",
                    ephemeral=True,
                )
            else:
                return await interaction.followup.send(
                    "You don't currently have any open appeal tickets.\n"
                    "Select an appeal type above to submit one.",
                    ephemeral=True,
                )

        # ── Open appeal ticket ────────────────────────────────────────────────
        if selected not in _APPEAL_TYPE_KEYS or selected not in _TICKET_TYPES:
            return await interaction.response.send_message("Invalid selection.", ephemeral=True)

        ticket = _TICKET_TYPES[selected]

        try:
            await interaction.response.defer(ephemeral=True)
        except discord.NotFound:
            return

        # ── Appeal resubmission cooldown check ───────────────────────────────
        _remaining_cd = _appeal_denial_check(interaction.user.id, selected)
        if _remaining_cd is not None:
            _days_left = int(_remaining_cd.total_seconds() // 86400) + 1
            return await interaction.followup.send(
                f"⏳ Your **{ticket.label}** was recently denied.\n"
                f"You may resubmit in **{_days_left} day(s)**.\n"
                "If you believe this is a mistake, contact a DIFF leader directly.",
                ephemeral=True,
            )

        existing = await _supp_find_any_open_ticket(interaction.guild, interaction.user, appeal_only=True)
        if existing:
            ex_type_key = _supp_parse_topic(existing.topic, "ticket_type") or "ticket"
            ex_ticket = _TICKET_TYPES.get(ex_type_key)
            ex_label = ex_ticket.label if ex_ticket else "appeal"
            return await interaction.followup.send(
                f"You already have an open {ex_label}: {existing.mention}\n"
                "Please close it before submitting a new appeal.",
                ephemeral=True,
            )

        channel = await _supp_create_ticket_channel(interaction, ticket)
        if not channel:
            return

        # Post ticket embed + close/claim buttons
        ping = " ".join(filter(None, [interaction.user.mention, _supp_role_mention(ticket.ping_role_id)]))
        await channel.send(
            content=ping or None,
            embed=_supp_build_ticket_embed(ticket, interaction.user),
            view=SupportCloseButton(),
        )

        # Post the staff review panel with Accept/Deny/Need-Info buttons
        await channel.send(
            embed=_supp_build_appeal_review_embed(ticket, interaction.user),
            view=_AppealActionView(),
        )

        logs_channel = interaction.guild.get_channel(STAFF_LOGS_CHANNEL_ID)
        if isinstance(logs_channel, discord.TextChannel):
            try:
                await logs_channel.send(embed=_supp_build_log_embed("Opened", interaction.user, ticket, channel))
            except discord.HTTPException:
                pass

        # ── Ping mod-hub so leaders see new appeals immediately ────────────────
        from datetime import timezone as _tz
        mod_hub = interaction.guild.get_channel(MOD_HUB_CHANNEL_ID)
        if isinstance(mod_hub, discord.TextChannel):
            try:
                leader_mention = f"<@&{LEADER_ROLE_ID}>"
                alert = discord.Embed(
                    title=f"⚖️ New {ticket.label} Submitted",
                    description=(
                        f"{interaction.user.mention} has opened a **{ticket.label}**.\n\n"
                        f"Review it here: {channel.mention}"
                    ),
                    color=_TICKET_COLORS.get(ticket.key, discord.Color.orange()),
                    timestamp=datetime.now(_EST_TZ),
                )
                alert.add_field(name="👤 Member", value=f"{interaction.user.mention} (`{interaction.user.id}`)", inline=True)
                alert.add_field(name="📋 Type", value=ticket.label, inline=True)
                alert.set_footer(text="Different Meets • Appeal System")
                await mod_hub.send(content=leader_mention, embed=alert)
            except Exception:
                pass

        await interaction.followup.send(
            f"Your **{ticket.label}** has been submitted: {channel.mention}\n"
            "DIFF leadership has been notified and will review your case shortly. Please be patient and honest.",
            ephemeral=True,
        )


class SupportDropdownView(discord.ui.View):
    def __init__(self) -> None:
        super().__init__(timeout=None)
        self.add_item(SupportDropdown())
        self.add_item(AppealDropdown())

    async def on_error(self, interaction: discord.Interaction, error: Exception, item: discord.ui.Item) -> None:
        traceback.print_exception(type(error), error, error.__traceback__)
        try:
            if not interaction.response.is_done():
                await interaction.response.send_message("Something went wrong. Please try again.", ephemeral=True)
            else:
                await interaction.followup.send("Something went wrong. Please try again.", ephemeral=True)
        except Exception:
            pass


# ── Ticket inactivity monitor ─────────────────────────────────────────────────

_TICKET_WARN_HOURS  = 48   # warn after this many hours of silence
_TICKET_CLOSE_HOURS = 72   # auto-close after this many hours of silence

async def __ticket_inactivity_monitor_logic():
    guild = bot.get_guild(GUILD_ID)
    if not guild:
        return
    from datetime import timezone as _tz
    now = datetime.now(_EST_TZ)

    for channel in guild.text_channels:
        topic = channel.topic or ""
        if "ticket_owner=" not in topic or "ticket_type=" not in topic:
            continue
        # Skip channels already marked as warned
        ticket_type = _supp_parse_topic(topic, "ticket_type") or ""
        if ticket_type not in _TICKET_TYPES:
            continue

        # Find last message timestamp
        last_msg: discord.Message | None = None
        try:
            async for m in channel.history(limit=1):
                last_msg = m
        except Exception:
            continue

        if not last_msg:
            continue

        age_hours = (now - last_msg.created_at.replace(tzinfo=_tz.utc)).total_seconds() / 3600

        # Already sent a warning? Don't double-warn (check for our warning message)
        if age_hours >= _TICKET_CLOSE_HOURS:
            owner_id_raw = _supp_parse_topic(topic, "ticket_owner")
            owner_id = int(owner_id_raw) if owner_id_raw and owner_id_raw.isdigit() else 0
            ticket_obj = _TICKET_TYPES.get(ticket_type, _TICKET_TYPES["support"])
            reviewer_member = guild.me or guild.get_member(guild.owner_id)
            if reviewer_member:
                try:
                    await channel.send(
                        embed=discord.Embed(
                            description="⏰ This ticket has been inactive for over 72 hours and is being automatically closed.",
                            color=discord.Color.dark_grey(),
                        )
                    )
                    await asyncio.sleep(3)
                    transcript = await _supp_export_transcript(channel)
                    logs_ch = guild.get_channel(STAFF_LOGS_CHANNEL_ID)
                    if isinstance(logs_ch, discord.TextChannel):
                        idle_embed = discord.Embed(
                            title=f"⏰ Ticket Auto-Closed (Inactive) — {ticket_obj.label}",
                            color=discord.Color.dark_grey(),
                            timestamp=now,
                        )
                        idle_embed.add_field(name="📁 Channel", value=f"`{channel.name}`", inline=True)
                        idle_embed.add_field(name="👤 Owner", value=f"<@{owner_id}> (`{owner_id}`)", inline=True)
                        idle_embed.add_field(name="⏰ Inactive For", value=f"{age_hours:.0f}h", inline=True)
                        idle_embed.set_footer(text="Different Meets • Ticket System")
                        try:
                            await logs_ch.send(embed=idle_embed)
                        except Exception:
                            pass
                        if transcript and channel.guild:
                            await _post_transcript_to_channel(
                                channel.guild, transcript,
                                channel.name, "Support Ticket",
                                outcome="Auto-closed (72h inactivity)",
                            )
                    await channel.delete(reason="Ticket auto-closed: 72h inactivity")
                except Exception:
                    pass

        elif age_hours >= _TICKET_WARN_HOURS:
            # Send a single inactivity warning (check if we already sent one)
            warning_sent = False
            try:
                async for m in channel.history(limit=10):
                    if m.author.id == (bot.user.id if bot.user else 0) and m.embeds:
                        if any("inactive" in (e.description or "").lower() for e in m.embeds):
                            warning_sent = True
                            break
            except Exception:
                pass

            if not warning_sent:
                owner_id_raw = _supp_parse_topic(topic, "ticket_owner")
                try:
                    await channel.send(
                        content=f"<@{owner_id_raw}>" if owner_id_raw else None,
                        embed=discord.Embed(
                            title="⏰ Inactivity Warning",
                            description=(
                                "This ticket has been **inactive for 48 hours**.\n\n"
                                "If no response is received within the next **24 hours**, "
                                "this ticket will be automatically closed.\n\n"
                                "Please respond or ask staff to close it if your issue is resolved."
                            ),
                            color=discord.Color.orange(),
                        )
                    )
                except Exception:
                    pass

@tasks.loop(minutes=30)
async def _ticket_inactivity_monitor() -> None:
    _loop_success('_ticket_inactivity_monitor')
    try:
        await run_with_timeout('_ticket_inactivity_monitor', __ticket_inactivity_monitor_logic(), timeout=180)
    except Exception as _lte:
        await _handle_loop_error('_ticket_inactivity_monitor', _lte, _ticket_inactivity_monitor)
@_ticket_inactivity_monitor.error
async def __ticket_inactivity_monitor_on_error(error: Exception) -> None:
    await _handle_loop_error('_ticket_inactivity_monitor', error, _ticket_inactivity_monitor)
@_ticket_inactivity_monitor.before_loop
async def _before_ticket_monitor():
    await bot.wait_until_ready()


# ── Ticket stats command ──────────────────────────────────────────────────────

@bot.command(name="ticketstats")
async def _ticket_stats_cmd(ctx: commands.Context) -> None:
    """Show a count of all currently open tickets by type."""
    if not isinstance(ctx.author, discord.Member):
        return
    is_staff = any(r.id in _LEADERSHIP_HOST_ROLE_IDS for r in ctx.author.roles)
    if not is_staff:
        return
    try:
        await ctx.message.delete()
    except Exception:
        pass

    guild = ctx.guild
    if not guild:
        return

    counts: dict[str, int] = {k: 0 for k in _TICKET_TYPES}
    total = 0
    for channel in guild.text_channels:
        topic = channel.topic or ""
        if "ticket_owner=" not in topic or "ticket_type=" not in topic:
            continue
        for key in _TICKET_TYPES:
            if f"ticket_type={key}" in topic:
                counts[key] += 1
                total += 1
                break

    from datetime import timezone as _tz
    embed = discord.Embed(
        title="📊 DIFF Open Ticket Stats",
        color=discord.Color.blurple(),
        timestamp=datetime.now(_EST_TZ),
    )

    support_lines = []
    appeal_lines = []
    for key, count in counts.items():
        if count == 0:
            continue
        t = _TICKET_TYPES[key]
        line = f"{t.emoji} **{t.label}** — `{count}`"
        if key in _APPEAL_TYPE_KEYS:
            appeal_lines.append(line)
        else:
            support_lines.append(line)

    embed.add_field(
        name="📋 Support Tickets",
        value="\n".join(support_lines) or "*None open*",
        inline=False,
    )
    embed.add_field(
        name="⚖️ Appeal Tickets",
        value="\n".join(appeal_lines) or "*None open*",
        inline=False,
    )
    embed.add_field(name="🔢 Total Open", value=f"`{total}`", inline=True)
    embed.set_footer(text="Different Meets • Support System")
    if DIFF_LOGO_URL:
        embed.set_thumbnail(url=DIFF_LOGO_URL)

    await ctx.send(embed=embed, delete_after=60)


