# ── Welcome DM on member join ─────────────────────────────────────────────────

@bot.event
async def on_member_join(member: discord.Member) -> None:
    if member.bot:
        return

    # ── Anti-raid join-flood detection ────────────────────────────────────────
    import time as _time_mod
    _now_ts = _time_mod.time()
    _raid_join_times.append(_now_ts)
    _raid_join_times[:] = [_t for _t in _raid_join_times if _now_ts - _t < 30]
    if len(_raid_join_times) >= 5:
        _mod_hub_ch = member.guild.get_channel(MOD_HUB_CHANNEL_ID)
        if isinstance(_mod_hub_ch, discord.TextChannel):
            try:
                _raid_e = discord.Embed(
                    title="🚨 Possible Raid Detected",
                    description=(
                        f"**{len(_raid_join_times)} members** joined in the last 30 seconds.\n"
                        "Consider enabling slowmode or raising verification requirements."
                    ),
                    color=discord.Color.red(),
                )
                _raid_e.set_footer(text="DIFF Anti-Raid System")
                await _mod_hub_ch.send(content=f"<@&{LEADER_ROLE_ID}>", embed=_raid_e)
            except Exception:
                pass
        for _ch in member.guild.text_channels:
            try:
                if _ch.permissions_for(member.guild.default_role).read_messages and _ch.slowmode_delay < 30:
                    await _ch.edit(slowmode_delay=30, reason="Anti-raid: join flood detected")
            except Exception:
                pass

    # Record join timestamp for activity tracking
    try:
        _activity_upsert(member.id, join_ts=time.time())
    except Exception:
        pass

    await _send_welcome_dm(member)


@bot.event
async def on_member_remove(member: discord.Member) -> None:
    """Log leave event with reason tags, drop-off stage, and risk colour to staff logs."""
    if member.bot:
        return
    try:
        leave_ts      = time.time()
        row           = _activity_get(member.id)
        join_ts       = row["join_ts"] if row else (
            member.joined_at.timestamp() if member.joined_at else None
        )
        last_msg      = row["last_message"] if row else None
        last_vc_ts    = row["last_vc"]       if row else None
        meet_count    = int(row["meet_attendance_count"] or 0) if row else 0
        days_in       = round((leave_ts - join_ts) / 86400, 1) if join_ts else None

        was_verified  = any(r.id == VERIFIED_ROLE_ID      for r in member.roles)
        had_meet_role = any(r.id == MEET_ATTENDER_ROLE_ID for r in member.roles)
        # Detect if they held any application-related role as proxy for "Applied"
        _app_role_names = {"applied", "applicant", "interviewing", "pending"}
        had_application = any(r.name.lower() in _app_role_names for r in member.roles)

        skip_ids   = {member.guild.default_role.id, UNVERIFIED_ROLE_ID}
        role_names = ", ".join(r.name for r in member.roles if r.id not in skip_ids) or "None"

        # Compute analytics helpers
        reason_tags   = _detect_leave_reasons(was_verified, had_meet_role, last_msg, days_in, leave_ts)
        drop_off      = _detect_drop_off_stage(was_verified, had_meet_role, meet_count, had_application)

        # Persist to DB
        _activity_log_leave(
            user_id=member.id,
            username=str(member),
            join_ts=join_ts,
            leave_ts=leave_ts,
            was_verified=was_verified,
            had_meet_role=had_meet_role,
            role_names=role_names,
            last_message=last_msg,
            last_vc=last_vc_ts,
            reason_tags=", ".join(reason_tags),
            drop_off_stage=drop_off,
        )

        # ── Risk colour ──────────────────────────────────────────────────────
        # Red = high risk (never engaged), Yellow = medium, Green = was active
        if not was_verified or "Likely Ghost Member" in reason_tags:
            embed_colour = discord.Color.from_rgb(200, 30, 30)    # red
            risk_label   = "🔴 High Risk"
        elif not had_meet_role or "Inactive After Joining" in reason_tags:
            embed_colour = discord.Color.from_rgb(210, 150, 0)    # yellow
            risk_label   = "🟡 Needs Follow-up"
        else:
            embed_colour = discord.Color.from_rgb(30, 160, 60)    # green
            risk_label   = "🟢 Was Active"

        # ── Format helpers ───────────────────────────────────────────────────
        if days_in is not None:
            if days_in < 1:
                stay_str = "< 1 day"
            elif days_in < 7:
                stay_str = f"{days_in} days"
            elif days_in < 30:
                stay_str = f"{days_in / 7:.1f} weeks"
            else:
                stay_str = f"{days_in / 30:.1f} months"
        else:
            stay_str = "Unknown"

        def _age_str(ts: float | None) -> str:
            if not ts:
                return "Not tracked"
            age = int(leave_ts - ts)
            if age < 3600:   return f"{age // 60}m ago"
            if age < 86400:  return f"{age // 3600}h ago"
            return f"{age // 86400}d ago"

        # ── Build embed ──────────────────────────────────────────────────────
        embed = discord.Embed(
            title="👋 Member Left",
            color=embed_colour,
            timestamp=datetime.now(timezone.utc),
        )
        embed.set_thumbnail(url=member.display_avatar.url)
        embed.add_field(
            name="User",
            value=f"`{member}` — ID `{member.id}`",
            inline=False,
        )
        embed.add_field(name="Time in Server", value=stay_str,          inline=True)
        embed.add_field(name="Risk Level",     value=risk_label,        inline=True)
        embed.add_field(name="Drop-off Stage", value=f"📍 {drop_off}",  inline=True)
        embed.add_field(
            name="Status",
            value=(
                f"{'✅' if was_verified  else '❌'} Verified\n"
                f"{'✅' if had_meet_role else '❌'} Attended a Meet"
            ),
            inline=True,
        )
        embed.add_field(
            name="Activity",
            value=f"Last msg: {_age_str(last_msg)}\nLast VC: {_age_str(last_vc_ts)}",
            inline=True,
        )
        embed.add_field(name="Roles", value=role_names[:512], inline=False)
        embed.add_field(
            name="🏷️ Leave Reason Tags",
            value=" · ".join(f"`{t}`" for t in reason_tags),
            inline=False,
        )
        if join_ts:
            embed.add_field(name="Joined", value=f"<t:{int(join_ts)}:D>", inline=True)
        embed.set_footer(text="DIFF Leave Analytics  |  !leavedm <user_id> to send survey")

        ch = member.guild.get_channel(STAFF_LOGS_CHANNEL_ID)
        if isinstance(ch, discord.TextChannel):
            await ch.send(embed=embed)
    except Exception as _e:
        _bot_log.error("[LeaveAnalytics] %s: %s", member, _e, exc_info=True)


async def _wipe_old_panels(channel: discord.TextChannel) -> None:
    """
    Delete every bot-posted message in the support panel channel.
    The channel should only ever contain the one unified panel — anything
    the bot posted there (embed or component) is an old or duplicate panel.
    Recent messages (<14 days) use bulk-delete; older ones are deleted one-by-one.
    """
    from datetime import timezone as _tz
    bot_id = bot.user.id if bot.user else 0
    cutoff = datetime.now(_EST_TZ) - timedelta(days=13, hours=23)

    to_delete: list[discord.Message] = []
    try:
        async for msg in channel.history(limit=500, oldest_first=False):
            if msg.author.id == bot_id and (msg.embeds or msg.components):
                to_delete.append(msg)
    except discord.HTTPException:
        pass

    recent = [m for m in to_delete if m.created_at > cutoff]
    aged   = [m for m in to_delete if m.created_at <= cutoff]

    # Bulk-delete recent messages in chunks of 100
    for i in range(0, len(recent), 100):
        chunk = recent[i:i + 100]
        try:
            await channel.delete_messages(chunk, reason="Support panel refresh — removing old panels")
            await asyncio.sleep(0.5)
        except discord.HTTPException:
            for m in chunk:
                try:
                    await m.delete()
                    await asyncio.sleep(0.3)
                except (discord.HTTPException, discord.NotFound):
                    pass

    # Individual delete for older messages
    for m in aged:
        try:
            await m.delete()
            await asyncio.sleep(0.5)
        except (discord.HTTPException, discord.NotFound):
            pass


@bot.tree.command(name="post-support-panel", description="Post the DIFF Support Center dropdown panel (staff only)")
async def post_support_panel(interaction: discord.Interaction) -> None:
    if not interaction.guild:
        return await interaction.response.send_message("Server only.", ephemeral=True)
    if not isinstance(interaction.user, discord.Member) or not is_staff_reviewer(interaction.user):
        return await interaction.response.send_message("Staff only.", ephemeral=True)
    channel = interaction.guild.get_channel(SUPPORT_PANEL_CHANNEL_ID)
    if not isinstance(channel, discord.TextChannel):
        return await interaction.response.send_message("Support panel channel not found.", ephemeral=True)
    try:
        await interaction.response.defer(ephemeral=True)
    except discord.NotFound:
        return
    await _wipe_old_panels(channel)
    await channel.send(embed=_supp_build_panel_embed(), view=SupportDropdownView())
    await interaction.followup.send(f"✅ Support & Appeal panel posted in {channel.mention}.", ephemeral=True)


@bot.command(name="refreshsupportpanel")
async def _refresh_support_panel_cmd(ctx: commands.Context):
    if not any(r.id in _LEADERSHIP_ROLE_IDS for r in ctx.author.roles):
        return
    try:
        await ctx.message.delete()
    except Exception:
        pass
    channel = ctx.guild.get_channel(SUPPORT_PANEL_CHANNEL_ID) if ctx.guild else None
    if not isinstance(channel, discord.TextChannel):
        await ctx.send("Support panel channel not found.", delete_after=8)
        return
    await _wipe_old_panels(channel)
    await channel.send(embed=_supp_build_panel_embed(), view=SupportDropdownView())
    await ctx.send(f"✅ Support & Appeal panel refreshed in {channel.mention}.", delete_after=8)


# =========================
# DIFF STAFF AUTOMATION SYSTEM
# =========================

_STAFF_DATA_FILE = "diff_data/diff_staff_stats.json"
_PROMOTION_LOG_CHANNEL_ID = STAFF_LOGS_CHANNEL_ID

_PROMOTION_FLOW: dict[int, int] = {
    CREW_MEMBER_ROLE_ID: HOST_ROLE_ID,
    HOST_ROLE_ID: MANAGER_ROLE_ID,
    MANAGER_ROLE_ID: CO_LEADER_ROLE_ID,
    CO_LEADER_ROLE_ID: LEADER_ROLE_ID,
}

_PROMOTION_THRESHOLDS = {
    "tickets_handled": 8,
    "applications_reviewed": 4,
    "meets_hosted": 4,
    "score": 18,
}

_STAFF_DM_APPROVED_TITLE = "DIFF Staff Application Update"
_STAFF_DM_DENIED_TITLE = "DIFF Staff Application Decision"
_STAFF_DM_APPROVED_BODY = (
    "You have been approved for the DIFF staff team.\n\n"
    "Congratulations, and thank you for showing interest in helping the crew grow.\n\n"
    "A leadership member reviewed your application and chose to move forward with you. "
    "Please remain active, professional, and consistent as you step into this role.\n\n"
    "Be ready to support the community, assist members, and represent DIFF the right way.\n\n"
    "— Different Meets"
)
_STAFF_DM_DENIED_BODY = (
    "Thank you for applying for the DIFF staff team.\n\n"
    "After review, your application was not approved at this time.\n\n"
    "This does not mean you cannot improve and apply again later. Keep staying active, "
    "show maturity, support the community, and continue building your presence in DIFF.\n\n"
    "We appreciate your interest and effort.\n\n"
    "— Different Meets"
)


class _StatsStore:
    def __init__(self, file_path: str) -> None:
        from pathlib import Path as _Path
        self.path = _Path(file_path)
        self.data = self._load()

    def _default(self) -> dict:
        from datetime import timezone as _tz
        return {"users": {}, "last_reset": datetime.now(_EST_TZ).isoformat()}

    def _load(self) -> dict:
        if not self.path.exists():
            d = self._default()
            self.path.write_text(json.dumps(d, indent=2), encoding="utf-8")
            return d
        try:
            return json.loads(self.path.read_text(encoding="utf-8"))
        except Exception:
            d = self._default()
            self.path.write_text(json.dumps(d, indent=2), encoding="utf-8")
            return d

    def save(self) -> None:
        self.path.write_text(json.dumps(self.data, indent=2), encoding="utf-8")

    def ensure_user(self, user_id: int) -> dict:
        key = str(user_id)
        if key not in self.data["users"]:
            from datetime import timezone as _tz
            self.data["users"][key] = {
                "tickets_handled": 0,
                "applications_reviewed": 0,
                "meets_hosted": 0,
                "reports_resolved": 0,
                "appeals_reviewed": 0,
                "accepted_apps": 0,
                "denied_apps": 0,
                "last_updated": datetime.now(_EST_TZ).isoformat(),
            }
        return self.data["users"][key]

    def add_stat(self, user_id: int, field: str, amount: int = 1) -> dict:
        from datetime import timezone as _tz
        user = self.ensure_user(user_id)
        user[field] = int(user.get(field, 0)) + amount
        user["last_updated"] = datetime.now(_EST_TZ).isoformat()
        self.save()
        return user

    def reset_all(self) -> None:
        self.data = self._default()
        self.save()

    def leaderboard(self) -> list[tuple[int, dict]]:
        rows = [(int(uid), stats) for uid, stats in self.data["users"].items()]
        rows.sort(key=lambda x: _staff_score(x[1]), reverse=True)
        return rows


def _staff_score(stats: dict) -> int:
    return (
        stats.get("tickets_handled", 0) * 2
        + stats.get("applications_reviewed", 0) * 3
        + stats.get("meets_hosted", 0) * 2
        + stats.get("reports_resolved", 0) * 2
        + stats.get("appeals_reviewed", 0) * 2
    )


def _staff_next_promo_role(member: discord.Member) -> int | None:
    current_ids = {r.id for r in member.roles}
    for cur, nxt in _PROMOTION_FLOW.items():
        if cur in current_ids and nxt not in current_ids:
            return nxt
    return None


_staff_store = _StatsStore(_STAFF_DATA_FILE)


async def _staff_send_dm(member: discord.Member, approved: bool) -> None:
    from datetime import timezone as _tz
    try:
        embed = discord.Embed(
            title=_STAFF_DM_APPROVED_TITLE if approved else _STAFF_DM_DENIED_TITLE,
            description=_STAFF_DM_APPROVED_BODY if approved else _STAFF_DM_DENIED_BODY,
            color=discord.Color.green() if approved else discord.Color.red(),
            timestamp=datetime.now(_EST_TZ),
        )
        embed.set_footer(text="Different Meets • Staff System")
        await member.send(embed=embed)
    except discord.HTTPException:
        pass


async def _staff_check_promotion(guild: discord.Guild, member: discord.Member) -> None:
    from datetime import timezone as _tz
    stats = _staff_store.ensure_user(member.id)
    score = _staff_score(stats)
    meets_threshold = (
        stats.get("tickets_handled", 0) >= _PROMOTION_THRESHOLDS["tickets_handled"]
        or stats.get("applications_reviewed", 0) >= _PROMOTION_THRESHOLDS["applications_reviewed"]
        or stats.get("meets_hosted", 0) >= _PROMOTION_THRESHOLDS["meets_hosted"]
        or score >= _PROMOTION_THRESHOLDS["score"]
    )
    if not meets_threshold:
        return
    next_role_id = _staff_next_promo_role(member)
    if not next_role_id:
        return
    next_role = guild.get_role(next_role_id)
    if not next_role:
        return
    log_channel = guild.get_channel(_PROMOTION_LOG_CHANNEL_ID)
    if not isinstance(log_channel, discord.TextChannel):
        return
    now = datetime.now(_EST_TZ)
    embed = discord.Embed(
        title="📈 Promotion Suggestion",
        description=(
            f"User: {member.mention}\n"
            f"Suggested Next Role: {next_role.mention}\n\n"
            "This staff member has reached the DIFF activity threshold for a promotion review."
        ),
        color=discord.Color.green(),
        timestamp=now,
    )
    embed.add_field(name="Tickets Handled", value=str(stats.get("tickets_handled", 0)), inline=True)
    embed.add_field(name="Apps Reviewed", value=str(stats.get("applications_reviewed", 0)), inline=True)
    embed.add_field(name="Meets Hosted", value=str(stats.get("meets_hosted", 0)), inline=True)
    embed.add_field(name="Reports Resolved", value=str(stats.get("reports_resolved", 0)), inline=True)
    embed.add_field(name="Appeals Reviewed", value=str(stats.get("appeals_reviewed", 0)), inline=True)
    embed.add_field(name="Activity Score", value=str(score), inline=True)
    if DIFF_LOGO_URL:
        embed.set_thumbnail(url=DIFF_LOGO_URL)
    if DIFF_BANNER_URL:
        embed.set_image(url=DIFF_BANNER_URL)
    embed.set_footer(text="Different Meets • Staff Automation")
    try:
        await log_channel.send(embed=embed)
    except discord.HTTPException:
        pass


class StaffReviewView(discord.ui.View):
    def __init__(self) -> None:
        super().__init__(timeout=None)

    async def _get_applicant(self, interaction: discord.Interaction) -> discord.Member | None:
        if not interaction.guild or not isinstance(interaction.channel, discord.TextChannel):
            return None
        owner_raw = _supp_parse_topic(interaction.channel.topic, "ticket_owner")
        if not owner_raw or not owner_raw.isdigit():
            return None
        return interaction.guild.get_member(int(owner_raw))

    async def _handle(self, interaction: discord.Interaction, approved: bool) -> None:
        if not interaction.guild or not isinstance(interaction.user, discord.Member):
            return await interaction.response.send_message("Server only.", ephemeral=True)
        if not any(r.id in _LEADERSHIP_ROLE_IDS for r in interaction.user.roles) \
                and not interaction.user.guild_permissions.manage_guild:
            return await interaction.response.send_message("Only DIFF leadership can use this panel.", ephemeral=True)

        applicant = await self._get_applicant(interaction)
        if applicant is None:
            return await interaction.response.send_message("Could not detect the applicant from this ticket.", ephemeral=True)

        await interaction.response.send_message(
            f"Application {'approved' if approved else 'denied'} and logged.", ephemeral=True
        )

        _staff_store.add_stat(interaction.user.id, "applications_reviewed", 1)
        _staff_store.add_stat(interaction.user.id, "accepted_apps" if approved else "denied_apps", 1)

        if approved:
            role = interaction.guild.get_role(_SUPP_APPROVED_STAFF_ROLE_ID)
            if role and role not in applicant.roles:
                try:
                    await applicant.add_roles(role, reason=f"Application approved by {interaction.user}")
                except discord.HTTPException:
                    pass

        from datetime import timezone as _tz
        now = datetime.now(_EST_TZ)
        ch_embed = discord.Embed(
            title="✅ Application Approved" if approved else "❌ Application Denied",
            description=f"Applicant: {applicant.mention}\nReviewed By: {interaction.user.mention}",
            color=discord.Color.green() if approved else discord.Color.red(),
            timestamp=now,
        )
        ch_embed.set_footer(text="Different Meets • Staff System")
        if isinstance(interaction.channel, discord.TextChannel):
            await interaction.channel.send(embed=ch_embed)

        await _staff_send_dm(applicant, approved=approved)

        logs_channel = interaction.guild.get_channel(STAFF_LOGS_CHANNEL_ID)
        if isinstance(logs_channel, discord.TextChannel):
            log_embed = discord.Embed(
                title="🧾 Staff Application Decision",
                description=(
                    f"Applicant: {applicant.mention}\n"
                    f"Reviewed By: {interaction.user.mention}\n"
                    f"Decision: {'Approved' if approved else 'Denied'}\n"
                    f"Time: <t:{int(now.timestamp())}:F>"
                ),
                color=discord.Color.blue(),
                timestamp=now,
            )
            log_embed.set_footer(text="Different Meets • Staff System")
            try:
                await logs_channel.send(embed=log_embed)
            except discord.HTTPException:
                pass

        await _staff_check_promotion(interaction.guild, interaction.user)

        for child in self.children:
            child.disabled = True
        try:
            await interaction.message.edit(view=self)
        except discord.HTTPException:
            pass

    @discord.ui.button(label="Accept", emoji="✅", style=discord.ButtonStyle.success, custom_id="diff_staff_auto_accept")
    async def accept(self, interaction: discord.Interaction, _: discord.ui.Button) -> None:
        await self._handle(interaction, approved=True)

    @discord.ui.button(label="Deny", emoji="❌", style=discord.ButtonStyle.danger, custom_id="diff_staff_auto_deny")
    async def deny(self, interaction: discord.Interaction, _: discord.ui.Button) -> None:
        await self._handle(interaction, approved=False)


