if not TOKEN:
    raise ValueError("TOKEN not found.")

keep_alive()


def _crash_log(reason: str) -> None:
    """Append crash reason to discord.log so it survives the restart."""
    try:
        with open("discord.log", "a", encoding="utf-8") as _f:
            _f.write(f"[CRASH @ {datetime.now(timezone.utc).strftime('%Y-%m-%d %H:%M:%S UTC')}] {reason}\n")
    except Exception:
        pass

async def run_bot():
    try:
        await bot.start(TOKEN, reconnect=True)
    except discord.errors.HTTPException as e:
        msg = f"[Rate limited] Retrying..." if e.status == 429 else f"[HTTP error] {e}"
        print(msg)
        _crash_log(msg)
    except KeyboardInterrupt:
        pass
    except Exception as e:
        msg = f"[Crash] {type(e).__name__}: {e}"
        print(msg)
        _crash_log(msg)
    finally:
        try:
            if not bot.is_closed():
                await bot.close()
        except Exception:
            pass

# ── Pi Health Command ─────────────────────────────────────────────────────────

@bot.tree.command(name="pihealth", description="Check Raspberry Pi hardware status (staff only)", guild=discord.Object(id=GUILD_ID))
async def pihealth(interaction: discord.Interaction):
    if not isinstance(interaction.user, discord.Member) or not is_staff_reviewer(interaction.user):
        await interaction.response.send_message("Staff only.", ephemeral=True)
        return
    await interaction.response.defer(ephemeral=True)
    lines = []
    try:
        with open("/sys/class/thermal/thermal_zone0/temp") as _f:
            temp_c = int(_f.read().strip()) / 1000
            lines.append(f"🌡️ **CPU Temp:** {temp_c:.1f}°C")
    except Exception:
        lines.append("🌡️ **CPU Temp:** unavailable")
    try:
        import subprocess as _sp
        _mem = _sp.check_output(["free", "-m"], text=True).splitlines()
        _parts = _mem[1].split()
        used_mb, total_mb = int(_parts[2]), int(_parts[1])
        pct = used_mb / total_mb * 100
        lines.append(f"💾 **RAM:** {used_mb} MB / {total_mb} MB ({pct:.0f}% used)")
    except Exception:
        lines.append("💾 **RAM:** unavailable")
    try:
        with open("/proc/uptime") as _f:
            secs = float(_f.read().split()[0])
        h, rem = divmod(int(secs), 3600)
        m, s = divmod(rem, 60)
        lines.append(f"⏱️ **Pi Uptime:** {h}h {m}m {s}s")
    except Exception:
        lines.append("⏱️ **Pi Uptime:** unavailable")
    try:
        import subprocess as _sp
        _df = _sp.check_output(["df", "-h", "/"], text=True).splitlines()[1].split()
        lines.append(f"💿 **Disk:** {_df[2]} used / {_df[1]} total ({_df[4]} full)")
    except Exception:
        lines.append("💿 **Disk:** unavailable")
    embed = discord.Embed(
        title="🖥️ Raspberry Pi Status",
        description="\n".join(lines),
        color=discord.Color.blurple(),
        timestamp=datetime.now(_EST_TZ),
    )
    embed.set_footer(text="DIFF Bot • Pi Health Monitor")
    await interaction.followup.send(embed=embed, ephemeral=True)


# ── Roll Call Finalize Reminder ────────────────────────────────────────────────
_rc_reminded: set = set()  # (guild_id, meet_number) pairs already reminded this session

async def __rc_finalize_reminder_loop_logic():
    try:
        guild = bot.get_guild(GUILD_ID)
        if not guild:
            return
        meets = _rc_db.get_meets(GUILD_ID)
        if not meets:
            return
        now_ts = datetime.now(timezone.utc).timestamp()
        ch = guild.get_channel(HOST_RSVP_CHANNEL_ID)
        if not isinstance(ch, discord.TextChannel):
            return
        for meet in meets:
            mn = int(meet["meet_number"])
            key = (GUILD_ID, mn)
            if meet["is_finalized"] or key in _rc_reminded:
                continue
            st = str(meet["start_time"] or "")
            _m = re.search(r"<t:(\d+):", st)
            if not _m:
                continue
            meet_unix = int(_m.group(1))
            if now_ts - meet_unix >= 3600:  # 1+ hour past meet time
                _rc_reminded.add(key)
                host_id = meet["host_id"]
                mention = f"<@{host_id}>" if host_id else f"<@&{HOST_ROLE_ID}>"
                await ch.send(
                    f"⚠️ {mention} — **Meet {mn}** ended over an hour ago but hasn't been finalized. "
                    f"Please open the admin panel and finalize attendance when you're ready!"
                )
    except Exception as _e:
        print(f"[RcReminder] Error: {_e}")

@tasks.loop(minutes=30)
async def _rc_finalize_reminder_loop():
    _loop_success('_rc_finalize_reminder_loop')
    try:
        await run_with_timeout('_rc_finalize_reminder_loop', __rc_finalize_reminder_loop_logic(), timeout=120)
    except Exception as _lte:
        await _handle_loop_error('_rc_finalize_reminder_loop', _lte, _rc_finalize_reminder_loop)
@_rc_finalize_reminder_loop.error
async def __rc_finalize_reminder_loop_on_error(error: Exception) -> None:
    await _handle_loop_error('_rc_finalize_reminder_loop', error, _rc_finalize_reminder_loop)
@_rc_finalize_reminder_loop.before_loop
async def _before_rc_reminder():
    await bot.wait_until_ready()


# =========================
# PSN HOST STATUS BOARD
# =========================

try:
    from psnawp_api import PSNAWP as _PSNAWP
    _PSNAWP_AVAILABLE = True
except ImportError:
    _PSNAWP_AVAILABLE = False

_PSN_MAP_FILE  = os.path.join(DATA_FOLDER, "diff_psn_map.json")
_PSN_NPSSO_KEY = "PSN_NPSSO"


def _psn_map_load() -> dict:
    try:
        with open(_PSN_MAP_FILE, "r") as _f:
            return json.load(_f)
    except Exception:
        return {"map": {}, "board_message_id": None}

def _psn_map_save(_d: dict) -> None:
    try:
        with open(_PSN_MAP_FILE, "w") as _f:
            json.dump(_d, _f, indent=2)
    except Exception:
        pass

def _psn_npsso() -> str:
    return os.environ.get(_PSN_NPSSO_KEY, "").strip()

def _psn_client():
    if not _PSNAWP_AVAILABLE:
        return None
    npsso = _psn_npsso()
    if not npsso:
        return None
    try:
        # psnawp_api 2.x dropped the keyword arg — try positional first
        try:
            return _PSNAWP(npsso)
        except TypeError:
            return _PSNAWP(npsso=npsso)
    except Exception as _e:
        print(f"[PSN] Client init failed: {_e}")
        return None


def _psn_fetch_all_sync(psn_ids: list) -> dict:
    """Sync: fetch PSN presence for a list of PSN IDs. Returns {psn_id: parsed_dict}."""
    client = _psn_client()
    if not client:
        return {}
    results: dict = {}
    for psn_id in psn_ids:
        try:
            user     = client.user(online_id=psn_id)
            raw      = user.get_presence()
            basic    = raw.get("basicPresence", raw)
            avail    = basic.get("availability", "offline")
            ppi      = basic.get("primaryPlatformInfo") or {}
            platform = ppi.get("platform", "")
            online   = ppi.get("onlineStatus", "offline") == "online" or avail == "availableToPlay"
            dnd      = avail == "doNotDisturb"
            games    = basic.get("gameTitleInfoList") or []
            game     = games[0].get("titleName", "") if games else ""
            last_ts  = basic.get("lastAvailableDate", "")
            results[psn_id] = {
                "online":   online,
                "dnd":      dnd,
                "platform": platform,
                "game":     game,
                "last":     last_ts,
                "error":    None,
            }
        except Exception as _e:
            results[psn_id] = {"online": False, "dnd": False, "platform": "", "game": "", "last": "", "error": str(_e)}
    return results


async def _psn_fetch_all(psn_ids: list) -> dict:
    loop = asyncio.get_event_loop()
    return await loop.run_in_executor(None, _psn_fetch_all_sync, psn_ids)


def _psn_platform_emoji(platform: str) -> str:
    p = platform.upper()
    if "PS5" in p:
        return "🎮 PS5"
    if "PS4" in p:
        return "🎮 PS4"
    if p:
        return f"🎮 {platform}"
    return ""


def _psn_build_board_embed(guild: discord.Guild, presence: dict, psn_map: dict) -> discord.Embed:
    """Build the PSN status board embed from fetched presence data."""
    # Invert map: psn_id → [discord_member, ...]
    gta_lines:     list[str] = []
    online_lines:  list[str] = []
    dnd_lines:     list[str] = []
    offline_lines: list[str] = []
    error_count = 0

    for did_str, psn_id in psn_map.items():
        member = guild.get_member(int(did_str))
        name   = member.display_name if member else f"<@{did_str}>"
        p      = presence.get(psn_id, {})

        if p.get("error"):
            error_count += 1
            offline_lines.append(f"⚫ **{name}** (`{psn_id}`) — unavailable")
            continue

        game     = p.get("game", "")
        platform = _psn_platform_emoji(p.get("platform", ""))
        plat_str = f" · {platform}" if platform else ""

        if p.get("online"):
            if "grand theft auto" in game.lower() or "gta" in game.lower():
                gta_lines.append(f"🟢 **{name}** (`{psn_id}`){plat_str} · 🏎️ GTA Online")
            elif game:
                online_lines.append(f"🟡 **{name}** (`{psn_id}`){plat_str} · {game}")
            else:
                online_lines.append(f"🟡 **{name}** (`{psn_id}`){plat_str} · Online")
        elif p.get("dnd"):
            dnd_lines.append(f"🔴 **{name}** (`{psn_id}`) · Do Not Disturb")
        else:
            last = ""
            raw_last = p.get("last", "")
            if raw_last:
                try:
                    ts = int(datetime.fromisoformat(raw_last.replace("Z", "+00:00")).timestamp())
                    last = f" · last seen <t:{ts}:R>"
                except Exception:
                    pass
            offline_lines.append(f"⚫ **{name}** (`{psn_id}`){last}")

    total  = len(gta_lines) + len(online_lines) + len(dnd_lines) + len(offline_lines)
    online = len(gta_lines) + len(online_lines)

    if gta_lines:
        color = 0x43B581
    elif online_lines:
        color = 0xFAA61A
    else:
        color = 0x36393F

    filled = round(online / max(total, 1) * 10)
    bar    = "🟩" * filled + "⬛" * (10 - filled)

    embed = discord.Embed(
        title="🎮 DIFF Host PSN Status",
        description=(
            "Live PlayStation presence for the host team.\n"
            "━━━━━━━━━━━━━━━━━━━━━━\n"
            f"{bar}  **{online}/{total}** online"
        ),
        color=color,
        timestamp=datetime.now(timezone.utc),
    )
    embed.set_thumbnail(url=DIFF_LOGO_URL)

    if gta_lines:
        embed.add_field(name=f"🏎️ In GTA Online  ({len(gta_lines)})", value="\n".join(gta_lines), inline=False)
    if online_lines:
        embed.add_field(name=f"🟡 Online Elsewhere  ({len(online_lines)})", value="\n".join(online_lines), inline=False)
    if dnd_lines:
        embed.add_field(name=f"🔴 Do Not Disturb  ({len(dnd_lines)})", value="\n".join(dnd_lines), inline=False)
    if offline_lines:
        embed.add_field(name=f"⚫ Offline  ({len(offline_lines)})", value="\n".join(offline_lines), inline=False)

    if not psn_map:
        embed.add_field(
            name="No PSN accounts registered",
            value="Hosts can register with `!setpsn YourPSN`",
            inline=False,
        )

    footer = "DIFF Meets • PSN Status Board — updates every 5 min"
    if error_count:
        footer += f" • {error_count} account(s) unreachable"
    embed.set_footer(text=footer)
    return embed


async def _psn_refresh_board(guild: discord.Guild) -> None:
    """Fetch presence and update (or post) the board embed in the host team channel."""
    d = _psn_map_load()
    psn_map: dict = d.get("map", {})

    ch = guild.get_channel(_HOST_TEAM_CHANNEL_ID)
    if not isinstance(ch, discord.TextChannel):
        try:
            ch = await guild.fetch_channel(_HOST_TEAM_CHANNEL_ID)
        except Exception:
            return
    if not isinstance(ch, discord.TextChannel):
        return

    # Fetch presence (runs sync psnawp in thread pool)
    presence = await _psn_fetch_all(list(psn_map.values())) if psn_map and _psn_npsso() else {}
    embed = _psn_build_board_embed(guild, presence, psn_map)

    board_msg_id = d.get("board_message_id")
    if board_msg_id:
        try:
            msg = await ch.fetch_message(int(board_msg_id))
            await msg.edit(embed=embed)
            return
        except discord.NotFound:
            pass
        except Exception as _e:
            print(f"[PSN] Board edit failed: {_e}")
            return

    # Post fresh board
    try:
        msg = await ch.send(embed=embed)
        d["board_message_id"] = msg.id
        _psn_map_save(d)
    except Exception as _e:
        print(f"[PSN] Board post failed: {_e}")


async def __psn_board_refresh_loop_logic():
    guild = next((g for g in bot.guilds if g.id == GUILD_ID), None)
    if guild:
        try:
            await _psn_refresh_board(guild)
        except Exception as _e:
            print(f"[PSN] Loop error: {_e}")

@tasks.loop(minutes=5)
async def _psn_board_refresh_loop():
    _loop_success('_psn_board_refresh_loop')
    try:
        await run_with_timeout('_psn_board_refresh_loop', __psn_board_refresh_loop_logic(), timeout=60)
    except Exception as _lte:
        await _handle_loop_error('_psn_board_refresh_loop', _lte, _psn_board_refresh_loop)
@_psn_board_refresh_loop.error
async def __psn_board_refresh_loop_on_error(error: Exception) -> None:
    await _handle_loop_error('_psn_board_refresh_loop', error, _psn_board_refresh_loop)
@_psn_board_refresh_loop.before_loop
async def _before_psn_board():
    await bot.wait_until_ready()


